window.__QUIZ_SUBJECT__=[{"id": "objective>Computer Studies>2014>1", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The first calculator was built by", "images": [], "options": {"A": "Marie Jacquad", "B": "Balise Pascal", "C": "Charles Babbage", "D": "John Napier"}, "answer": "B", "explanation": "Blaise Pascal  The first calculator or adding machine to be produced in any quantity and actually used was the Pascaline, or Arithmetic Machine, designed and built by the French mathematician-philosopher Blaise Pascal between 1642 and 1644.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>2", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "A similarity between data and information is that both", "images": [], "options": {"A": "can be displayed on the monitor", "B": "are computer inputs", "C": "are processed facts", "D": "are computer results"}, "answer": "A", "explanation": "Both data and information can be displayed on a monitor. Data refers to raw, unprocessed, and unorganized facts or details that alone might not make much sense. Information, on the other hand, is processed data; it is data that has been given a context and is useful to the user.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>3", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The computer hardware can be classified into", "images": [], "options": {"A": "ALU and Control Unit", "B": "System Unit and Peripheral", "C": "Central Processing Unit and Control Unit", "D": "Input and Output Units"}, "answer": "B", "explanation": "The computer hardware is classified into System Unit and Peripheral", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>4", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "The outcome of a processed data in a computer is known as", "images": [], "options": {"A": "raw fact", "B": "information", "C": "database", "D": "computer result"}, "answer": "B", "explanation": "The outcome of a processed data in a computer is known as 'information'. Raw data is processed by a computer and turned into a meaningful output, which is referred to as information. This is the fundamental concept of data processing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>5", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Which of the following devices is not a micro computer?", "images": [], "options": {"A": "Notebook", "B": "Laptop", "C": "EDVAC", "D": "Desktop"}, "answer": "C", "explanation": "EDVAC (Electronic Discrete Variable Automatic Computer) was one of the earliest electronic computers. It is not a micro computer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>6", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Which of the following computing devices did not exist in the pre-computing age to the 19th century?", "images": [], "options": {"A": "Napier's bone", "B": "Abacus", "C": "ENIAC", "D": "Slide Rule"}, "answer": "C", "explanation": "ENIAC (Electronic Numerical Integrator and Computer) is considered to be the first operational digital computer in USA, developed by Army ordinance to compute World War II ballistic firing tables.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>7", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The computing devices invented by Charles Babbage are", "images": [], "options": {"A": "Difference Engine and Abacus", "B": "Analytical Engine and Slide Rule", "C": "Abacus and Slide Rule", "D": "Analytical and Difference Engines"}, "answer": "D", "explanation": "Charles Babbage, an English mechanical engineer and polymath, originated the concept of a digital programmable computer. He invented two computing devices which are known as the Analytical Engine and the Difference Engine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>8", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "In a computer, the sets of instruction that direct it in performing a particular task is called", "images": [], "options": {"A": "information", "B": "program", "C": "data", "D": "file"}, "answer": "B", "explanation": "In a computer, a program is a set of instructions that direct the computer to perform a particular task. These instructions are written in a programming language that the computer can understand and execute.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>9", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The property of a disk that determines the amount of data it may contain is", "images": [], "options": {"A": "size", "B": "volume", "C": "storage capacity", "D": "storage power"}, "answer": "C", "explanation": "The property of a disk that determines the amount of data it may contain is its storage capacity. This is usually measured in bytes and its multiples (KB, MB, GB, TB, etc.). The size and volume of a disk do not necessarily determine its storage capacity, and 'storage power' is not a recognized term in this context.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>10", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following items best describes the term hardcopy?", "images": [], "options": {"A": "Print out", "B": "Written on a hard board", "C": "Information stored on a hard disk", "D": "Amount of data"}, "answer": "A", "explanation": "A hardcopy refers to a printed document or material that is in a physical form. It is a physical version of a digital document. Therefore, the term 'hardcopy' is best described as a 'Print out'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>11", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following is not an output device?", "images": [], "options": {"A": "Plotters", "B": "Speakers", "C": "Projectors", "D": "Webcams"}, "answer": "D", "explanation": "An output device is any piece of computer hardware equipment which converts information into human-readable form. Plotters, Speakers, and Projectors are all output devices as they display or produce output from the computer. However, Webcams are input devices because they capture and send data to the computer, rather than receiving and displaying data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>12", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following signifies the correct association between a hardware component and its function?", "images": [], "options": {"A": "Mouse to input", "B": "Monitor to print", "C": "CPU to storage", "D": "Hard disk to processing"}, "answer": "A", "explanation": "A hardware component's function is defined by what it does in a computer system. A mouse is an input device used to input data into the computer. A monitor is used to display information, but it does not print. The CPU (Central Processing Unit) is the main processing unit of a computer, but it does not store data. The hard disk is used for storage, not for processing. Therefore, the correct association between a hardware component and its function is 'Mouse to input'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>13", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Fig. 1 is a logic gate. Use it to answer this question.      Fig. 1 represents", "images": ["Computer Studies/imgs/2014/img1.png"], "options": {"A": "an AND gate", "B": "an OR gate", "C": "a NOT gae", "D": "a NAND gate"}, "answer": "B", "explanation": "The diagram labeled Fig. 1 illustrates an OR gate, a fundamental logic gate used in digital circuits. An OR gate produces a high output (1) if any of its inputs are high (1). It acts as a logical OR operation, returning true if any of its inputs are true.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>14", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Fig. 1 is a logic gate. Use it to answer this question.    In Fig. 1, X, Y and Z respectively represent", "images": ["Computer Studies/imgs/2014/img1.png"], "options": {"A": "input, output and input signals", "B": "output, output and input signals", "C": "output, input and output signals", "D": "input, input and output signals"}, "answer": "D", "explanation": "In the diagram labeled Fig. 1, X and Y represent the input variables, while Z represents the output variable. This indicates that the OR gate takes X and Y as inputs and produces Z as the output, based on the logical OR operation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>15", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Which of the following software is best suitable for keeping records during national population census?", "images": [], "options": {"A": "Word Processing", "B": "Spreadfast", "C": "Graphic", "D": "Database"}, "answer": "D", "explanation": "Database software is best suitable for keeping records during a national population census. This is because a database is designed to store, retrieve, define, and manage large amounts of data, making it an ideal tool for tasks that involve storing and manipulating large amounts of information, like a national population census.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>16", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "A major function of system software is", "images": [], "options": {"A": "collection of files", "B": "translation of machine language into machine code", "C": "file management", "D": "arrangement of files in ascending order"}, "answer": "C", "explanation": "The three major functions of system software are allocating system resources, monitoring system activities, and disk and file management.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>17", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "An advantage of Graphical User Interface (GUI) over Disk Operating System (DOC) is that it allows the use of", "images": [], "options": {"A": "diskette", "B": "keyboard", "C": "mouse", "D": "monitor"}, "answer": "C", "explanation": "An advantage of Graphical User Interface (GUI) over Disk Operating System (DOS) is that it allows the use of a mouse. GUI is a type of user interface that allows users to interact with electronic devices through graphical icons and visual indicators, as opposed to text-based interfaces, typed command labels or text navigation. One of the main advantages of GUI is the use of a mouse to navigate and interact with the system, which is not typically available in DOS.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>18", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Which of the following methods is not suitable for securing files?", "images": [], "options": {"A": "Use of back up", "B": "Use of antivirus", "C": "Saving documents without a password", "D": "Proper labelling of storage devices"}, "answer": "C", "explanation": "Securing files involves protecting them from unauthorized access, loss, or damage. While using backups, antivirus software, and proper labeling of storage devices can help secure files, saving documents without a password does not provide any security. It allows anyone who can access the storage location to open and potentially modify the document. Therefore, saving documents without a password is not a suitable method for securing files.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>19", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Which of the following programming languages needs no translator for it to run?", "images": [], "options": {"A": "High Level Language", "B": "Low Level Language", "C": "Machine Language", "D": "Assembly Language"}, "answer": "C", "explanation": "Machine language is the only programming language that a computer can understand without a translator. It is written in binary and is directly executed by the computer. High-level languages and assembly languages need to be translated into machine language before they can be run. Therefore, machine language is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>20", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Fig. 2 is a System Development Cycle. Use it to answer this question      The path labeled I is the", "images": ["Computer Studies/imgs/2014/img2.png"], "options": {"A": "system design", "B": "system implementation", "C": "study review", "D": "feasibility study"}, "answer": "D", "explanation": "The path labeled 'I' represents the feasibility study, an essential step in the software development life cycle (SDLC). A feasibility study is a comprehensive analysis that evaluates the practicality and viability of a proposed software project, considering factors such as technical feasibility, economic feasibility, legal feasibility, and operational feasibility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>21", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Fig. 2 is a System Development Cycle. Use it to answer this question    The path labeled II is the", "images": ["Computer Studies/imgs/2014/img2.png"], "options": {"A": "system design", "B": "system implementation", "C": "study review", "D": "feasibility study"}, "answer": "A", "explanation": "The path labeled 'II' represents the system design phase of the software development life cycle (SDLC). System design involves creating a detailed blueprint of the software system, outlining its architecture, components, and interactions. This phase ensures that the software meets the specified requirements and is technically feasible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>22", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Fig. 2 is a System Development Cycle. Use it to answer this question    The path labeled III is the", "images": ["Computer Studies/imgs/2014/img2.png"], "options": {"A": "system design", "B": "study review", "C": "system implementation", "D": "feasibility study"}, "answer": "C", "explanation": "The path labeled 'III' represents the system implementation phase of the software development life cycle (SDLC). System implementation involves translating the system design into a working software product. This phase includes coding, testing, and integrating the various components of the software.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>23", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Fig. 3 is a flowchart. Use it to answer this question.      The part labeled I represents", "images": ["Computer Studies/imgs/2014/img3.png"], "options": {"A": "begin/start symbol", "B": "process/action symbol", "C": "read/write symbol", "D": "stop/end symbol"}, "answer": "C", "explanation": "The symbol labeled 'I' within the flowchart represents a read/write operation, indicating a step where data is either inputted into the system or outputted from the system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>24", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Fig. 3 is a flowchart. Use it to answer this question.    The part labeled II represents", "images": ["Computer Studies/imgs/2014/img3.png"], "options": {"A": "decision symbol", "B": "read/write symbol", "C": "process symbol", "D": "stop/end symbol"}, "answer": "C", "explanation": "The symbol labeled 'II' within the flowchart represents a process step, indicating an action or operation that is performed within the process. This symbol is typically used to represent tasks, activities, or decision points.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>25", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Fig. 3 is a flowchart. Use it to answer this question.    The part labelled III represents", "images": ["Computer Studies/imgs/2014/img3.png"], "options": {"A": "process/action symbol", "B": "decision symbol", "C": "read/write symbol", "D": "stop symbol"}, "answer": "B", "explanation": "The symbol labeled 'III' within the flowchart represents a decision step, indicating a point in the process where a choice or evaluation is made. This symbol is typically used to represent decision points that determine the flow of the process based on specific conditions or criteria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>26", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The acronym HTTP stands for", "images": [], "options": {"A": "Hyper Text Transfer Protocol", "B": "Higher Transfer Text Protocol", "C": "Hard Text Transfer Protocol", "D": "Higher Text Transfer Protocol"}, "answer": "A", "explanation": "HTTP stands for Hyper Text Transfer Protocol. It is the protocol used for transferring hypertext requests and information on the internet. Hypertext is structured text that uses logical links (hyperlinks) between nodes containing text. Therefore, the correct answer is Hyper Text Transfer Protocol.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>27", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "In ring topology, the computer that is allowed to transmit data possesses the", "images": [], "options": {"A": "packet", "B": "data", "C": "access method", "D": "token"}, "answer": "D", "explanation": "In a ring topology, the computer that is allowed to transmit data possesses the 'token'. A token is a special type of frame that is passed around the network from one node to the next. Only the node that holds the token can transmit data. Once the data transmission is complete, the token is released back into the network for other nodes to use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>28", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The most cost effective and secure way of transmitting confidential messages among the employees of an organization is the", "images": [], "options": {"A": "electronic notice boards", "B": "teleconferencing", "C": "e-mail", "D": "social networks"}, "answer": "C", "explanation": "E-mail is the most cost effective and secure way of transmitting confidential messages among the employees of an organisation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>29", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The application software which allows information available on the internet to be obtained is called", "images": [], "options": {"A": "browser", "B": "world wide web", "C": "spreadsheet", "D": "internet protocol"}, "answer": "A", "explanation": "The application software which allows information available on the internet to be obtained is called a 'browser'. A web browser is a software application that people use to access the World Wide Web. It translates the coding language of the web into the text, graphics, and other features that we see.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>30", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "A modem and a telephone connection are provided. Other things needed to be able to connect a computer to the internet are", "images": [], "options": {"A": "ISP account and utility software", "B": "browser and ISP account", "C": "ISP account and network", "D": "browser and printer"}, "answer": "B", "explanation": "To connect a computer to the internet, you need an Internet Service Provider (ISP) account, which provides you with access to the internet, and a browser, which is a software application used to locate, retrieve and display content on the World Wide Web, including Web pages, images, video and other files.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>31", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Which of the following is employed in transfer of data between computers and a network?", "images": [], "options": {"A": "Fiber optic", "B": "Male connector", "C": "Female connector", "D": "USB Port"}, "answer": "A", "explanation": "Fiber optic cables are used in the transfer of data between computers and a network. They transmit information as light, and are capable of transmitting large amounts of data at high speeds over long distances. They are less susceptible to interference and are faster than traditional copper cables.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>32", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "Which of the following software can be used for graphic production", "images": [], "options": {"A": "DOS editor", "B": "PC writer", "C": "Corel draw", "D": "Acrobat reader"}, "answer": "C", "explanation": "Corel Draw is a vector graphics editor developed and marketed by Corel Corporation. It is also the name of the Corel graphics suite, which includes the bitmap-image editor Corel Photo-Paint as well as other graphics-related programs. It is used for graphic production.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>33", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "In word processing, the icon in Fig. 4 is used for", "images": ["Computer Studies/imgs/2014/img4.png"], "options": {"A": "paging", "B": "line spacing", "C": "numbering", "D": "bulleting"}, "answer": "C", "explanation": "The icon depicted in Figure 4 is commonly used in word processing applications to insert numbered lists. This feature allows users to automatically assign sequential numbers to items within a list, enhancing readability and organization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>34", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Which of the following items is not located on the MS Word menu bar?", "images": [], "options": {"A": "Home", "B": "Open", "C": "View", "D": "Mailings"}, "answer": "B", "explanation": "The Open option is not located on the MS Word menu bar. It is typically found in the Quick Access Toolbar or File menu. The Home, View, and Mailings tabs are all located on the menu bar and contain various commands for formatting, viewing, and managing documents.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>35", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Use Table 3 to answer this question.  ABCDE1BOOKSSUPPLIEDTO SENIORHIGHSCHOOLS2MATHSICTENGLISH3SHS I3450450056783SHS II8765658090005SHS III245640094400    In Table 3, the content of cell C5 is", "images": [], "options": {"A": "2456", "B": "4009", "C": "4400", "D": "3450"}, "answer": "B", "explanation": "The question asks for the content of cell C5 in the given table. In spreadsheet terminology, cell references are given as a combination of the column letter and the row number. So, cell C5 refers to the cell in the third column (C) and the fifth row (5). Looking at the table, the content of cell C5 is '4009', which matches option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>36", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Use Table 3 to answer this question.  ABCDE1BOOKSSUPPLIEDTO SENIORHIGHSCHOOLS2MATHSICTENGLISH3SHS I3450450056783SHS II8765658090005SHS III245640094400  The number of cells that contain data in row 1 is", "images": [], "options": {"A": "1", "B": "3", "C": "5", "D": "7"}, "answer": "C", "explanation": "The question asks for the number of cells that contain data in row 1 of the given table. In spreadsheet terminology, a row is a horizontal line, and a cell is a box where a row and column intersect. Looking at the table, row 1 contains the following data: 'BOOKS', 'SUPPLIED', 'TO SENIOR', 'HIGH', 'SCHOOLS'. Therefore, there are 5 cells in row 1 that contain data, which matches option 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>37", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Use Table 3 to answer this question.  ABCDE1BOOKSSUPPLIEDTO SENIORHIGHSCHOOLS2MATHSICTENGLISH3SHS I3450450056783SHS II8765658090005SHS III245640094400  Which of the cells in Table 3 contains numeric data with the least value?", "images": [], "options": {"A": "A5", "B": "B5", "C": "C5", "D": "D5"}, "answer": "B", "explanation": "The provided table shows that cell B5 contains the numeric data with the lowest value. Comparing the numerical values in all the cells, it is clear that 2456 is the smallest among them, indicating that it is the cell with the least value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>38", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "In changing the storage location of a file, the command to use is", "images": [], "options": {"A": "ctrl + S keys", "B": "'save' command", "C": "'save as' command", "D": "Alt + f, then save"}, "answer": "C", "explanation": "'Save as' command is used to change the storage location of a file. This command allows you to specify a new location and name for the file. The 'ctrl + S keys' and 'save' command are used to save changes to the current file in its current location. 'Alt + f, then save' is a keyboard shortcut to save a file, not to change its location.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>39", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following statements is true about registers?", "images": [], "options": {"A": "It is a storage area around CPU", "B": "It is situated beside the CPU", "C": "It is situated beside the memory", "D": "It is a special high speed storage area within the CPU"}, "answer": "D", "explanation": "Registers are a special high-speed storage area within the CPU. They are the smallest and fastest storage area in the computer. The CPU uses registers to store data that is being processed. The other options are incorrect because registers are not situated around or beside the CPU or memory, they are inside the CPU.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>40", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The instruction fetched into the CPU is decoded by the", "images": [], "options": {"A": "primary memory", "B": "program counter", "C": "ALU", "D": "Control Unit"}, "answer": "D", "explanation": "The Control Unit of the CPU is responsible for decoding instructions. It interprets the instructions and initiates the necessary actions to execute them. The primary memory holds the instructions and data, the program counter keeps track of the address of the next instruction to be executed, and the ALU (Arithmetic Logic Unit) performs arithmetic and logical operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>41", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The process of restarting a computer is known as", "images": [], "options": {"A": "cold booting", "B": "warm booting", "C": "resume booting", "D": "restart booting"}, "answer": "B", "explanation": "Warm booting is the process of restarting a computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2014>42", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Evaluate the BASIC statement  LET Z = 4*W2 + 2*y given that W = 5 and Y = 10.", "images": [], "options": {"A": "50", "B": "8", "C": "100", "D": "120"}, "answer": "D", "explanation": "The BASIC statement can be evaluated by substituting the given values of W and Y into the equation. So, Z = 4*5^2 + 2*10 = 4*25 + 20 = 100 + 20 = 120. Therefore, the correct answer is 120.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>43", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Given that 2610 = (X)2, X is", "images": [], "options": {"A": "11011", "B": "11010", "C": "11110", "D": "10111"}, "answer": "B", "explanation": "The decimal number 26 can be converted to binary by dividing by 2 and recording the remainder until the quotient is 0. The binary equivalent of 26 is 11010. Therefore, the correct option is 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>44", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "In hexadecimal number system, B, D, F represent", "images": [], "options": {"A": "11, 12, 13 respectively", "B": "11, 13, 15 respectively", "C": "13, 14, 15 respectively", "D": "14, 16, 17 respectively"}, "answer": "B", "explanation": "A = 10, B = 11, C = 12, D =13, E = 14, F = 15  B, D, F = 11, 13, 15 respectively", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>45", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The conversion of 110012 to base 10 equals", "images": [], "options": {"A": "30", "B": "28", "C": "25", "D": "20"}, "answer": "C", "explanation": "110012 to base 10  14130201  (1 × 24) + (1 × 23) + (0 × 22) + (0 × 21) + (1 × 20)  16 + 8 + 0 + 0 + 1  25", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>46", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "The transaction file can also be described as", "images": [], "options": {"A": "master file", "B": "movement file", "C": "reference file", "D": "historical file"}, "answer": "B", "explanation": "A transaction file is a file that is used to update a master file in a batch processing system. It contains records of transactions that occur, such as sales or purchases. This is why it is also referred to as a movement file, as it records the movement of transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>47", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the following statements is not true about a computer file?", "images": [], "options": {"A": "It is very fast to access any record within a file", "B": "It is created electronically", "C": "Initial setup is expensive", "D": "File creation and access are less laborious"}, "answer": "A", "explanation": "While computer files can be accessed quickly, the speed of access can vary depending on the size of the file and the method of access used. For example, sequential access (where records are accessed one after the other in order) can be slower than direct access (where any record can be accessed directly without having to go through other records).", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>48", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "An advantage of sequential access over serial access is that", "images": [], "options": {"A": "sequential file is slow", "B": "sequential file is detailed", "C": "sequential file does not use key", "D": "individual records can be located more quickly"}, "answer": "D", "explanation": "Sequential access means that records are accessed one after the other in a specific order, usually based on a key field. This can make it quicker to locate individual records compared to serial access, where records are accessed in the order they were entered, without any specific order.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>49", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "The use of electronic systems to send an unsolicited e-mail to someone's address is known as", "images": [], "options": {"A": "hacking", "B": "spamming", "C": "internet fraud", "D": "piracy"}, "answer": "B", "explanation": "Spamming is the practice of sending unwanted, unsolicited digital messages, especially advertising messages to a group of recipients. In this context, the question refers to the act of sending unsolicited emails, which is known as spamming.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2014>50", "subject": "Computer Studies", "year": "2014", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Which of the following ideals is protected by copyright?", "images": [], "options": {"A": "Ideas", "B": "Profit", "C": "Expression of Ideas", "D": "Inexperience"}, "answer": "C", "explanation": "Copyright protects the expression of ideas, not the ideas themselves. This means that if you have a unique way of expressing an idea, that expression is protected by copyright. However, the underlying idea itself is not protected, and others are free to express that same idea in their own unique ways.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>1", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Charles Babbage was the first to", "images": [], "options": {"A": "invent slide rule", "B": "invent analytical engine", "C": "make census machine", "D": "make use of the punched card"}, "answer": "B", "explanation": "Charles Babbage is best known for his proposal of the Analytical Engine, a mechanical general-purpose computer. The Analytical Engine contained an Arithmetic Logic Unit (ALU), basic flow control, punch cards (inspired by the Jacquard Loom), and integrated memory. It is considered the first design for a computer that could be considered a complete machine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>2", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Which of the following devices is not a micro computer?", "images": [], "options": {"A": "Desktop", "B": "EDVAC", "C": "Laptop", "D": "Notebook"}, "answer": "B", "explanation": "EDVAC (Electronic Discrete Variable Automatic Computer) is not a microcomputer. It is an early computer developed in the 1940s and 1950s. Microcomputers are small, relatively inexpensive computers with a microprocessor as its central processing unit (CPU). Examples of microcomputers include personal computers like desktops, laptops, and notebooks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>3", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The main difference between a laptop and a desktop is that, a laptop", "images": [], "options": {"A": "does not have mouse while a desktop has", "B": "uses USB port while desktop uses parallel port", "C": "can be connected to the internet while desktop cannot", "D": "contains high capacity battery that powers for extensive period while desktop does not"}, "answer": "D", "explanation": "The main difference between a laptop and a desktop is that a laptop contains a high capacity battery that powers it for an extensive period while a desktop does not. Both laptops and desktops can use a mouse, have USB and parallel ports, and can be connected to the internet.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>4", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Abacus is used for", "images": [], "options": {"A": "addition", "B": "subtraction", "C": "addition and subtraction", "D": "multiplication and division"}, "answer": "C", "explanation": "The abacus is a simple, manual calculating device that has been used for thousands of years. It can be used for addition and subtraction, as well as more complex calculations like multiplication and division. However, the basic use of an abacus is for addition and subtraction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>5", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The computer hardware is made up of system unit and", "images": [], "options": {"A": "motherboard", "B": "peripheral", "C": "control unit", "D": "central processing unit"}, "answer": "B", "explanation": "The computer hardware is made up of the system unit and peripherals. The system unit includes components like the motherboard, control unit, and central processing unit. However, peripherals refer to external devices like the keyboard, mouse, printer, etc., that are connected to the computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>6", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The computer memory is measured in", "images": [], "options": {"A": "bit", "B": "byte", "C": "hertz", "D": "nibble"}, "answer": "B", "explanation": "Computer memory is measured in bytes. A byte is a unit of digital information that consists of 8 bits. A bit is the most basic unit of information in computing and digital communications. The name is a portmanteau of binary digit. The byte is one of the core data types in computer science.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>7", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "If the output signal of any logic gate is fed into an inverter, the results is", "images": [], "options": {"A": "NOT gate", "B": "NOR gate", "C": "the inverse of the output signal", "D": "the same as the output signal"}, "answer": "C", "explanation": "An inverter in digital logic, also known as a NOT gate, is a logic gate which implements logical negation. If the output signal of any logic gate is fed into an inverter, the result is the inverse of the output signal. This is because an inverter simply flips the input signal. If the input is true (or '1'), the output is false (or '0'), and vice versa.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>8", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The device through which the main components of the computer communicate with each other is called", "images": [], "options": {"A": "keyboard", "B": "memory", "C": "light pen", "D": "system bus"}, "answer": "D", "explanation": "The system bus is the device through which the main components of the computer communicate with each other. It is a subsystem that transfers data between computer components inside a computer or between computers. The other options like keyboard, memory, and light pen are not used for communication between the main components of the computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>9", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The hardware of a computer does not consist of", "images": [], "options": {"A": "casing", "B": "mouse", "C": "peripherals", "D": "windows"}, "answer": "D", "explanation": "Windows is not a hardware component of a computer. It is an operating system, which is a type of software. The casing, mouse, and peripherals are all hardware components of a computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>10", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Output devices in a computer are those devices that send", "images": [], "options": {"A": "results to the memory of the computer", "B": "processed data and instructions into the computer", "C": "in data and instructions into the computer", "D": "data and instructions into the memory of the computer"}, "answer": "A", "explanation": "Output devices in a computer are those devices that send results to the memory of the computer. They take information that the computer has processed and present it in a form that humans can understand. The other options are incorrect as they describe the functions of input devices and memory, not output devices.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>11", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following is not a mobile input device", "images": [], "options": {"A": "Joystick", "B": "Light pen", "C": "Mouse", "D": "Scanner"}, "answer": "D", "explanation": "A scanner is not a mobile input device. A mobile input device is a device that is portable and can be used to input data into a computer or other computational device. A scanner is typically a stationary device that is used to convert hard-copy information into a digital format.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>12", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Figure 1 is a logic gate. Use it to answer this question.      Figure 1 represents", "images": ["Computer Studies/imgs/2015/img1.png"], "options": {"A": "a NOT gate", "B": "a NAND gate", "C": "an AND gate", "D": "an OR gate"}, "answer": "C", "explanation": "Figure 1 illustrates an AND gate, a fundamental logic gate used in digital circuits. An AND gate produces a high output (1) only when all of its inputs are high (1). It acts as a logical AND operation, returning true only if all its inputs are true.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>13", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure 1 is a logic gate. Use it to answer this question.    X, Y and Z respectively, represents", "images": ["Computer Studies/imgs/2015/img1.png"], "options": {"A": "input, output and input signals", "B": "output, output and input signals", "C": "output, input and output signals", "D": "input, input and output signals"}, "answer": "D", "explanation": "X and Y are input devices while Z is an output device.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>14", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure 1 is a logic gate. Use it to answer this question.    When signals X = 0 and Y = 1, signal Z is", "images": ["Computer Studies/imgs/2015/img1.png"], "options": {"A": "0. 1.", "B": "0", "C": "1", "D": "0+1"}, "answer": "B", "explanation": "The output signal Z is 0. This is because, according to the behavior of the logic gate, the output is determined by the inputs, and for an AND gate, Z = X * Y. Since 1 * 0 = 0, the resulting output is Z = 0.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>15", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The memory unit of the computer belongs to the", "images": [], "options": {"A": "control unit", "B": "input device", "C": "output device", "D": "system unit"}, "answer": "D", "explanation": "The memory unit of the computer belongs to the system unit. The system unit, also known as the system chassis, is a box-like case housing the electronic components of a computer. These components include the central processing unit (CPU), memory, and other parts essential to the computer's operation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>16", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Which of the following is not a function of an operating system?", "images": [], "options": {"A": "Analysis of the computer components", "B": "Ensuring the proper functioning of hardware", "C": "Maintenance of directories in external storage", "D": "Opening and closing files"}, "answer": "A", "explanation": "Analysis of the computer components is not a function of an operating system. An operating system (OS) is system software that manages computer hardware, software resources, and provides various services for computer programs. The OS does not analyze computer components; instead, it manages and coordinates the use of hardware among the different application programs for various users.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>17", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "An example of a specific purpose application package is the", "images": [], "options": {"A": "payroll program", "B": "database program", "C": "spreadsheet program", "D": "word processing program"}, "answer": "A", "explanation": "A specific purpose application package is a software that is designed to carry out a specific task. A payroll program is an example of this as it is designed specifically to manage and process payroll.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>18", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The operating system, translators and utility programs are examples of", "images": [], "options": {"A": "application software", "B": "customized software", "C": "network software", "D": "system software"}, "answer": "D", "explanation": "System software is a type of computer program that is designed to run a computer's hardware and application programs. The operating system, translators and utility programs are all examples of system software.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>19", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The first stage in program development is problem", "images": [], "options": {"A": "analysis", "B": "definition", "C": "solving", "D": "testing"}, "answer": "B", "explanation": "The first stage in program development is problem definition. This is where the problem is identified and defined. It is the stage where the developer determines what the program is supposed to do.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>20", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A pictorial representation of program flow is referred to as", "images": [], "options": {"A": "algorithm", "B": "flow chart", "C": "process mapping", "D": "pseudo code"}, "answer": "B", "explanation": "A flow chart is a type of diagram that represents an algorithm, workflow or process, showing the steps as boxes of various kinds, and their order by connecting them with arrows. This diagrammatic representation illustrates a solution model to a given problem. Flowcharts are used in analyzing, designing, documenting or managing a process or program in various fields.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>21", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "An example of a programming language that uses mnemonic codes is", "images": [], "options": {"A": "Assembly program", "B": "BASIC program", "C": "COBOL program", "D": "FORTRAN program"}, "answer": "A", "explanation": "Assembly language is a low-level programming language for a computer, or other programmable device, in which there is a very strong correspondence between the language and the architecture's machine code instructions. Each assembly language is specific to a particular computer architecture. In contrast, most high-level programming languages are generally portable across multiple architectures but require interpreting or compiling. Assembly language may also be called symbolic machine code.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>22", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "The use of satellite to transmit signal information to the earth is enabled with the use of", "images": [], "options": {"A": "GSM", "B": "GPS", "C": "POS", "D": "WAN"}, "answer": "B", "explanation": "GPS (Global Positioning System) is a satellite-based radionavigation system owned by the United States government and operated by the United States Space Force. It is one of the global navigation satellite systems (GNSS) that provides geolocation and time information to a GPS receiver anywhere on or near the Earth where there is an unobstructed line of sight to four or more GPS satellites.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>23", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The line segment that describes the contents of the message when sending an e-mail is", "images": [], "options": {"A": "Cc", "B": "Contents", "C": "Subject", "D": "To"}, "answer": "C", "explanation": "The 'Subject' line in an email is used to describe the contents of the message. It gives the recipient an idea of what the email is about before they open it. 'Cc' is used to send the email to additional recipients, 'To' is used to specify the main recipient, and 'Contents' is not a standard part of an email.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>24", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Which of the following networks covers the widest range?", "images": [], "options": {"A": "LAN", "B": "MAN", "C": "PAN", "D": "WAN"}, "answer": "D", "explanation": "A Wide Area Network (WAN) covers the widest range among the options. It is a network that covers a large geographic area such as a city, country, or spans even intercontinental distances, using a communications channel that combines many types of media such as telephone lines, cables, and air waves. A LAN (Local Area Network) covers a small area like a home, office, or group of buildings, while a MAN (Metropolitan Area Network) covers a larger area than a LAN within a city or town and a PAN (Personal Area Network) covers a very small area, typically a person's workspace.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>25", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The keyboard command used to copy text in MS'-word document is", "images": [], "options": {"A": "Shift + C", "B": "Ctrl + N", "C": "Ctrl + C", "D": "Ctrl + Alt + C"}, "answer": "C", "explanation": "The keyboard command used to copy text in MS Word document is 'Ctrl + C'. 'Ctrl + N' is used to create a new document, 'Shift + C' and 'Ctrl + Alt + C' are not standard shortcuts in MS Word.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>26", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "The colour palette in Corel Draw allows the user to", "images": [], "options": {"A": "arrange colour", "B": "draw in colour", "C": "pick colour tool", "D": "choose different pre-set colour palettes"}, "answer": "D", "explanation": "The colour palette in Corel Draw allows the user to choose different pre-set colour palettes. This feature provides a range of pre-set colours that users can select and apply to their designs. It does not arrange colour, draw in colour or pick colour tool.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>27", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "In order to get to the symbol dialog box in MS-Word, click on the", "images": [], "options": {"A": "Home tab", "B": "Insert tab", "C": "Page Layout tab", "D": "View tab"}, "answer": "B", "explanation": "In order to get to the symbol dialog box in MS-Word, you need to click on the 'Insert' tab. The 'Insert' tab contains various tools for inserting different elements into your document, including symbols. The other tabs (Home, Page Layout, View) do not provide access to the symbol dialog box.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>28", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "In a network, the workstation is usually connected to the", "images": [], "options": {"A": "Hub", "B": "Modem", "C": "Router", "D": "Switch"}, "answer": "A", "explanation": "In a network, the workstation is usually connected to the hub. A hub is a common connection point for devices in a network. Hubs are devices that are used to connect multiple devices on a network. They are typically used in local area networks (LAN). A router, on the other hand, is used to connect multiple networks together. A switch is a device in a network that channels incoming data from any of multiple input ports to the specific output port that will take the data toward its intended destination.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>29", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "When browsing on the Internet, a possible reason for the message \"page not found\" is that", "images": [], "options": {"A": "the weather is hot.", "B": "the web browser is fast.", "C": "multiple web pages are loading at the same time.", "D": "a connection between the client and server has been lost."}, "answer": "D", "explanation": "The message 'page not found' usually appears when the server hosting the webpage cannot be found. This could be due to the server being down, the webpage being moved or deleted, or a connection issue between the client (your computer) and the server. The weather or speed of the web browser has no effect on this, and multiple web pages loading at the same time would slow down the loading process, but not cause a 'page not found' error.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>30", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Which of the following is not a network device?", "images": [], "options": {"A": "Hub", "B": "Modem", "C": "Port", "D": "Router"}, "answer": "C", "explanation": "A port is not a network device. A port is a virtual data connection that can be used by programs to exchange data directly, instead of going through a file or some other temporary storage location. On the other hand, a hub, modem, and router are all network devices. A hub is a common connection point for devices in a network, a modem is a device that modulates an analog carrier signal to encode digital information, and also demodulates such a carrier signal to decode the transmitted information, and a router is a device that forwards data packets along networks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>31", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "Which of the following is a valid e-mail address?", "images": [], "options": {"A": "www.itbeginswithu.org", "B": "waeconlinee@yahoo.co.uk", "C": "www.waeconline.org", "D": "www.fine.gov.ng"}, "answer": "B", "explanation": "A valid email address has a specific format that includes a local part, the @ symbol, and the domain part. The local part may be up to 64 characters long and the domain may have a maximum of 253 characters — but the maximum of 256 characters length of a forward or reverse path restricts the entire email address to be no more than that. The only option that follows this format is 'waeconlinee@yahoo.co.uk'. The other options are web addresses, not email addresses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>32", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "In word processing, an efficient way to move the second paragraph and place it after the fourth paragraph is", "images": [], "options": {"A": "copy and paste", "B": "copy, cut and paste", "C": "cut and paste", "D": "cut, copy and paste"}, "answer": "C", "explanation": "In word processing, to move a paragraph or any text, the 'cut and paste' function is used. 'Cut' removes the text from its current location and 'paste' places it in the new location. The 'copy' function is not needed in this case as we are not creating a duplicate of the text.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>33", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "In order to locate a particular word in a document, an easy way to do this is to use the", "images": [], "options": {"A": "Find command", "B": "Go To command", "C": "Replace command", "D": "Search command"}, "answer": "A", "explanation": "The 'Find command' is used to locate a particular word in a document. It searches the document for the specific word or phrase you have entered. The 'Go To command' is used to navigate to a specific page or section in the document, the 'Replace command' is used to find and replace specific words or phrases, and the 'Search command' is not a specific command in word processing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>34", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following items changes shape depending on the task being performed?", "images": [], "options": {"A": "Ribbon", "B": "Active tab", "C": "Insertion point", "D": "Mouse pointer"}, "answer": "D", "explanation": "The 'Mouse pointer' changes shape depending on the task being performed. For example, it may appear as an I-beam when over text (indicating you can select or insert text), an arrow when over general areas, a hand over links, etc. The 'Ribbon', 'Active tab', and 'Insertion point' do not change shape based on the task.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>35", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The computer keyboard key(s) that a user presses to move to the beginning of a current line of text is/are the", "images": [], "options": {"A": "Enter key", "B": "Home key", "C": "Ctrl + B keys", "D": "Ctrl + Home Keys"}, "answer": "B", "explanation": "Home key is primarily used to return the typing cursor to the beginning of the line on which you are currently typing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>36", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Data loss in a computer cannot be prevented by the use of", "images": [], "options": {"A": "antivirus", "B": "backup", "C": "flash drive", "D": "password"}, "answer": "C", "explanation": "A flash drive is a storage device, it does not prevent data loss. Antivirus software can prevent data loss by protecting against malware, backups can prevent data loss by creating copies of data, and passwords can prevent unauthorized access to data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>37", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The shortcut command used in restarting a computer is", "images": [], "options": {"A": "Ctrl + S", "B": "Ctrl + O", "C": "Del + Alt + S", "D": "Alt + Ctrl + Del"}, "answer": "D", "explanation": "To restart a computer, the short command is press and hold \"ctrl\" and \"alt\" keys in the keyboard and then press the \"del\" key.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>38", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The term bus width in data transfer refers to the", "images": [], "options": {"A": "number of wires in the bus", "B": "size of the data movement", "C": "number of bits of information the RAM can send to the CPU at the same time", "D": "number of wires in the bus that carry information to the processor at a time"}, "answer": "C", "explanation": "The term 'bus width' in data transfer refers to the number of bits of information that can be sent to the CPU from the RAM at the same time. This is because the bus is the main communication system that transfers data between different components of a computer, such as the CPU and the RAM. The width of the bus determines how much data can be transferred at a time. The wider the bus, the more bits can be transferred simultaneously.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>39", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The part of the computer that holds the data and programs for CPU processing is the", "images": [], "options": {"A": "Address", "B": "Register", "C": "Random Access Memory", "D": "Read Only Memory"}, "answer": "C", "explanation": "Random Access Memory (RAM) is the part of a computer system that holds that data and programs for CPU processing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>40", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A high level language can be converted to a machine language using", "images": [], "options": {"A": "a compiler", "B": "an editor", "C": "a utility program", "D": "an operating system"}, "answer": "A", "explanation": "A high-level language can be converted to a machine language using a compiler. A compiler is a special program that processes statements written in a particular programming language and turns them into machine language or 'code' that a computer's processor uses. This process is necessary because computers only understand machine language, while humans prefer to write in high-level languages, which are easier to understand and use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>41", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following statements is true of encryption? It", "images": [], "options": {"A": "provides complete privacy", "B": "provides security of varying reliability", "C": "makes message unreadable by the recipient", "D": "permits an individual to have access to another person's message"}, "answer": "B", "explanation": "Encryption is a method of converting an original message into a form that is unreadable to unauthorized individuals. It provides security of varying reliability depending on the encryption algorithm used. It does not provide complete privacy as the encrypted message can still be intercepted, it just can't be understood without the decryption key. It does not make the message unreadable by the recipient, as the recipient should have the decryption key to convert the message back to its original form. It does not permit an individual to have access to another person's message, it actually prevents unauthorized access.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>42", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Computer ethics are important because they", "images": [], "options": {"A": "ensure identity theft", "B": "regulate the privacy of messages only", "C": "address piracy and comportment issues", "D": "prevent copyright infringement on discretional basis"}, "answer": "C", "explanation": "Computer ethics are important because they address issues such as piracy and comportment issues. They guide how individuals should behave when using computers and the internet. They do not ensure identity theft, in fact, they discourage such actions. They do not regulate the privacy of messages only, they cover a wide range of issues including privacy, accuracy, property, and accessibility. They do not prevent copyright infringement on a discretional basis, they aim to prevent copyright infringement in all cases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>43", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Which of the following is the main advantage of intellectual property right?", "images": [], "options": {"A": "Discouragement of sharing", "B": "Discovery of brilliant persons", "C": "Encouragement of innovations", "D": "Maximization of profit"}, "answer": "C", "explanation": "The main advantage of intellectual property rights is the encouragement of innovations. Intellectual property rights protect the interests of creators by giving them property rights over their creations. This encourages more people to innovate as they know their creations will be protected. It does not discourage sharing, in fact, it can encourage sharing as creators know their rights will be protected. It does not aim to discover brilliant persons, although it can indirectly lead to this. It does not aim to maximize profit, although it can indirectly lead to this as well.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>44", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Which of the following statements is true of free software? It", "images": [], "options": {"A": "can be borrowed freely", "B": "is a low cost software", "C": "is a free unlicensed software", "D": "is a licensed software with permission to copy freely"}, "answer": "D", "explanation": "Free software refers to software that respects users' freedom and community. It is a licensed software that users are free to run, copy, distribute, study, change and improve. Therefore, the statement 'it is a licensed software with permission to copy freely' is correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>45", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "In hexadecimal number system, B, D and F represent which of the following decimal numbers?", "images": [], "options": {"A": "11, 13 and 15 respectively.", "B": "12, 14 and 15 respectively.", "C": "13, 14 and 15 respectively.", "D": "14, 16 and 17 respectively."}, "answer": "A", "explanation": "In hexadecimal number system, the decimal equivalents of B, D and F are 11, 13 and 15 respectively. Hexadecimal is a base-16 number system that uses sixteen distinct symbols, typically the symbols 0–9 to represent values zero to nine, and A, B, C, D, E, F (or alternatively a–f) to represent values ten to fifteen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>46", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The conversion of 110012 to base ten equals", "images": [], "options": {"A": "20", "B": "25", "C": "28", "D": "30"}, "answer": "B", "explanation": "14130201102  (1 × 24) + (1 × 23) + (0 × 22) + (0 × 21) + (1 × 20)  16 + 8 + 0 + 0 + 1  2510", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2015>47", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "910 is equivalent to X8, where X is", "images": [], "options": {"A": "7", "B": "10", "C": "11", "D": "12"}, "answer": "C", "explanation": "898  1 R 1 ↑  0 R 1 ↑  11  Therefore, X = 11", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>48", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Use the MS-Excel table below to answer this question  ABCD1BOOKSUPPLIEDTO SENIORHIGH SCHOOLS2.FORMMATHSICTENGLISH LANGUAGE3SHS I2456658056784SHS II3450400944005SHS III876545009000    The content of cell D3 is", "images": [], "options": {"A": "3450", "B": "4400", "C": "4500", "D": "5678"}, "answer": "D", "explanation": "Based on the data presented in the table, the value contained within cell D3 is 5678. This indicates that the specific location identified as D3 holds the numerical value of 5678.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>49", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Use the MS-Excel table below to answer this question  ABCD1BOOKSUPPLIEDTO SENIORHIGH SCHOOLS2.FORMMATHSICTENGLISH LANGUAGE3SHS I2456658056784SHS II3450400944005SHS III876545009000  The number of cells that contain data in row is", "images": [], "options": {"A": "1", "B": "3", "C": "4", "D": "5"}, "answer": "C", "explanation": "The number of cells that contain data in row is A B C D which is 4.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2015>50", "subject": "Computer Studies", "year": "2015", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Use the MS-Excel table below to answer this question  ABCD1BOOKSUPPLIEDTO SENIORHIGH SCHOOLS2.FORMMATHSICTENGLISH LANGUAGE3SHS I2456658056784SHS II3450400944005SHS III876545009000  The number of cells that contains numeric data in the table are", "images": [], "options": {"A": "4", "B": "8", "C": "9", "D": "12"}, "answer": "C", "explanation": "Cells that contain numerical data are B3, B4, B5 : C3, C4, C5 and D3, D4, D5 making a total of 9.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>1", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The first calculating device is the", "images": [], "options": {"A": "Abacus", "B": "Census machine", "C": "Difference engine", "D": "Napier bones"}, "answer": "A", "explanation": "The first calculating device is the Abacus. The Abacus is an ancient tool used for arithmetic calculations. It was invented in ancient times and is still used in some parts of the world today. The other options, such as the Census machine, Difference engine, and Napier bones, were developed much later.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>2", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following represents features of a computer?  I. It is constructed from electronics components   II. It has self regeneration capability  III. It has facility for storage of data and programs  IV. It has provision for input and output data", "images": [], "options": {"A": "I, II and III only", "B": "I, II and IV only", "C": "I, III and IV only", "D": "II, III and IV only"}, "answer": "C", "explanation": "Computer is constructed from electronics component, it has facility for storage of data and programs and it has provision for input and output data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>3", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Arrange in a hierarchical order by date, the following inventions: I slide rule; II pascaline; III analytical engine; IV difference engine", "images": [], "options": {"A": "I, II, IV and III", "B": "III, IV, I and II", "C": "III, IV, II and I", "D": "I, II, III and IV"}, "answer": "A", "explanation": "Slide rule, pascaline, difference engine and analytical engine.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2016>4", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following is true about raw data?", "images": [], "options": {"A": "It is well categorized", "B": "It exists in oral form only", "C": "It exists in written form only", "D": "It cannot be relied on to make decision"}, "answer": "D", "explanation": "Raw data refers to unprocessed or unorganized data that hasn't undergone any analysis or transformation. It is often messy and lacks context. Therefore, it cannot be relied upon to make informed decisions without further processing, analysis, and interpretation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>5", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Which of the following was used by Joseph Marie Jacquad in inventing the Loom?", "images": [], "options": {"A": "punched card", "B": "smart card", "C": "smart chip", "D": "sound card"}, "answer": "A", "explanation": "Joseph Marie Jacquard used punched cards in inventing the Jacquard Loom. The punched card was used to control the weaving of patterns in the fabric, making it an early example of a programmable machine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>6", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Which generation of computers used vacuum tubes in their circuitry?", "images": [], "options": {"A": "first generation", "B": "second generation", "C": "third generation", "D": "fourth generation"}, "answer": "A", "explanation": "The first generation of computers used vacuum tubes in their circuitry. Vacuum tubes were used as the basic components for memory and circuitry for CPU. These computers were very large in size and had a lot of heat dissipation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>7", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : HISTORY OF COMPUTERS", "question": "The full meaning of the acronym ENIAC is", "images": [], "options": {"A": "Electronic Numerical Integrator and Calculator", "B": "Electronic Numerical Integrator and Computer", "C": "Electronic Numeric Integration Automatic Calculator", "D": "Electronic Numeric Integrated Automatic Calculator"}, "answer": "B", "explanation": "The full meaning of the acronym ENIAC is Electronic Numerical Integrator and Computer", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>8", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The primary memory of the computer can be divided into", "images": [], "options": {"A": "register and random access memory", "B": "mass storage and read only memory", "C": "volatile memory and auxilliary memory", "D": "random access memory and read only memory"}, "answer": "D", "explanation": "The primary memory of the computer can be divided into Random Access Memory (RAM) and Read Only Memory (ROM). RAM is a type of computer memory that can be read from and written to in any order. This is where the computer stores data that it is actively using. ROM is a type of non-volatile memory used in computers and other electronic devices. Data stored in ROM cannot be electronically modified after the manufacture of the memory device.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>9", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A common communication pathway shared by hardware components in the computer is called", "images": [], "options": {"A": "bus", "B": "channel", "C": "firmware", "D": "register"}, "answer": "A", "explanation": "A bus is a communication system that transfers data between components inside a computer, or between computers. This expression covers all related hardware components (wire, optical fiber, etc.) and software, including communication protocols.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>10", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following can be described as the brain of the computer hardware?", "images": [], "options": {"A": "BIOS", "B": "microprocessor", "C": "RAM chip", "D": "system clock"}, "answer": "B", "explanation": "The microprocessor is often referred to as the 'brain' of a computer because it controls the operations of the computer. It processes the instructions, performs calculations and manages data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>11", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following is not a computer output device?", "images": [], "options": {"A": "disk", "B": "plotter", "C": "printer", "D": "speaker"}, "answer": "A", "explanation": "A disk is not an output device. It is a storage device. Output devices are hardware components that convey information to the user or another device. Examples include monitors, printers, speakers, and plotters.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>12", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The computer process that electronically prepares a disk to store data is called", "images": [], "options": {"A": "coupling", "B": "initialization", "C": "decoding", "D": "standardization"}, "answer": "B", "explanation": "The process of electronically preparing a disk to store data is called initialization. This process involves setting up the file system on the disk so that it can be used to store and retrieve data. Coupling is a process of connecting two things together, decoding is the process of converting encoded data back into its original form, and standardization is the process of making something conform to a standard. None of these terms accurately describe the process of preparing a disk to store data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>13", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Data to be processed by the microprocessor is temporarily stored in the", "images": [], "options": {"A": "auxiliary storage", "B": "backing storage", "C": "main storage", "D": "random access memory"}, "answer": "D", "explanation": "Data to be processed by the microprocessor is temporarily stored in the Random Access Memory (RAM). RAM is a type of computer memory that can be accessed randomly, that is, any byte of memory can be accessed without touching the preceding bytes. Auxiliary storage and backing storage are terms used to describe non-volatile storage devices, such as hard drives and SSDs, where data is stored permanently or until it is deliberately erased. Main storage could refer to either RAM or the primary storage device, depending on context, but it is less specific than the term 'random access memory'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>14", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "The smallest unit of information representation which is addressable on the computer memory is", "images": [], "options": {"A": "1 bits", "B": "2 bits", "C": "4 bits", "D": "8 bits"}, "answer": "D", "explanation": "The smallest unit of information representation which is addressable on the computer memory is 8 bits, also known as a byte. A bit is the most basic unit of information in computing and digital communications. The name is a portmanteau of binary digit. However, the byte, not the bit, is the smallest addressable unit of memory in many computer systems.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>15", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Software is referred to as the", "images": [], "options": {"A": "generic term for computer programs", "B": "physical components of the computer", "C": "part of the computer for communication", "D": "part of the computer which is breakable"}, "answer": "A", "explanation": "Software is a general term used to describe a collection of computer programs, procedures, and documentation that perform some task on a computer system. It is the non-tangible component of computers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>16", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The software whose output is intended for the human user is called", "images": [], "options": {"A": "application software", "B": "firmware", "C": "malware", "D": "system software"}, "answer": "A", "explanation": "Application software, also known as an application or an 'app', is computer software designed to help the user to perform specific tasks. Examples include enterprise software, accounting software, office suites, graphics software and media players.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>17", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The parts of the taskbar include:   I - recycle bin  II - start button  III - system tray  IV - quick launch toolbar", "images": [], "options": {"A": "I, II and IV only", "B": "I, III and IV only", "C": "II, III and IV only", "D": "I, II, III and IV"}, "answer": "C", "explanation": "The taskbar is a graphical user interface element that contains various functionalities, such as the Start button, Quick Launch toolbar, and system tray. The recycle bin is not part of the taskbar, it is a separate icon on the desktop.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>18", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The similarities between main memory and registers is that they are:  I - volatile   II - under the direct control of the user  III - protected by the system unit  IV - for system use only", "images": [], "options": {"A": "I, II and IV only", "B": "I, III and IV only", "C": "II, III and IV only", "D": "I, II, III and IV"}, "answer": "B", "explanation": "The main memory and registers are both volatile, meaning they lose their information when power is lost, and they are both protected by the system unit. However, they are not under the direct control of the user and they are not for system use only. Registers are used to hold data that is being processed, while main memory is used to hold data and instructions that are currently in use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>19", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A pictorial representation of the logic of a program is called", "images": [], "options": {"A": "diagram", "B": "flowchart", "C": "pseudocode", "D": "software"}, "answer": "B", "explanation": "A flowchart is a type of diagram that represents an algorithm, workflow or process, showing the steps as boxes of various kinds, and their order by connecting them with arrows. This diagrammatic representation illustrates a solution model to a given problem. Flowcharts are used in analyzing, designing, documenting or managing a process or program in various fields.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>20", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A subroutine is called in a flowchart through the use of", "images": [], "options": {"A": "data", "B": "predefined process", "C": "process", "D": "terminator"}, "answer": "B", "explanation": "In a flowchart, a predefined process symbol is used to represent a subroutine. A subroutine is a sequence of program instructions that performs a specific task, packaged as a unit. This unit can then be used in programs wherever that particular task should be performed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>21", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The symbol used to represent an execution flow in a flowchart is", "images": ["Computer Studies/imgs/2016/img1.png", "Computer Studies/imgs/2016/img2.png", "Computer Studies/imgs/2016/img3.png", "Computer Studies/imgs/2016/img4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "Arrows and lines are commonly used connectors for each processed symbol that represent the flow and sequence of the process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>22", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A suitable notation for the expression mc2 is", "images": [], "options": {"A": "m * c^2", "B": "m * x * 2", "C": "m * c^2", "D": "m * C * ^2"}, "answer": "A", "explanation": "The expression mc2 is a mathematical expression that represents the product of m and the square of c. In programming, the ^ symbol is used to denote exponentiation. Therefore, the correct notation for the expression mc2 is m * c^2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>23", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Use the BASIC program below to answer this question  10 &nbsp &nbsp LET K = 2  20 &nbsp &nbsp LET L = 9  30 &nbsp &nbsp LET SUM = 0  40 &nbsp &nbsp FOR J = K TO STEP 2  50 &nbsp &nbsp SUM = SUM + J2  60 &nbsp &nbsp PRINT \"ANSWER =\", SUM  70 &nbsp &nbsp NEXT J  80 &nbsp &nbsp END    How many times will the statement lines 50 and 60 be repeated?", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": "C", "explanation": "On each iteration of the loop, the statement lines 50 and 60 will be executed. This means that the statement lines 50 and 60 will be repeated 4 times.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>24", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Use the BASIC program below to answer this question  10 &nbsp &nbsp LET K = 2  20 &nbsp &nbsp LET L = 9  30 &nbsp &nbsp LET SUM = 0  40 &nbsp &nbsp FOR J = K TO STEP 2  50 &nbsp &nbsp SUM = SUM + J2  60 &nbsp &nbsp PRINT \"ANSWER =\", SUM  70 &nbsp &nbsp NEXT J  80 &nbsp &nbsp END  Which of the following best represents the sequence of output from the program?", "images": [], "options": {"A": "2, 3", "B": "4, 20, 36", "C": "4, 16, 36, 64", "D": "4, 20, 56, 120"}, "answer": "D", "explanation": "Initially, sum = 0 and J = 2 (from the FOR LOOP and incremented by for 2 every iteration)  (1) sum = 0 + 22 = 0 + 4 = 4 (sum is now 4 and J incremented to 4)  (2) sum = 4 + 42 = 4 + 16 = 20 (sum is now 20 and J incremented to 6)  (3) sum = 20 + 62 = 20 + 36 = 56 (sum is now 56 and J incremented to 8)  (4) sum = 56 + 82 = 56 + 64 = 120 (The program terminates)      Therefore, 4, 20, 56 and 120 best represents the sequence of output from the program.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>25", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Use the BASIC program below to answer this question  10 &nbsp &nbsp LET K = 2  20 &nbsp &nbsp LET L = 9  30 &nbsp &nbsp LET SUM = 0  40 &nbsp &nbsp FOR J = K TO STEP 2  50 &nbsp &nbsp SUM = SUM + J2  60 &nbsp &nbsp PRINT \"ANSWER =\", SUM  70 &nbsp &nbsp NEXT J  80 &nbsp &nbsp END  The last output that will be displayed by the program is", "images": [], "options": {"A": "20", "B": "36", "C": "64", "D": "120"}, "answer": "D", "explanation": "The given BASIC program initializes variables and then uses a loop to calculate the sum of squares for certain values of J. Here's a breakdown of the program's logic:    K = 2 and L = 9 set the starting and ending values of the loop.  The FOR loop runs with J starting at 2, incrementing by 2 each time (TO L STEP 2).  During each iteration, the value of J is squared and added to the SUM variable.  The loop runs until J reaches or exceeds 9, printing the SUM after each iteration.  The values for J will be: 2, 4, 6, and 8. The squares of these numbers are:    22 = 4  42 = 16  62 = 36  82 = 64    Now, summing them up:    SUM = 4 + 16 + 36 + 64 = 120  Thus, the last output displayed by the program is 120.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>26", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Which of the following networks can be extended to cover continents?", "images": [], "options": {"A": "Metropolitan Area Network", "B": "Personal Area Network", "C": "Wide Area Network", "D": "Wireless Area Network"}, "answer": "C", "explanation": "A Wide Area Network (WAN) is a telecommunications network that extends over a large geographical area for the purpose of computer networking. Wide Area Networks are often established with leased telecommunication circuits. This makes it possible for them to cover continents, which is not typically possible for Metropolitan Area Networks, Personal Area Networks, or Wireless Area Networks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>27", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Identify the browsers in the following list   I - telnet  II - netscape navigator  III - opera  IV - mozilla firefox", "images": [], "options": {"A": "I, II and III only", "B": "I, III and IV only", "C": "II, III and IV only", "D": "I, II, III and IV"}, "answer": "C", "explanation": "Telnet is a protocol used on the Internet or local area networks to provide a bidirectional interactive text-oriented communication facility using a virtual terminal connection. It is not a browser. Netscape Navigator, Opera, and Mozilla Firefox are all web browsers, which are software applications used to access information on the World Wide Web. Therefore, the correct answer is II, III and IV only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>28", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Trap doors and bombs are typical examples of", "images": [], "options": {"A": "adware", "B": "computer worms", "C": "firewall", "D": "trojan horses"}, "answer": "D", "explanation": "Trap doors and bombs are typical examples of Trojan horses. A Trojan horse is a type of malicious software that misleads users of its true intent. The term is derived from the Ancient Greek story of the deceptive wooden horse that led to the fall of the city of Troy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>29", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The first four steps required to open an email account include   I - click on \"Create my account\"  II - go to home page of the service provider  III - click create \"New Account\"  IV - click on \"Mail\"", "images": [], "options": {"A": "I, II, IV and III", "B": "II, I, IV and III", "C": "II, IV, III and I", "D": "IV, II, I and III"}, "answer": "C", "explanation": "The correct sequence to open an email account is: II - go to home page of the service provider, IV - click on \"Mail\", III - click create \"New Account\", I - click on \"Create my account\". This sequence ensures that you are on the correct platform (service provider), you are in the correct section (Mail), you are initiating the correct action (creating a new account), and finally confirming the action (Create my account).", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>30", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "The two main components of a radio communication system are", "images": [], "options": {"A": "transmitter and terminal", "B": "receiver and determinator", "C": "transmitter and receiver", "D": "transmitter and terminator"}, "answer": "C", "explanation": "The two main components of a radio communication system are the transmitter and the receiver. The transmitter sends the signal and the receiver receives the signal. The transmitter converts electrical signals into radio waves and sends them while the receiver receives the radio waves and converts them back into electrical signals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>31", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following can a traveller who finds himself in a new environment rely on for direction to his final destination?", "images": [], "options": {"A": "DNS", "B": "GPRS", "C": "GPS", "D": "TCP"}, "answer": "C", "explanation": "A GPS (Global Positioning System) is a system that provides location and time information in all weather conditions, anywhere on or near the Earth where there is an unobstructed line of sight to four or more GPS satellites. It is used for navigation and is the most reliable tool for a traveller in a new environment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>32", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The default number of sheets of a workbook is", "images": [], "options": {"A": "one", "B": "two", "C": "three", "D": "four"}, "answer": "C", "explanation": "In most spreadsheet software like Microsoft Excel, the default number of sheets in a new workbook is three. This can be changed in the settings, but when you open a new workbook, it will typically have three sheets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>33", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "The chart type that does not have the X and Y axes display is the", "images": [], "options": {"A": "area chart", "B": "bar chart", "C": "pie chart", "D": "scatter diagram"}, "answer": "C", "explanation": "A pie chart is a type of graph in which a circle is divided into sectors that each represent a proportion of the whole. It does not have X and Y axes because it does not represent data along two dimensions, but rather as parts of a whole.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>34", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "When a worksheet is deleted from a workbook. It is", "images": [], "options": {"A": "lost forever", "B": "sent to the recycle bin", "C": "sent to the original folder", "D": "stored permanently in main memory"}, "answer": "A", "explanation": "When a worksheet is deleted from a workbook in a spreadsheet software like Microsoft Excel, it is lost forever. It is not sent to the recycle bin or any other location. It's important to be sure before deleting a worksheet as this action cannot be undone.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>35", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "A block of text that is marked by the tab key when the enter is pressed can be referred to as", "images": [], "options": {"A": "margin", "B": "paragraph", "C": "white space", "D": "word wrap"}, "answer": "B", "explanation": "In word processing software like Microsoft Word, a block of text that is marked by the tab key when the enter key is pressed is referred to as a paragraph. The tab key is used to create indentation at the beginning of a paragraph, and pressing the enter key signifies the end of a paragraph.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>36", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Principal uses of word processing software packages include   I - preparing draft articles for publication  II - preparing reports for top management  III - preparing accounts   IV - preparing organisation's newsletter", "images": [], "options": {"A": "I, II and IV only", "B": "I, III and IV only", "C": "II, III and IV only", "D": "I, II, III and IV"}, "answer": "A", "explanation": "The principal uses of word processing software packages include:    I - Preparing draft articles for publication  II - Preparing reports for top management  IV - Preparing the organization's newsletter", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>37", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "In a database, a primary key is a field which contains", "images": [], "options": {"A": "text only", "B": "unique entries", "C": "duplicate values", "D": "numeric value only"}, "answer": "B", "explanation": "In a database, a primary key is a field which contains unique entries. This is because a primary key is used to uniquely identify each record in a database table. No two distinct records in a table can have the same value in the primary key field.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>38", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "One megabyte is equivalent to", "images": [], "options": {"A": "one million bytes", "B": "two million bytes", "C": "three million bytes", "D": "four million bytes"}, "answer": "A", "explanation": "One megabyte is equivalent to one million bytes. This is based on the decimal system where 1MB = 10^6 bytes. However, in the binary system, 1MB is often considered as 2^20 bytes or 1,048,576 bytes, but in the context of data transmission rates and storage capacity, it is usually referred to as one million bytes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>39", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Converting 4B716 to binary is", "images": [], "options": {"A": "0100 1010 01112", "B": "0100 1011 01112", "C": "0100 1000 01112", "D": "0100 1100 01112"}, "answer": "B", "explanation": "Convert each hex digit to 4 binary digits:  = 4 &nbsp &nbsp &nbsp &nbsp &nbsp B &nbsp &nbsp &nbsp &nbsp &nbsp 7  = 0100 &nbsp 1011 &nbsp 0111  = 0100 &nbsp 1011 &nbsp 01112", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2016>40", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The speed of data transfer in the computer can be determined in terms of", "images": [], "options": {"A": "protocol and bus speed", "B": "bus speed and width", "C": "bus speed and storage media", "D": "bus width and storage media"}, "answer": "B", "explanation": "The speed of data transfer in a computer is determined by the bus speed and width. The bus speed refers to how fast data is transferred within the computer's internal components, while the bus width refers to how much data can be transferred at once. The wider the bus, the more data can be transferred simultaneously, thus increasing the speed of data transfer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>41", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The initial screen that is displayed after a computer booting is referred to as", "images": [], "options": {"A": "desktop", "B": "interface", "C": "software", "D": "taskbar"}, "answer": "A", "explanation": "The initial screen that is displayed after a computer boots up is referred to as the desktop. The desktop typically contains icons that represent different computer programs and files, as well as a taskbar and other tools for navigating the computer system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>42", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following is not a biometric data", "images": [], "options": {"A": "finger prints", "B": "password", "C": "pattern of eye iris", "D": "sound of the voice"}, "answer": "B", "explanation": "Biometric data refers to unique, measurable characteristics of human beings that can be used for identification and access control. Examples of biometric data include fingerprints, eye iris patterns, and voice patterns. A password, however, is not a form of biometric data because it is not a unique, measurable characteristic of a human being.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>43", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "The main advantage of intellectual property right is", "images": [], "options": {"A": "maximization of profit", "B": "discovering of brilliant persons", "C": "discovering of sharing", "D": "encouragement of innovations"}, "answer": "D", "explanation": "Intellectual property rights provide an incentive for individuals or companies to innovate by giving them exclusive rights to the commercial use of their inventions. This encourages more innovation as it allows inventors to reap the financial benefits of their inventions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>44", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The word bit refers to", "images": [], "options": {"A": "the value zero or one", "B": "the value zero or more", "C": "central processing unit command", "D": "central processing unit instructions"}, "answer": "A", "explanation": "In computing, a bit is the most basic unit of information. It can have only one of two values, typically 0 or 1.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>45", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The decimal number 1024 in hexadecimal equivalent is", "images": [], "options": {"A": "2416", "B": "40016", "C": "3E816", "D": "8BB16"}, "answer": "B", "explanation": "In hexadecimal numbering system, 1024 is represented as 400.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>46", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following is true of a digital logic gate", "images": [], "options": {"A": "it has at least two inputs but only one output", "B": "it has many outputs and inputs", "C": "it has at least one or more inputs but only one output", "D": "it has at least one input and two outputs"}, "answer": "C", "explanation": "A digital logic gate is a basic building block of a digital circuit. Most logic gates have two inputs and one output. At any given moment, every terminal is in one of the two binary conditions low (0) or high (1), represented by different voltage levels. The logic state of a terminal can, and generally does, change often, as the circuit processes data. In electronics, a logic gate is an idealized or physical device implementing a Boolean function, a logical operation performed on one or more binary inputs that produces a single binary output. So, the correct answer is 'it has at least one or more inputs but only one output'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2016>47", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the following is a temporary file that can be used only once and then discarded?", "images": [], "options": {"A": "refresh file", "B": "master file", "C": "system file", "D": "transaction file"}, "answer": "D", "explanation": "A transaction file is a temporary file that is used to store data that will be used to update the master file. The transaction file is used only once and then discarded after the update process. So, the correct answer is 'transaction file'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>48", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Sorting of records is sufficient and a necessary condition for creating", "images": [], "options": {"A": "random file", "B": "indirect file", "C": "sequential file", "D": "indexed sequential file"}, "answer": "C", "explanation": "Sorting of records is a necessary condition for creating a sequential file. In a sequential file, records are stored in order based on a key field that uniquely identifies the record. This key field is sorted in ascending or descending order. So, the correct answer is 'sequential file'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>49", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "The illegal copying and use of proprietary/copy righted software is called", "images": [], "options": {"A": "hacking", "B": "spamming", "C": "hardware piracy", "D": "software piracy"}, "answer": "D", "explanation": "The illegal copying and use of proprietary/copyrighted software is referred to as 'software piracy'. This is when someone installs and uses commercial software without paying for the program. It is against the law and is a violation of the software's license agreement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2016>50", "subject": "Computer Studies", "year": "2016", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Symptoms of computer virus attack include:  I - improved processing speeds  II - drive light coming up without apparent reason  III - Unexplainable printer activity  IV - file disappearance or strange files appearance on-screen.", "images": [], "options": {"A": "I, II and III only", "B": "I, III and IV only", "C": "II, III and IV only", "D": "I, II, III and IV"}, "answer": "C", "explanation": "Symptoms of a computer virus attack often include drive light coming up without apparent reason, unexplainable printer activity, and file disappearance or strange files appearing on-screen. Improved processing speeds is not a typical symptom of a virus attack, in fact, a virus usually slows down the computer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>1", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "The \"collection of the unorganised facts and figures\" is called", "images": [], "options": {"A": "data", "B": "file", "C": "information", "D": "variable"}, "answer": "A", "explanation": "The 'collection of unorganised facts and figures' is referred to as 'data'. Data is raw, unprocessed, and in an unorganized form that needs to be processed to make it meaningful. Information, on the other hand, is processed data. A file is a container in a computer system for storing data, information, settings, etc. A variable is a storage location paired with an associated symbolic name, which contains some known or unknown quantity of information referred to as a value.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>2", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The census machine was invented by", "images": [], "options": {"A": "Blaise Pascal", "B": "Gottried von Leibnitz", "C": "Herman Hollerith", "D": "Joseph Marie Jacquad"}, "answer": "C", "explanation": "The census machine, also known as the punched card machine, was invented by Herman Hollerith. He developed this machine to help process data for the 1890 U.S. Census. It was a significant step in the development of data processing and marked the beginning of the era of automated computing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>3", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "A graph plotter is most suited for use in a/an", "images": [], "options": {"A": "tax office", "B": "immigration office", "C": "population census office", "D": "geographical information system"}, "answer": "D", "explanation": "A graph plotter is a device that plots graphs or other visual representations of data. It is most suited for use in a geographical information system (GIS) because it can accurately plot geographical data on a map. GIS is a system designed to capture, store, manipulate, analyze, manage, and present all types of geographical data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>4", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "A set of programs, routines and procedures that are used to operate the computer hardware is called", "images": [], "options": {"A": "firmware", "B": "shareware", "C": "software", "D": "utility"}, "answer": "C", "explanation": "Software is a set of programs, routines and procedures that are used to operate the computer hardwares.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>5", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following can be used to write a high level program source code?", "images": [], "options": {"A": "lotus 1-2-3", "B": "MS Access", "C": "Opera", "D": "Text Editor"}, "answer": "D", "explanation": "A high-level program source code is written using a text editor. A text editor is a type of program used for editing plain text files. It provides features for rapid text entry and manipulation. Examples of text editors include Notepad, Sublime Text, Atom, etc. The other options like Lotus 1-2-3, MS Access, and Opera are not used for writing high-level program source code.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>6", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "A computer that requests the services of another computer on a network is called a", "images": [], "options": {"A": "client", "B": "host", "C": "master", "D": "server"}, "answer": "A", "explanation": "Client is a computer that requests the services of another computer on a network. It is a dependent computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>7", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The available page orientation in Microsoft Word are", "images": [], "options": {"A": "portrait and justify", "B": "justify and right align", "C": "left align and landscape", "D": "portrait and landscape"}, "answer": "D", "explanation": "In Microsoft Word, the available page orientations are portrait and landscape. Portrait orientation is a vertical design or layout, while landscape orientation is a horizontal design or layout. The other options like portrait and justify, justify and right align, left align and landscape are not valid page orientations in Microsoft Word.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>8", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "The copyright law is used to protect", "images": [], "options": {"A": "right of men", "B": "right of minors", "C": "intellectual property", "D": "right of women only"}, "answer": "C", "explanation": "The copyright law is used to protect intellectual property. Intellectual property refers to creations of the mind, such as inventions; literary and artistic works; designs; and symbols, names and images used in commerce.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>9", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following component is directly located inside the computer processor?", "images": [], "options": {"A": "ALU", "B": "BIOS", "C": "RAM", "D": "ROM"}, "answer": "A", "explanation": "The Arithmetic Logic Unit (ALU) is directly located inside the computer processor. The ALU performs simple arithmetic and logical operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>10", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Napier's Bone was designed purposely for calculation of", "images": [], "options": {"A": "sum and quotient", "B": "sum and difference", "C": "product and quotient", "D": "difference and quotient"}, "answer": "C", "explanation": "Napier's Bones was a device invented by John Napier for calculation of products and quotients of numbers. The device uses a set of rectangular rods, 'bones', which are inscribed with multiplication tables.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>11", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The hardware component that is responsible for fetching, decoding and execution of program instruction is", "images": [], "options": {"A": "accumulator", "B": "read only memory", "C": "random access memory", "D": "central processing unit"}, "answer": "D", "explanation": "The Central Processing Unit (CPU) is the primary component of a computer that performs most of the processing inside the computer. It's responsible for fetching, decoding, and executing program instructions. The other options like accumulator, read only memory, and random access memory are parts of the computer but they don't perform the functions of fetching, decoding, and executing program instructions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>12", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following is found on the taskbar?", "images": [], "options": {"A": "scrollbar", "B": "wall paper", "C": "screen saver", "D": "quick lunch toolbar"}, "answer": "D", "explanation": "The Quick Launch toolbar is found on the taskbar. It provides access to programs that you frequently use. The scrollbar, wallpaper, and screensaver are not found on the taskbar. The scrollbar is a graphical control element with which continuous text, pictures, or anything else can be scrolled including time in video applications, the wallpaper is the image in the background on your computer desktop, and the screensaver is a computer program that blanks the screen or fills it with moving images or patterns when the computer is not in use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>13", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A high level language program translator which converts a source code to machine readable format and executes it one line at a time is called", "images": [], "options": {"A": "compiler", "B": "debugger", "C": "editor", "D": "interpreter"}, "answer": "D", "explanation": "An interpreter is a type of translator used for translating high-level programming languages to machine language. It translates the source code line by line into machine code and executes it. A compiler, on the other hand, translates the entire source code into machine code before execution. A debugger is a tool used to test and debug a program, while an editor is a software application for creating or manipulating the text of computer programs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>14", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Use the following QBASIC statement to answer this question   DIM DEPOSIT (1, 10)    The keyword DIM in the statement stands for", "images": [], "options": {"A": "diagram", "B": "diameter", "C": "diamond", "D": "dimension"}, "answer": "D", "explanation": "In QBASIC, DIM is a keyword used to declare or dimension an array. It stands for 'dimension'. An array is a data structure that contains a group of elements. In QBASIC, arrays are declared using the DIM statement. For example, DIM DEPOSIT (1, 10) declares an array named DEPOSIT with 11 elements, indexed from 1 to 10.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>15", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Use the following QBASIC statement to answer this question   DIM DEPOSIT (1, 10)  The expression DEPOSIT (1, 10) stands for an array with", "images": [], "options": {"A": "1 element", "B": "11 elements", "C": "10 elements", "D": "No element"}, "answer": "C", "explanation": "10 elements (starts at index 1 and ends at index 10)", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>16", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "In a star network, each node must", "images": [], "options": {"A": "be connected directly to adjacent nodes", "B": "be connected directly to a central network hub", "C": "be connected directly to a common backbone cable", "D": "possess a token before it can transmit signal to adjacent node"}, "answer": "B", "explanation": "In a star network, each node (computer, printer, or other device) is connected directly to a central network hub. The central hub manages and controls all functions of the network. It also acts as a repeater for the data flow. This type of network is easy to install and manage, but bottlenecks can occur because all data must pass through the hub.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>17", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Which of the following views is used to create database objects in Microsoft Access?", "images": [], "options": {"A": "Design view", "B": "Datasheet view", "C": "Layout view", "D": "Normal view"}, "answer": "A", "explanation": "In Microsoft Access, the Design View is used to create and modify the structure of database objects such as tables, forms, and reports. It provides a more detailed view of the structure of the database object.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>18", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "A field chosen to uniquely identify every record in a database is", "images": [], "options": {"A": "foreign key", "B": "local key", "C": "primary key", "D": "secondary key"}, "answer": "C", "explanation": "In a database, a primary key is a field or combination of fields that uniquely identifies each record. It is a fundamental concept in relational database design and ensures that each record can be uniquely identified, preventing duplicates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>19", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Use the table below to answer this question  CharacterDecimal codeASCII codeN781001110O11001111T8411    The cell labelled I in the table represents", "images": [], "options": {"A": "72", "B": "74", "C": "75", "D": "79"}, "answer": "D", "explanation": "Based on the data presented in the table, the value contained within cell I is 79.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2017>20", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Use the table below to answer this question  CharacterDecimal codeASCII codeN781001110O11001111T8411  The cell labelled II in the table represents", "images": [], "options": {"A": "1001101", "B": "1010100", "C": "1010101", "D": "1010110"}, "answer": "B", "explanation": "The cell labelled II in the table represents the ASCII code for the character 'T'. The ASCII code for 'T' is 1010100.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2017>21", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Use the table below to answer this question  CharacterDecimal codeASCII codeN781001110O11001111T8411  The ASCII code for the word NOT can be written as", "images": [], "options": {"A": "101010010011111001110", "B": "100111010011111010100", "C": "100111110101001001110", "D": "100111010101001111"}, "answer": "B", "explanation": "The ASCII code for the word 'NOT' can be written as the concatenation of the ASCII codes for 'N', 'O', and 'T'. The ASCII codes for 'N', 'O', and 'T' are 1001110, 1001111, and 1010100 respectively. Therefore, the ASCII code for 'NOT' is 100111010011111010100.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2017>22", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the following is not a method of accessing file?", "images": [], "options": {"A": "Circular", "B": "Random", "C": "Serial", "D": "Sequential"}, "answer": "A", "explanation": "The term 'circular' is not applicable to file access methods. Files are accessed using specific methods such as sequential access, direct access, or indexed sequential access. Circular is not a valid or recognized method for accessing file data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>23", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The advantages of a computer include that they:  I - operate at high speeds  II - think for the user  III - are accurate  IV - are credible", "images": [], "options": {"A": "I, II and III only", "B": "I, III and IV only", "C": "II, III and IV only", "D": "I, II, II and IV"}, "answer": "B", "explanation": "Computers operate at high speeds, are accurate, and are credible. However, computers do not think for the user. They only execute commands given to them by the user. Therefore, the correct answer is 'I, III and IV only'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>24", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "In MS Excel, comments used in cells are called", "images": [], "options": {"A": "cell tip", "B": "smart tip", "C": "soft tip", "D": "web tip"}, "answer": "A", "explanation": "Cell tips are text notes that can be added to cells in Excel spreadsheets. They are displayed in a small yellow bubble when the mouse pointer is over the cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>25", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following statements is not true about secondary storage media? They", "images": [], "options": {"A": "are volatile", "B": "are non-volatile", "C": "are relatively cheap", "D": "have storage capacity"}, "answer": "A", "explanation": "Secondary storage media are non-volatile, relatively cheap, and have storage capacity. However, they are not volatile. Volatile memory loses its stored information when the power to the computer is turned off, while non-volatile memory retains the stored information even when not powered. Therefore, the correct answer is 'are volatile'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>26", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the file formats is supported in all windows operating systems?", "images": [], "options": {"A": "BSD", "B": "EXT", "C": "FAT", "D": "NTFS"}, "answer": "C", "explanation": "FAT (File Allocation Table) is a file system that is supported by all versions of Windows, DOS, and many other operating systems. BSD (Berkeley Software Distribution) is a Unix operating system derivative, EXT is a file system used primarily by Linux, and NTFS (New Technology File System) is a file system used by Windows NT and its successors, but not supported by all versions of Windows.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>27", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following symbols is not a relational operator in BASIC programming language?", "images": [], "options": {"A": "", "B": ">", "C": "∧", "D": ""}, "answer": "C", "explanation": "In BASIC programming language, the relational operators are  (greater than), and &#8804; (less than or equal to). The symbol ∧ is not a relational operator in BASIC. It is often used in other programming languages and mathematical notation to represent logical AND or exponentiation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>28", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The following are features of web browsers except", "images": [], "options": {"A": "address bar", "B": "formular bar", "C": "menu bar", "D": "title bar"}, "answer": "B", "explanation": "Web browsers typically have features like an address bar, a menu bar, and a title bar. The address bar is where you type in the URL of the website you want to visit, the menu bar contains options for things like saving and printing, and the title bar displays the title of the web page you're viewing. However, a 'formular bar' is not a feature of a web browser. It's a term more commonly associated with spreadsheet applications like Microsoft Excel, where it's used to enter and edit data in the active cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>29", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The act of translating data into a secret code is known as", "images": [], "options": {"A": "authentication", "B": "authorization", "C": "encryption", "D": "piracy"}, "answer": "C", "explanation": "Encryption is the process of converting data into a code to prevent unauthorized access. It is a method of securing data by converting it into a form that can only be read by someone who knows how to convert the data back into its original form. Authentication and authorization are security measures but they do not involve translating data into a secret code. Piracy is the unauthorized use or reproduction of another's work.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>30", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The absolute address of cell G5 in a spreadsheet application is represented by", "images": [], "options": {"A": "$G5", "B": "G$5", "C": "$G$5", "D": "$G5$"}, "answer": "C", "explanation": "In spreadsheet applications, the absolute address of a cell is represented by prefixing both the column letter and row number with a dollar sign ($). So, the absolute address of cell G5 is represented as $G$5. This means that if the formula is copied to another cell, the cell reference will not change.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>31", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Soft boot is initiated by pressing", "images": [], "options": {"A": "Ctrl + Alt + Del", "B": "Function key F10", "C": "Main switch", "D": "Bootstrap"}, "answer": "A", "explanation": "A soft boot, also known as a warm boot, is a restart of a computer that is already turned on. It is often initiated by pressing the Ctrl + Alt + Del keys simultaneously. Function key F10, main switch, and bootstrap do not initiate a soft boot.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>32", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the following factors limits access to computerized file system? It", "images": [], "options": {"A": "occupies less space", "B": "requires regular supply of power", "C": "is highly efficient in processing information", "D": "provides easy and fast access to information"}, "answer": "B", "explanation": "A computerized file system requires a regular supply of power to function. Without power, the system cannot operate, thus limiting access to the files. The other options are advantages of a computerized file system, not limitations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>33", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following is not a good ICT security policy?", "images": [], "options": {"A": "Re-use of old password", "B": "Frequent change of password", "C": "Backing up files and documents", "D": "Scanning e-mail attachment for virus before opening it"}, "answer": "A", "explanation": "Re-using old passwords is not a good ICT security policy because it can make the system vulnerable to unauthorized access. Good security policies include frequent password changes, backing up files and documents, and scanning email attachments for viruses before opening them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>34", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "INPUTINPUTOUTPUTPQR001010100110  The table above represents the Truth Table for", "images": [], "options": {"A": "NOT logic gate", "B": "NOR logic gate", "C": "AND logic gate", "D": "NAND logic gate"}, "answer": "B", "explanation": "The given truth table represents the NOR logic gate. In a NOR gate, the output is true (or 1) only when all inputs are false (or 0). In the given table, the output is 1 only when both inputs P and Q are 0, which is the behavior of a NOR gate. The other options (NOT, AND, NAND) do not match this behavior.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2017>35", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Use the information below to answer this question  I. - Mouse II. - Keyboard III. - Scanner IV. - Joystick.    The input devices used to capture date of birth, on an online form as", "images": [], "options": {"A": "I, III and IV only", "B": "I, II and III only", "C": "I and II only", "D": "II and IV only"}, "answer": "C", "explanation": "To capture date of birth on an online form, you would typically use a mouse to navigate to the form field and a keyboard to type in the date. A scanner or joystick would not typically be used for this purpose. Therefore, the correct answer is 'I and II only'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>36", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Use the information below to answer this question  I. - Mouse II. - Keyboard III. - Scanner IV. - Joystick.  The input devices used to capture finger print is", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "C", "explanation": "A scanner is typically used to capture fingerprints. This is because a scanner can create a digital image of the fingerprint, which can then be stored and analyzed. A mouse, keyboard, or joystick would not typically be used for this purpose. Therefore, the correct answer is 'III'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>37", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "To hibernate windows operating system means", "images": [], "options": {"A": "restart the computer in safe mode", "B": "restart the computer in hibernate mode", "C": "shut down the computer and terminate all the running applications", "D": "shut down the computer without closing all the running applications"}, "answer": "D", "explanation": "Hibernate is a power-saving state designed primarily for laptops. While sleep puts your work and settings in memory and draws a small amount of power, hibernation puts your open documents and programs on your hard disk, and then turns off your computer. Of all the power-saving states in Windows, hibernation uses the least amount of power. Therefore, the correct answer is 'shut down the computer without closing all the running applications'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>38", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following statements can be used for looping in BASIC?", "images": [], "options": {"A": "FOR ... NEXT", "B": "IF ... THEN", "C": "GO TO", "D": "GO SUB"}, "answer": "A", "explanation": "The 'FOR ... NEXT' statement is used for looping in BASIC (Beginner's All-purpose Symbolic Instruction Code). It allows a block of code to be repeated a certain number of times. The loop starts with the 'FOR' statement, which sets the loop counter to an initial value. The 'NEXT' statement increases the loop counter by one and repeats the loop if the final value is not reached.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>39", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The flowchart symbol   represents", "images": ["Computer Studies/imgs/2017/img1.png"], "options": {"A": "comment", "B": "connector", "C": "decision", "D": "input/output"}, "answer": "C", "explanation": "The diamond-shaped flowchart symbol represents a decision point, indicating a juncture in the process where a choice or evaluation must be made. This symbol is typically used to represent conditional statements or branching points, where the flow of the process is determined based on a specific condition or comparison.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>40", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Which of the following tasks is accomplished by using bookmarks? To", "images": [], "options": {"A": "add anchors in webpage", "B": "add hyperlinks in webpage", "C": "quickly jump to specific location in document", "D": "mark the ending of a paragraph of a document"}, "answer": "C", "explanation": "Bookmarks are used to quickly jump to a specific location in a document. They are particularly useful in large documents where navigating to a particular section manually would be time-consuming. By setting a bookmark at a particular location, you can instantly return to that location at any time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>41", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Which of the following function keys can be used to run slide show in a PowerPoint presentation?", "images": [], "options": {"A": "F2", "B": "F5", "C": "F7", "D": "F12"}, "answer": "B", "explanation": "In PowerPoint, the F5 function key is used to start a slide show from the beginning. If you want to start the slide show from the current slide, you would use the Shift + F5 shortcut. The other function keys listed have different uses: F2 is used to edit the active cell in Excel, F7 is used to start spell check in Word, and F12 is used to open the Save As dialog box in most Microsoft Office programs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>42", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Use the MS Excel table below to answer this question  S/NABCD1Stock Listof Tayo Okeke as at May, 20142Quoted stockShare UnitCurrent Unit Price (₦)Value3Tanzel Plc44,000502,200,0004Kaptol125,00080 ## # #5BANK KLM75,000140####6Arix Oil10,0002502,500,0007TOTAL VALUE    The formula used to compute the TOTAL VALUE in cell D7 is", "images": [], "options": {"A": "= sum (D2:D7)", "B": "= sum (D3:D7)", "C": "= sum (D2:D6)", "D": "= sum (D3:D6)"}, "answer": "D", "explanation": "The formula used to calculate the total value in cell D7 is \"=SUM(D3:D6)\". This formula instructs the spreadsheet software to add together the values contained within cells D3, D4, D5, and D6, resulting in the total sum of those values.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>43", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Use the MS Excel table below to answer this question  S/NABCD1Stock Listof Tayo Okeke as at May, 20142Quoted stockShare UnitCurrent Unit Price (₦)Value3Tanzel Plc44,000502,200,0004Kaptol125,00080 ## # #5BANK KLM75,000140####6Arix Oil10,0002502,500,0007TOTAL VALUE  Which of the columns needs to be adjusted to accommodate the cells contents?", "images": [], "options": {"A": "Column A", "B": "Column B", "C": "Column C", "D": "Column D"}, "answer": "D", "explanation": "Column D needs to be adjusted to accommodate the cells contents. This is because the contents of the cells in column D are larger than the column width. In Excel, adjusting a column width is necessary when the data in a cell is wider than the column itself.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>44", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Which of the following statements is true for a circuit switching communication system?", "images": [], "options": {"A": "It is not ideal for a real-time communication", "B": "Messages must be divided into packets before they are sent", "C": "It does not require any dedicated channel to be established between two parties", "D": "A dedicated channel must be established between two parties through the period of communication"}, "answer": "D", "explanation": "In a circuit switching communication system, a dedicated channel must be established between two parties through the period of communication. This is because circuit switching is a method of communication in which a dedicated channel (or circuit) is established for the duration of the transmission. The channel is reserved for the entire duration of the communication, making it ideal for real-time communication.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>45", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The first three steps to open an e-mail account include:   I - Click on create my account  II - Go to home page  III - Click create New Account", "images": [], "options": {"A": "I, II and III", "B": "II, I and III", "C": "II, III and I", "D": "I, III and II"}, "answer": "C", "explanation": "he correct order for opening an email account typically starts with visiting the homepage, then selecting the option to create a new account, followed by proceeding with account creation. Therefore, the correct sequence is II, III and I.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>46", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Converting 4B7hexadecimal to binary is", "images": [], "options": {"A": "010010100111two", "B": "010010110111two", "C": "010010000111two", "D": "010011000111two"}, "answer": "B", "explanation": "Convert each hex digit to 4 binary digits:  = 4 &nbsp &nbsp &nbsp &nbsp &nbsp B &nbsp &nbsp &nbsp &nbsp &nbsp 7  = 0100 &nbsp 1011 &nbsp 0111  = 010010110111two", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>47", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The modifier keys on the computer keyboard comprises of", "images": [], "options": {"A": "DEL, ESC and ALT keys", "B": "CTRL, CAPSLOCK and DEL keys", "C": "SHIFT, CTRL and ALT keys", "D": "CTRL, ALT and DEL keys"}, "answer": "C", "explanation": "Modifier keys on a computer keyboard are keys that modify the normal action of another key when the two are pressed in combination. Examples are the Shift, Ctrl (Control), and Alt (Alternate) keys. So, the correct answer is 'SHIFT, CTRL and ALT keys'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>48", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Arrange in hierarchical order by date the following inventions:  I - Census machine  II - Abacus   III - Slide rule   IV - Difference engine", "images": [], "options": {"A": "IV, II, III and I", "B": "III, I, II and IV", "C": "II, III, IV and I", "D": "I, IV, III and II"}, "answer": "C", "explanation": "The correct order of the inventions by date is: II - Abacus (Ancient times), III - Slide rule (1622), IV - Difference engine (1822), I - Census machine (1890). The Abacus is the oldest of these inventions, followed by the Slide rule, then the Difference engine, and finally the Census machine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2017>49", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A student mistakenly pressed the F5 key on keyboard while browsing on the internet. This will lead to", "images": [], "options": {"A": "opening of a new tab", "B": "closing of the active window", "C": "closing of all opening windows", "D": "reloading of the active window"}, "answer": "D", "explanation": "Pressing the F5 key on a keyboard while browsing the internet will lead to the reloading of the active window. This is a common keyboard shortcut in many web browsers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2017>50", "subject": "Computer Studies", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Opening an already existing sequential file in output (O) mode will lead to", "images": [], "options": {"A": "buffer overflow", "B": "deletion of the current content of the file", "C": "duplication of the current content of the file", "D": "addition of new data to the content of the file"}, "answer": "B", "explanation": "Opening an already existing sequential file in output mode will lead to the deletion of the current content of the file. In output mode, the file is opened for writing. If the file already exists, its contents are discarded and the file is treated as a new empty file.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>1", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Data can be defined as", "images": [], "options": {"A": "raw facts", "B": "mixed facts", "C": "facts on prints", "D": "processed facts"}, "answer": "A", "explanation": "Data is defined as raw facts or figures. These facts are unprocessed and can be processed into information. Hence, the correct answer is 'raw facts'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>2", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : HISTORY OF COMPUTERS", "question": "Which of the following output devices was common among the computing devices of the 19th century?", "images": [], "options": {"A": "Monitor", "B": "Plotter", "C": "Printer", "D": "Speaker"}, "answer": "C", "explanation": "In the 19th century, the most common output device among computing devices was the printer. Monitors and plotters were not yet invented, and speakers are not typically considered computing devices. Therefore, the correct answer is 'Printer'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>3", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The pre-computing age device which made use of beads and frames is", "images": [], "options": {"A": "Abacus", "B": "Napier's bone", "C": "Liebnitz multiplier", "D": "Burrough's counting device"}, "answer": "A", "explanation": "The Abacus is a pre-computing age device that made use of beads and frames. It is an ancient tool used for arithmetic calculations. Therefore, the correct answer is 'Abacus'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>4", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The system unit house the following components except", "images": [], "options": {"A": "plotter", "B": "motherboard", "C": "floppy disk", "D": "central processing unit"}, "answer": "A", "explanation": "The system unit is the main part of a computer. It includes the motherboard, central processing unit (CPU), and memory (RAM), as well as drives, like the hard drive and disc drive. However, a plotter is an external device that is used for printing vector graphics. In other words, it does not reside within the system unit, hence it is the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>5", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "During program execution in the central processing unit, the instruction is interpreted by the", "images": [], "options": {"A": "arithmetic logic", "B": "control unit", "C": "memory unit", "D": "registers unit"}, "answer": "B", "explanation": "During program execution in the central processing unit (CPU), the instruction is interpreted by the control unit. The control unit is a component of the CPU that manages the data flow between the processor and the rest of the computer system. It interprets the instructions fetched into the CPU and controls the operation of the other hardware components.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>6", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The most important system software in a computer system is the", "images": [], "options": {"A": "control programs", "B": "language translator", "C": "operating system", "D": "utility programs"}, "answer": "C", "explanation": "The most important system software in a computer system is the operating system. The operating system is a program that acts as an interface between the user and the computer hardware and controls the execution of all kinds of programs. It provides a software platform on top of which other programs, called application programs, can run.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>7", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "QBASIC keywords do not include", "images": [], "options": {"A": "FIND", "B": "LET", "C": "REM", "D": "STOP"}, "answer": "A", "explanation": "FIND is not a keyword in QBASIC. QBASIC keywords include LET, REM, STOP, etc. Keywords in programming languages are reserved words that are used to perform certain functions or operations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>8", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "An icon, a graphic or a text in a document or a webpage that connects to another file or object is called a", "images": [], "options": {"A": "hyperlink", "B": "domain name", "C": "web browser", "D": "web server"}, "answer": "A", "explanation": "Hyperlink is an icon, a graphic or a text in a document or webpage that connects to another file or object.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>9", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The largest component in a spreadsheet is", "images": [], "options": {"A": "cell", "B": "range", "C": "workbook", "D": "worksheet"}, "answer": "C", "explanation": "The largest component in a spreadsheet is a workbook. A workbook can contain multiple worksheets, each worksheet can contain multiple ranges, and each range can contain multiple cells.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>10", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Warm boot in computing is the same as", "images": [], "options": {"A": "debugging", "B": "handshake", "C": "hard boot", "D": "soft boot"}, "answer": "D", "explanation": "Warm boot in computing refers to the process of restarting a computer that is already turned on through the operating system. This is also known as a soft boot. A hard boot, on the other hand, involves turning off the power completely and then turning it back on.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>11", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The basic computer operation involves the following except", "images": [], "options": {"A": "Access", "B": "Input", "C": "Output", "D": "Process"}, "answer": "A", "explanation": "The basic operations of a computer include input, output, and processing. Access is not considered a basic operation of a computer. It is rather a function of the operating system that manages the computer's resources.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>12", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "The file that contains historical record is called a", "images": [], "options": {"A": "data file", "B": "master file", "C": "reference file", "D": "transaction file"}, "answer": "B", "explanation": "A master file in computing is a file that contains historical records or data. It is a primary file in a data processing system that holds the authoritative data items relating to an organization's business entities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>13", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Random file organisation is also known as", "images": [], "options": {"A": "direct file organisation", "B": "indexed file organisation", "C": "serial file organisation", "D": "sequential file organisation"}, "answer": "A", "explanation": "Random file organization is also known as direct file organization. In this type of file organization, records are stored directly at the location computed by applying a transformation or hash function to a key field. This allows for quick access to records.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>14", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following options is not a data type?", "images": [], "options": {"A": "Alphabetic data", "B": "Alphanumeric data", "C": "Numeric data", "D": "Valid data"}, "answer": "D", "explanation": "Valid data is not a data type. Alphabetic, alphanumeric, and numeric data are all types of data that describe the kind of information that can be stored and manipulated. Valid data, on the other hand, refers to data that is correct or accurate and does not describe a specific type of data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>15", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The major components of a computer system are", "images": [], "options": {"A": "firmware and humanware", "B": "hardware and firmware", "C": "hardware and software", "D": "software and firmware"}, "answer": "C", "explanation": "The major components of a computer system are hardware and software. Hardware refers to the physical components of a computer system, such as the CPU, memory, and input/output devices. Software refers to the programs and data that the computer processes. Firmware, which is a type of software that is closely related to hardware, and humanware, which refers to the human operators of the computer, are not considered major components of a computer system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>16", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The largest computer system in terms of processing power is", "images": [], "options": {"A": "laptop computer", "B": "mainframe computer", "C": "mini computer", "D": "super computer"}, "answer": "D", "explanation": "The largest computer system in terms of processing power is a supercomputer. Supercomputers are high-level computers used for complex computations and data processing. They are faster and more powerful than other types of computers such as mainframes, minicomputers, and laptops.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>17", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Figure 1 is a logic gate.    The logic gate represented in figure 1 is called", "images": ["Computer Studies/imgs/2018/img1.png"], "options": {"A": "AND gate", "B": "NAND gate", "C": "NOR gate", "D": "OR gate"}, "answer": "C", "explanation": "The logic gate shown in Figure 1 is known as a NOR Gate. A NOR gate is a combination of an OR gate followed by a NOT gate. It produces a high output (1) only when all of its inputs are low (0). In other words, the NOR gate gives an output of 0 if any of its inputs are high (1). This type of gate is widely used in digital circuits for performing logical negation and disjunction operations. In this case, Figure 1 is symbolizing the functionality of a NOR gate, which inverts the result of an OR gate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>18", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Identify the logic gate in figure 2.", "images": ["Computer Studies/imgs/2018/img2.png"], "options": {"A": "AND gate", "B": "NAND gate", "C": "NOR gate", "D": "OR gate"}, "answer": "B", "explanation": "The logic gate depicted in Figure 2 is called a NAND Gate. A NAND gate is a combination of an AND gate followed by a NOT gate. It produces a low output (0) only when all of its inputs are high (1). In any other case, the output will be high (1). Essentially, a NAND gate performs the opposite function of an AND gate, meaning it negates the result of an AND operation. NAND gates are fundamental in digital electronics and are commonly used in constructing complex circuits, including memory and processor systems.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>19", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES~~TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM~~TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Which of the following programs is an application specific?", "images": [], "options": {"A": "CorelDraw", "B": "Microsoft Access", "C": "Microsoft Word", "D": "Payroll System"}, "answer": "D", "explanation": "An application-specific program is a program that is designed to perform a specific task or tasks. In this case, a Payroll System is an application-specific program because it is designed specifically for managing payroll tasks. On the other hand, CorelDraw, Microsoft Access, and Microsoft Word are general-purpose software that can be used for a variety of tasks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>20", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES~~TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM~~TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The following programs are general purpose application software except", "images": [], "options": {"A": "CorelDraw", "B": "Editor", "C": "MS Access", "D": "MS Word"}, "answer": "B", "explanation": "General purpose application software is software that can be used for a variety of tasks. In this case, CorelDraw, MS Access, and MS Word are all general-purpose software. An editor, however, is not a general-purpose application software. It is a type of software that is used for editing code or text.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>21", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The following are relational operators in QBASIC programming except", "images": [], "options": {"A": "", "B": ">", "C": "'\"", "D": "="}, "answer": "C", "explanation": "The relational operators in QBASIC are , =, &#8804;, &#8805;, <>. The option '\"' is not a relational operator in QBASIC.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>22", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The three levels of programming languages are", "images": [], "options": {"A": "assembly language, low level language and high level language", "B": "java, C language and pascal", "C": "machine language, low level language and high level language", "D": "machine language, machine code and assembly language"}, "answer": "C", "explanation": "The three levels of programming languages are machine language, assembly language, and high-level language.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>23", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "The following components are network interconnecting devices except", "images": [], "options": {"A": "hub", "B": "modem", "C": "router", "D": "webcam"}, "answer": "D", "explanation": "The network interconnecting devices are devices that connect multiple networks together. The option 'webcam' is not a network interconnecting device.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>24", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Which of the following network cables offers the highest data transmission speed?", "images": [], "options": {"A": "Coaxial", "B": "Fibre optic", "C": "Telephone line", "D": "Twisted pair"}, "answer": "B", "explanation": "Fibre optic cables offer the highest data transmission speed. This is because they use light to transmit data, which travels faster than the electrical signals used in other types of cables.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>25", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Which of the following options is not an advantage of linear bus topology?", "images": [], "options": {"A": "It requires less cable length", "B": "It ensures easy broadcasting", "C": "Additional nodes can be connected easily", "D": "Terminators are required at both ends of the cable"}, "answer": "D", "explanation": "The statement 'Terminators are required at both ends of the cable' is not an advantage of linear bus topology. In fact, it is a requirement for this topology to prevent signal reflection at the ends of the main cable. The other options are advantages of linear bus topology.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>26", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Which of the following components are data communication equipment?  I. Scanner  II. Hub  III. Modem", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III"}, "answer": "C", "explanation": "Hub and Modem are data communication equipment. A hub is a common connection point for devices in a network and a modem is a device that modulates an analog carrier signal to encode digital information, and also demodulates such a carrier signal to decode the transmitted information. A scanner, on the other hand, is an input device that scans documents and converts them into digital data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>27", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The speed of data transfer in the computer can be determined in terms of", "images": [], "options": {"A": "protocol and bus speed", "B": "bus speed and bus width", "C": "bus width and storage media", "D": "bus speed and storage media"}, "answer": "B", "explanation": "The speed of data transfer in a computer is determined by the bus speed and bus width. The bus speed refers to how fast data is transferred across the bus. The bus width, on the other hand, refers to how much data can be transferred at once. The wider the bus, the more data can be transferred at once.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>28", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The process of restarting the computer system is known as", "images": [], "options": {"A": "cold booting", "B": "hard booting", "C": "hot booting", "D": "warm booting"}, "answer": "D", "explanation": "The process of restarting the computer system is known as warm booting. Warm booting is the process of restarting a computer that is already turned on through the operating system. This can be done by selecting the 'restart' option from the operating system's 'shutdown' menu or by pressing a combination of keys (such as Ctrl + Alt + Del) to trigger a restart.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>29", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The ASCII character set represents alphabetical and control characters using numeric codes ranging from", "images": [], "options": {"A": "0 to 124", "B": "0 to 125", "C": "0 to 127", "D": "0 to 128"}, "answer": "C", "explanation": "The ASCII (American Standard Code for Information Interchange) character set represents alphabetical and control characters using numeric codes ranging from 0 to 127. This includes both upper and lower case alphabets, digits, punctuation marks, control characters and special characters.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>30", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "A row in a database table is referred to as", "images": [], "options": {"A": "attribute", "B": "data item", "C": "field", "D": "record"}, "answer": "D", "explanation": "In the context of a database, a row is referred to as a 'record'. A record is a group of related fields (columns) of information treated as a unit. For example, in a student database, each student's details (name, ID, course, etc.) would form a record.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>31", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "The conversion of readable data to unreadable codes in order to prevent unauthorised access is known as", "images": [], "options": {"A": "authentication", "B": "encryption", "C": "encoding", "D": "decryption"}, "answer": "B", "explanation": "The process of converting readable data into unreadable codes to prevent unauthorized access is known as 'encryption'. Encryption is a method of securing data by scrambling the information into a format that can only be read (or 'decrypted') by someone who has the correct 'key'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>32", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The algebraic equation for the AND gate with input variables A and B is", "images": [], "options": {"A": "X = A.B", "B": "X = A+B", "C": "X = A-B", "D": "X = A + By"}, "answer": "A", "explanation": "The algebraic equation for the AND gate with input variables A and B is 'X = A.B'. In Boolean algebra, the dot represents the AND operation. The AND gate is a basic digital logic gate that provides an output which is true only when all its inputs are true.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>33", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The command line prompt of MS-DOS operating system is represented as", "images": [], "options": {"A": "C: >", "B": "C:\\", "C": "C:\\>", "D": "C\\:>"}, "answer": "C", "explanation": "The command line prompt of MS-DOS operating system is represented as 'C:\\>'. This is because in MS-DOS, the command line prompt shows the current drive letter (C) followed by a colon, a backslash, and a greater-than sign. The backslash represents the root directory of the current drive, and the greater-than sign is the actual prompt symbol that indicates the system is ready to accept commands.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>34", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The process of testing the logic of programs to ensure they give correct result is known as", "images": [], "options": {"A": "algorithm", "B": "desk checking", "C": "flowcharting", "D": "table checking"}, "answer": "B", "explanation": "The process of testing the logic of programs to ensure they give correct result is known as 'desk checking'. Desk checking is a manual process where a programmer checks the logic of their program by going through each line of code to ensure it works as expected. It is a step in the debugging process where errors in the program's logic can be identified and corrected before the program is run.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>35", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The MS-Windows shortcut keys to initiate warm booting is", "images": [], "options": {"A": "Alt + F4", "B": "Ctrl + Alt + Del", "C": "Ctrl + Esc", "D": "Ctrl + Shift + Del"}, "answer": "B", "explanation": "The MS-Windows shortcut keys to initiate warm booting is 'Ctrl + Alt + Del'. Warm booting refers to the process of restarting a computer system which is already on. This can be done in Windows using the 'Ctrl + Alt + Del' shortcut keys. This command interrupts the computer's operations and triggers a soft reboot without turning off the power.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>36", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The number 28ten in binary is", "images": [], "options": {"A": "1001two", "B": "11001two", "C": "110011two", "D": "11100two"}, "answer": "D", "explanation": "The number 28 in decimal (base 10) is represented as 11100 in binary (base 2). This is because 28 = 2^4 + 2^3 + 2^2 = 16 + 8 + 4 = 28. Therefore, the correct option is 4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>37", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following options is a biometric data?", "images": [], "options": {"A": "Gender", "B": "Password", "C": "Date of birth", "D": "Pattern of eye iris"}, "answer": "D", "explanation": "Biometric data refers to unique, measurable characteristics used to label and describe individuals. This includes physical characteristics like fingerprints, facial recognition, and iris recognition. Therefore, the correct option is 4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>38", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "A site engineer intends to acquire a computer system. What factors will he consider if he must choose a notebook computer over a desktop computer?", "images": [], "options": {"A": "Size, cost and battery life", "B": "Cost, size and convenience", "C": "Size, convenience and battery life", "D": "Cost, convenience and battery life"}, "answer": "C", "explanation": "When choosing a notebook computer over a desktop computer, the main factors to consider are size (notebooks are more portable), convenience (notebooks can be used in a variety of settings), and battery life (notebooks have a built-in power source that allows them to be used without being plugged into an outlet). Therefore, the correct option is 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>39", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Use the logic truth table in figure 3 to answer this question.  XYZ001011101110    Given that X and Y are input variables while Z is the output. The truth table in figure 3 represents", "images": [], "options": {"A": "XOR gate", "B": "EX OR gate", "C": "NOR gate", "D": "NAND gate"}, "answer": "D", "explanation": "The NAND gate, as represented in the table above, is a logic gate that performs the inverse of an AND operation. It outputs a low signal (0) only when all of its inputs are high (1). In every other input combination, the output will be high (1). The truth table for a NAND gate shows that even if just one input is 0, the output will be 1. This behavior is crucial for many digital circuits, making the NAND gate an essential building block in both combinational and sequential logic designs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>40", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Use the logic truth table in figure 3 to answer this question.  XYZ001011101110  A logic gate contains three input variable. The total possible combination of the input variables is", "images": [], "options": {"A": "3", "B": "4", "C": "8", "D": "12"}, "answer": "C", "explanation": "A logic gate with three input variables can have 2^3 = 8 possible combinations of the input variables. This is because each input variable can be either true (1) or false (0), giving two possibilities for each variable. The total number of combinations is therefore the number of possibilities for each variable raised to the power of the number of variables.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>41", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The following are the guidelines for drawing flowcharts except that it", "images": [], "options": {"A": "must have a logical start and finish", "B": "should be clear, neat and easy to follow", "C": "should follow a direction of right to left or bottom to top", "D": "should follow a direction of left to right or top to bottom"}, "answer": "C", "explanation": "Flowcharts should follow a direction of left to right or top to bottom. This is the standard convention for flowchart design, as it follows the natural reading direction for most languages. Therefore, the statement that a flowchart should follow a direction of right to left or bottom to top is incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>42", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Use the information below to answer this question  As a computer professional, you have just been contracted by a school to help them solve the problem they are facing in computing student's results. The school currently runs on manual system. Time and accuracy of the result are the major concerns.    What would you advise the school to do?", "images": [], "options": {"A": "Automate the system", "B": "Close down the school", "C": "Increase the number of staff", "D": "Buy more calculators for the staff"}, "answer": "A", "explanation": "The best solution to the problem of time and accuracy in computing student's results is to automate the system. Automation involves the use of computers and software applications to manage and control different processes. In this case, a software application can be developed to compute the student's results. This will not only save time but also increase the accuracy of the results.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>43", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING", "question": "Use the information below to answer this question  As a computer professional, you have just been contracted by a school to help them solve the problem they are facing in computing student's results. The school currently runs on manual system. Time and accuracy of the result are the major concerns.  If you are given the contract, what would be your first step of action?", "images": [], "options": {"A": "Analyse the result", "B": "Design a software", "C": "Investigate the problem", "D": "Maintain the staff"}, "answer": "C", "explanation": "The first step in solving any problem is to investigate it. This involves understanding the problem, its causes, and effects. In this case, the problem is time and accuracy in computing student's results. Therefore, the first step would be to investigate the current manual system to understand why it is slow and prone to errors. This will help in coming up with a suitable solution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>44", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "Which of the following charts does not display the X and Y axes?", "images": [], "options": {"A": "Bar chart", "B": "Bubble chart", "C": "Doughnut chart", "D": "X, Y graph"}, "answer": "C", "explanation": "A doughnut chart does not display the X and Y axes. A doughnut chart is a circular chart with a hole in the center, and it is used to represent data in the form of percentages or proportions. The data is represented in the form of sectors, where each sector represents a proportion of the total. Unlike bar, bubble, and X, Y graphs, a doughnut chart does not have X and Y axes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>45", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The uses of spreadsheet packages include:  I - Preparing organisation's logo  II - Performing sensitivity analysis  III - Preparing reports for senior management  IV - Preparation of profit forecasts.  Which of the following options is true?", "images": [], "options": {"A": "II and IV only", "B": "III and IV only", "C": "I, II and III only", "D": "II, III and IV only"}, "answer": "D", "explanation": "A spreadsheet package is a software application that allows users to manipulate, analyze and visualize data. It is not used for preparing an organization's logo (option I). However, it is used for performing sensitivity analysis (option II), preparing reports for senior management (option III), and preparation of profit forecasts (option IV). Therefore, the correct answer is 'II, III and IV only'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>46", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The common features of formula and function in spreadsheet are:  I. Entry is preceded by = or + symbol  II. They have fixed formats   III. They operate with cell addresses   IV. Their results are displayed.  Which of the following options is/are true?", "images": [], "options": {"A": "I, II and III only", "B": "I, III and IV only", "C": "II, III and IV only", "D": "I, II, III and IV"}, "answer": "B", "explanation": "In a spreadsheet, both formulas and functions are preceded by an = or + symbol (option I), they operate with cell addresses (option III), and their results are displayed (option IV). However, they do not have fixed formats (option II). Formulas can be written in any way as long as they follow the syntax rules of the spreadsheet program. Functions, on the other hand, do have a fixed format, but this only applies to functions and not formulas. Therefore, the correct answer is 'I, III and IV only'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>47", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "One megabyte is equivalent to", "images": [], "options": {"A": "1000 × 1024 bytes", "B": "1024 × 1024 bytes", "C": "1024 × 1048 bytes", "D": "1000 × 1000 × 1000 bytes"}, "answer": "B", "explanation": "In digital storage, one megabyte is equivalent to 1024 × 1024 bytes. This is because the binary system, which is used in digital storage, operates in powers of 2. Therefore, one kilobyte is 1024 bytes, and one megabyte is 1024 kilobytes, which is 1024 × 1024 bytes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>48", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Arrange the following spreadsheet window parts in a hierarchical order by size.  I. Worksheet  II. Cell  III. Workbook  IV. Range", "images": [], "options": {"A": "III, I, IV and II", "B": "II, IV, I and III", "C": "II, III, IV and I", "D": "IV, I, III and II"}, "answer": "A", "explanation": "In a spreadsheet, the hierarchy from largest to smallest is Workbook > Worksheet > Range > Cell. A workbook can contain multiple worksheets. Each worksheet is made up of ranges (a group of cells) and individual cells are the smallest unit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2018>49", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The statement in QBASIC that is used to add data at the end of existing sequential file is", "images": [], "options": {"A": "APPEND", "B": "CLOSE", "C": "INPUT", "D": "OUTPUT"}, "answer": "A", "explanation": "In QBASIC, the APPEND statement is used to add data at the end of an existing sequential file. CLOSE is used to close a file, INPUT is used to read data from a file, and OUTPUT is used to write data to a file.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2018>50", "subject": "Computer Studies", "year": "2018", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the following computer files can be used for updating the master file?", "images": [], "options": {"A": "Date", "B": "Program", "C": "Reference", "D": "Transaction"}, "answer": "D", "explanation": "A transaction file is used to update the master file. The master file is a permanent file in a system that is updated periodically, typically by a transaction file. A transaction file is a temporary file and contains the data necessary to update the master file.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>1", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING", "question": "The personnel who deals with the computer and its management is called", "images": [], "options": {"A": "Software", "B": "Liveware", "C": "Hardware", "D": "Firmware"}, "answer": "B", "explanation": "Liveware is the programmers, systems analysis operating staff, and other personnel working in a computer system. It is a slang used to denote people using computers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>2", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The map of Nigeria is an example of", "images": [], "options": {"A": "alphabetic data", "B": "audio data", "C": "biometric data", "D": "graphic data"}, "answer": "D", "explanation": "The map of Nigeria is an example of 'graphic data'. Graphic data refers to the use of geometric and graphical representations of information. 'Alphabetic data' refers to data that consists of letters, 'audio data' refers to sound, music, or any other type of audio signal, and 'biometric data' refers to data about a person's physical or behavioral characteristics.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>3", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The hexadecimal number 13, expressed as a binary number is", "images": [], "options": {"A": "00010011", "B": "00101100", "C": "00010110", "D": "00100100"}, "answer": "A", "explanation": "1316 = 1 x 161 + 3 x 160  = 1 x 16 + 3 x 1  = 16 + 3  = 1910    21929 rem 1 ↑24 rem 1 ↑22 rem 0 ↑21 rem 0 ↑0 rem 1 ↑  1316 = 100112", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>4", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Which of the following statements are true about computer?  I. It is constructed from electronic components.  II. It has self regeneration capability.  III. It has facility for storage of data and programs.  IV. It has provision for input and output of data.", "images": [], "options": {"A": "I, II and III only", "B": "I, II and IV only", "C": "I, III and IV only", "D": "II, III and IV only"}, "answer": "C", "explanation": "Computer has the following features, it is constructed from electronic components, it has self generating capability and it has facility for storage of data and programs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>5", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Computers are classified using the following criteria except", "images": [], "options": {"A": "cost and portability", "B": "data representation and purpose", "C": "size and speed", "D": "speed and storage"}, "answer": "A", "explanation": "Computers are classified using the following criteria except cost and portability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>6", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The Slide Rule is accurate to", "images": [], "options": {"A": "1 - 2 decimal places.", "B": "3 - 4 decimal places.", "C": "5 decimal places.", "D": "6 decimal places."}, "answer": "B", "explanation": "This is because the Slide Rule uses logarithms to perform calculations, and logarithms are accurate to a few decimal places. The accuracy of the Slide Rule also depends on the quality of the Slide Rule and the skill of the user.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>7", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : HISTORY OF COMPUTERS", "question": "Modern computers compared to earlier computers are", "images": [], "options": {"A": "faster and larger.", "B": "faster and smaller.", "C": "larger and stronger.", "D": "less reliable."}, "answer": "B", "explanation": "Modern computers are faster and smaller compared to earlier computers. This is due to advancements in technology that have allowed for the miniaturization of components while increasing processing power. The concept of Moore's Law, which states that the number of transistors on a microchip doubles approximately every two years, has largely driven this trend.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>8", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "An input device that converts an image into text is known as", "images": [], "options": {"A": "Optical Character Reader.", "B": "Optical Code Reader.", "C": "Optical Display Reader.", "D": "Optical Mark Reader."}, "answer": "A", "explanation": "An Optical Character Reader (OCR) is an input device that converts an image into text. It does this by recognizing the shapes of characters in an image and converting them into text that can be edited and read by a computer. This technology is commonly used in data entry, document management, and accessibility applications.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>9", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The type of printer which works on the same principle as a photocopier is", "images": [], "options": {"A": "Dot Matrix Printer.", "B": "Ink Jet Printer.", "C": "Laser Jet Printer.", "D": "Thermal Printer."}, "answer": "C", "explanation": "A Laser Jet Printer works on the same principle as a photocopier. Both use a process called xerography, which involves using static electricity to transfer toner (a type of ink powder) onto paper. The toner is then fused onto the paper with heat to create a permanent image or text.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>10", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The output of a NAND gate is 1 when", "images": [], "options": {"A": "all inputs are 0.", "B": "all inputs are 1.", "C": "any of the input is 0.", "D": "any of the input is 1."}, "answer": "A", "explanation": "A NAND gate is an inverted AND gate. In an AND gate, the output is 1 only when all inputs are 1. Therefore, in a NAND gate, the output is 0 only when all inputs are 1, and 1 in all other cases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>11", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A company known as CIBITO has the following memory modules in four of its computers as shown in Table 1.  Use the information in Table 1 to answer this question  Memory ModuleMemory TypeNumber of PinsP  Q  R  SSIMM  SIMM  SO DIMM  DIMM30  72  72  168    Which of the memory modules is appropriate for a notebook computer?", "images": [], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "A", "explanation": "Memory module P is appropriate for note book computer because it has the smallest PINS. Notebook computer has small PINS.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>12", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A company known as CIBITO has the following memory modules in four of its computers as shown in Table 1.  Use the information in Table 1 to answer this question  Memory ModuleMemory TypeNumber of PinsP  Q  R  SSIMM  SIMM  SO DIMM  DIMM30  72  72  168  The memory module with the smallest physical size is", "images": [], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "A", "explanation": "The physical size of a memory module is typically related to the number of pins it has. The fewer the pins, the smaller the physical size.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>13", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A company known as CIBITO has the following memory modules in four of its computers as shown in Table 1.  Use the information in Table 1 to answer this question  Memory ModuleMemory TypeNumber of PinsP  Q  R  SSIMM  SIMM  SO DIMM  DIMM30  72  72  168  Identify the memory module with the largest physical size.", "images": [], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "D", "explanation": "The memory module with the largest physical size is usually the one with the most number of pins. In this case, memory module S has the most number of pins (168), hence it is the largest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>14", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The scanner and the floppy disk are", "images": [], "options": {"A": "both input devices.", "B": "both output devices.", "C": "input and output devices respectively.", "D": "input and storage devices respectively."}, "answer": "D", "explanation": "A scanner is an input device because it captures images or text from physical sources and converts them into digital format that the computer can understand and use. A floppy disk, on the other hand, is a storage device because it is used to store data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>15", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The set of instructions written by computer experts to solve specific task of the user is called", "images": [], "options": {"A": "operating system.", "B": "application software.", "C": "system software.", "D": "utility software."}, "answer": "B", "explanation": "Application software is software designed to perform a group of coordinated functions, tasks or activities for the benefit of the user.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>16", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A collection of software that allows the computer to operate is called", "images": [], "options": {"A": "general-purpose software.", "B": "utility software.", "C": "operating system.", "D": "specific software."}, "answer": "C", "explanation": "Operating system is a collection of software that allows the computer to operate. It is a system software that manages computer hardware, software resources and provides common services for computer programs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>17", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "A suite of software that controls and manages the basic operation of a computer is", "images": [], "options": {"A": "application software.", "B": "management system.", "C": "software package.", "D": "system software."}, "answer": "D", "explanation": "System software is a type of computer program that is designed to run a computer's hardware and application programs. It includes the operating system, device drivers, diagnostic tools, servers, windowing systems, utilities, and more. It is responsible for controlling, integrating, and managing the individual hardware components of a computer system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>18", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The Windows PC and the Apple Macintosh are examples of two different", "images": [], "options": {"A": "input devices.", "B": "platforms.", "C": "programs.", "D": "storage devices."}, "answer": "B", "explanation": "The Windows PC and the Apple Macintosh are examples of two different platforms. In computing, a platform refers to the environment in which a piece of software is executed. It might be the hardware or the operating system (OS), even a web browser and associated application programming interfaces, or other underlying software, as long as the program code is executed with it.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>19", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Machine Language instructions are expressed in", "images": [], "options": {"A": "binary.", "B": "decimal.", "C": "hexadecimal.", "D": "octal."}, "answer": "A", "explanation": "Machine language instructions are expressed in binary. It is a set of instructions executed directly by a computer's central processing unit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>20", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The following symbols are used in flowcharting except the", "images": [], "options": {"A": "terminal symbol.", "B": "process symbol.", "C": "input/output symbol.", "D": "close symbol."}, "answer": "D", "explanation": "Close symbol is not used in flowcharting terminal, process and input/output symbols are used in flowcharting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>21", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Three major types of language translators are", "images": [], "options": {"A": "assembler, compiler and editor.", "B": "assembler, compiler and interpreter.", "C": "compiler, debugger and editor.", "D": "debugger, assembler and interpreter."}, "answer": "B", "explanation": "The three major types of language translators in computing are the assembler, compiler, and interpreter. An assembler translates assembly language into machine code. A compiler translates high-level language into machine code in one go, creating an executable file. An interpreter translates high-level language into machine code line by line, executing each line as it goes. Therefore, the correct answer is 'assembler, compiler and interpreter'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>22", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Translate 2m2 + 3n - 9 as a BASIC arithmetic expression.", "images": [], "options": {"A": "2 * m * 2 + 3 * n - 9", "B": "2 * m ∧2 + 3 * n - 9", "C": "2 * 2 * m + 3 * n - 9", "D": "2 * m * m * n + 3 - 9"}, "answer": "B", "explanation": "2m2 + 3n - 9 is translate as basic arithmetic expression as 2 * m ∧2 + 3 * n - 9  * → multiplication  ∧→ power, division → \\", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>23", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The term compiler in computer programming refers to a", "images": [], "options": {"A": "key punch operator of the computer.", "B": "person who compiles source programs.", "C": "person who writes the computer programming codes.", "D": "program which translates source program into object program."}, "answer": "D", "explanation": "Complex in computer programming refers to a program which translate source program into object program.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>24", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The IF . . . THEN statement in BASIC programming is", "images": [], "options": {"A": "a transfer of control.", "B": "used to redirect a statement.", "C": "used to eliminate the need for prompting each INPUT statement.", "D": "a conditional branch statement."}, "answer": "D", "explanation": "The IF...THEN statement in BASIC programming is a conditional branch statement. It allows the program to execute a certain section of code only if a particular test condition is true. If the condition is false, the program skips the section of code.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>25", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Flexibility of a good program means", "images": [], "options": {"A": "handling of any change(s) without having to rewrite the entire program.", "B": "the length of processing time and memory to process the instruction.", "C": "the program has to be broken down into a number of sub-tasks.", "D": "the program should work for two similar tasks in the same domain."}, "answer": "A", "explanation": "Flexibility of a good program means handling of any change(s) without having to rewrite the entire program.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>26", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Fibre Optic cable transmits signal in the form of", "images": [], "options": {"A": "sound.", "B": "electricity.", "C": "light.", "D": "microwave."}, "answer": "C", "explanation": "Fibre Optic cables transmit signals in the form of light. This is because they are made up of one or more optical fibers, which are used to carry light. The optical fiber elements are typically individually coated with plastic layers and contained in a protective tube suitable for the environment where the cable will be deployed. This matches with option 3.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>27", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Data transfer can be initiated through the following media except", "images": [], "options": {"A": "coaxial cable.", "B": "fibre optics.", "C": "trunking pipe.", "D": "twisted pair cable."}, "answer": "C", "explanation": "Coaxial cable, fibre optics, and twisted pair cable are all standard media used for data transfer in networking and telecommunications.    Trunking pipe is not a data transfer medium. It is a protective conduit used to route and organize cables (such as electrical wires or networking cables) but does not itself transmit data.    Thus, data transfer cannot be initiated through a trunking pipe.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>28", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "The topology represented in Figure 1 is", "images": ["Computer Studies/imgs/2019/img1.png"], "options": {"A": "bus topology.", "B": "mesh topology.", "C": "ring topology.", "D": "star topology."}, "answer": "A", "explanation": "The Topology represented in the diagram above is Bus topology.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>29", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "To send a created MS Powerpoint document using email to a user, the document can be added as", "images": [], "options": {"A": "Attachment.", "B": "Draft.", "C": "Reply.", "D": "Chat."}, "answer": "A", "explanation": "To send a created MS Powerpoint document using email to a user, the document can be added as Attachment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>30", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "What type of network is represented in Figure 2?", "images": ["Computer Studies/imgs/2019/img2.png"], "options": {"A": "Local Area Network", "B": "Metropolitan Area Network", "C": "Personal Area Network", "D": "Wide Area Network"}, "answer": "B", "explanation": "The type of network that is represented in the diagram above is Metropolitan Area Network.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>31", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "The major advantage of free software is that it is", "images": [], "options": {"A": "free and contains unlimited components.", "B": "licensed and available always.", "C": "licensed and can be copied by anyone.", "D": "superior in quality but not robust."}, "answer": "C", "explanation": "Free software, also known as open-source software, is a type of software that is licensed in a way that allows anyone to freely use, study, modify, and distribute the software. The major advantage of free software is that it is licensed and can be copied by anyone.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>32", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "In MS Excel, the cell that contains the pointer or cursor is called", "images": [], "options": {"A": "active cell.", "B": "current cell.", "C": "default cell.", "D": "passive cell."}, "answer": "A", "explanation": "Active cell is an alternatively referred to as cell pointer, current cell or selected cell, of microsoft excel the active cell has a bold black box around the cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>33", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "One major difference between paper spreadsheet and electronic spreadsheet is", "images": [], "options": {"A": "arrangement of columns.", "B": "headings formatting.", "C": "arrangement of rows.", "D": "speed of processing."}, "answer": "D", "explanation": "A paper spreadsheet is a ledger book with many sheets of paper divided into columns and rows in manual manner while electronic spreadsheet is an automated electronic spreadsheet that has the same of rows and columns but automatically recalculate every time you change any value. Speed of processing is the major difference.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>34", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "To hold row and column titles in places so that they do not scroll when the user scrolls a worksheet, click the", "images": [], "options": {"A": "freeze panes command on the windows menu.", "B": "hold titles command on the edit menu.", "C": "split command on the windows menu.", "D": "show grid command on the windows menu."}, "answer": "A", "explanation": "In Excel, to hold row and column titles in places so that they do not scroll when the user scrolls a worksheet, you would use the 'Freeze Panes' command on the windows menu. This allows the user to keep a portion of the sheet visible while the rest of the sheet scrolls.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>35", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "In Microsoft PowerPoint, two kinds of sound effect files that can be added to a presentation are", "images": [], "options": {"A": ".wav files and .mid files.", "B": ".wav files and .gif files.", "C": ".wav files and .jpg files.", "D": ".jpg files and .gif files."}, "answer": "A", "explanation": "In Microsoft PowerPoint, you can add sound effects to your presentation. The types of sound effect files that can be added are .wav files and .mid files. .wav files are audio files that contain audio data, while .mid files are MIDI (Musical Instrument Digital Interface) files that contain music data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>36", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "A cell with a red triangle in the top-right corner in a spreadsheet application signifies", "images": [], "options": {"A": "an error in the cell.", "B": "a comment associated with the cell.", "C": "that the font colour for text in the cell is red.", "D": "that a formula cannot be entered into the cell."}, "answer": "B", "explanation": "In spreadsheet applications like Microsoft Excel, a cell with a red triangle in the top-right corner signifies a comment associated with the cell. This feature is used to add notes or reminders about the data in the cell. It does not signify an error, a font color, or a restriction on entering formulas.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>37", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Spreadsheet packages can be used for", "images": [], "options": {"A": "database and painting.", "B": "drawing and painting.", "C": "budgeting and inventory.", "D": "word processing and drawing."}, "answer": "C", "explanation": "Spreadsheet packages like Microsoft Excel or Google Sheets are primarily used for tasks that involve numerical data, such as budgeting and inventory management. They are not typically used for database management, painting, drawing, or word processing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>38", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET~~TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Which of the following is true when data maintained in MS Excel workbook is linked to a word document? The Word document", "images": [], "options": {"A": "cannot be edited.", "B": "must contain a hyperlink.", "C": "contains a copy of the actual data.", "D": "contains a reference to the original source application."}, "answer": "D", "explanation": "When data from an MS Excel workbook is linked to a Word document, the Word document contains a reference to the original source application, not a copy of the actual data. This means that if the data in the Excel workbook is updated, the changes will also be reflected in the Word document. The Word document can still be edited and does not necessarily need to contain a hyperlink.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>39", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Data that is copied from an application is stored in the", "images": [], "options": {"A": "clipboard.", "B": "driver.", "C": "prompt.", "D": "terminal."}, "answer": "A", "explanation": "When you copy data from an application, it is stored in the clipboard. The clipboard is a feature of many operating systems that allows short-term, transitory storage and transfer within and between application programs. The clipboard is usually temporary and unnamed, and its contents reside in the computer's RAM.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>40", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "After several 'save' and 'delete' operations, there remain many scattered areas of data too small to be used productively. This describes", "images": [], "options": {"A": "utilization.", "B": "protection.", "C": "fragmentation.", "D": "backing up."}, "answer": "C", "explanation": "Fragmentation is a condition in which there are many scattered areas of storage in a data base that are too small to used productively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>41", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The disk operating system will label three hard drives as", "images": [], "options": {"A": "A, B and C.", "B": "C, D and E.", "C": "B, C and D.", "D": "F, G and H."}, "answer": "B", "explanation": "In a disk operating system, the hard drives are labeled starting from C. The A and B labels are reserved for floppy drives or other removable media. So, three hard drives would be labeled as C, D, and E.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>42", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Which of the options labelled I to IV give the two stages involved in booting?  I. Power On Self Test  II. Loading of Operating System  III. Loading of email  IV. Power On Safe Mode", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and IV only", "D": "III and IV only"}, "answer": "A", "explanation": "Booting is a process that starts operating systems when the user turns on a computer system. It involves two main stages: the Power-On Self-Test (POST) and the Loading of Operating System. POST is a diagnostic testing sequence run by a computer's BIOS as the computer's power is initially turned on. If the POST is successful, the system BIOS will then load the Operating System into the computer's memory.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>43", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A bit as used in computing in digital communication is", "images": [], "options": {"A": "a decimal digit.", "B": "an octal digit.", "C": "a binary digit.", "D": "a hexadecimal digit."}, "answer": "C", "explanation": "In computing and digital communication, a bit is the most basic unit of information. It is a binary digit, the smallest increment of data on a machine. A bit can hold only one of two values: 0 or 1, because the systems are designed to store data in binary format.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>44", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Multiply 1012 by 112", "images": [], "options": {"A": "10012", "B": "10112", "C": "11102", "D": "11112"}, "answer": "D", "explanation": "Therefore, 1012 &#215; 112 = 11112", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>45", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "In BCD encoding system, 2510 will be represented as", "images": [], "options": {"A": "01100101", "B": "01010110", "C": "100101", "D": "01010010"}, "answer": "C", "explanation": "2510 = (?) BCD    2 ⊣ 0010  5 ⊣ 0101    2510 = (100101)BCD", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>46", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "The following actions are sources of security breaches in computing except", "images": [], "options": {"A": "carelessness", "B": "hackers' threat", "C": "piracy", "D": "viruses"}, "answer": "C", "explanation": "The actions are sources of security branches in computing include carelessness, hacker's threat and viruses but piracy is not sources of security breaches in computing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>47", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Effects of file insecurity include the following except", "images": [], "options": {"A": "virus infection", "B": "file corruption", "C": "encrypted data", "D": "data loss"}, "answer": "C", "explanation": "encrypted data is not effect of file insecurity virus infection, file corruption and data loss are effects of file insecurity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>48", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the file organization methods can be accessed both randomly and sequentially?", "images": [], "options": {"A": "Direct files", "B": "Indexed sequential files", "C": "Random files", "D": "Sequential files"}, "answer": "B", "explanation": "Indexed sequential files is the file organisation methods that can be accessed both randomly and sequently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2019>49", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "A computer program that gathers information about a person or organization without their knowledge or consent is known as", "images": [], "options": {"A": "Adware", "B": "Time Bomb", "C": "Malware", "D": "Spyware"}, "answer": "D", "explanation": "Spyware is a computer program that gathers information about a person or organisation without their knowledge or consent.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2019>50", "subject": "Computer Studies", "year": "2019", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Password reset disk should be created", "images": [], "options": {"A": "every time the user changes password.", "B": "once only.", "C": "only when the user forgets the password.", "D": "twice only."}, "answer": "A", "explanation": "A password reset disk should be created every time the user changes password. This is because the password reset disk contains a file that stores the current password. If the password is changed and the disk is not updated, it will still contain the old password, making it useless for password recovery.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>1", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Which of the following is not a step involved in data conversion?", "images": [], "options": {"A": "Input", "B": "Output", "C": "Process", "D": "Transfer"}, "answer": "D", "explanation": "The  steps involved in how a computer converts data to required information are input - process - output.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>2", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The communication of knowledge, concepts and ideas is referred to as", "images": [], "options": {"A": "information processing", "B": "information transmission", "C": "telecasting", "D": "webcasting"}, "answer": "B", "explanation": "information transmission is the acquisition, recording, organization, retrieval, display, and dissemination of information.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>3", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The equivalent of the decimal number 89 in base 4 is", "images": [], "options": {"A": "1021", "B": "1201", "C": "1211", "D": "1121"}, "answer": "D", "explanation": "89 to base 4                             4 89                           4 22 R  1                           4  5  R  2                           4  1  R  1                           4  0  R  1     Therefore, 89 to base 4 = 1121", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>4", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Choose the incorrect statement about microcomputers", "images": [], "options": {"A": "A microcomputer can be placed on a single silicon chip", "B": "a microcomputer can have more processing capability than a mainframe model", "C": "ROM chips may be used in micros to permanently store program instruction", "D": "Most micros use rigid disk storage devices rather than floppy disk drivers"}, "answer": "B", "explanation": "Micro computer is widely used and the fastest growing computers. Designed for general usage like entertainment, education and work purposes. Examples are desktop computers, gaming consoles, sound and navigation system of a car, notebooks, notebooks, PDA's, tablet pc's, smart phones, calculators, laptops.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>5", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Under classification by data representation,computers can be", "images": [], "options": {"A": "analogue, digital and hybrid", "B": "hybrid, mainframes and analogue", "C": "mini-computers, digital and supercomputers", "D": "supercomputers and mini-computers"}, "answer": "A", "explanation": "Computers can be classified by data representation into analogue, digital and hybrid. Analogue computers represent data as physical quantities and operate on the data by manipulating the quantities. Digital computers represent data as digits and operate on the data using mathematical and logical operations. Hybrid computers combine the features of both analogue and digital computers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>6", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Pascal's calculating machine was useful in", "images": [], "options": {"A": "addition and subtraction only", "B": "division only", "C": "Arithmetic", "D": "multiplication only"}, "answer": "C", "explanation": "Pascal's calculator also known as the arithmetic machine or pascaline, it is a mechanical calculator invented by  Blaise Pascal in the mid 17th century. He designed the machine to add and subtract two numbers directly and to perform multiplication and division through repeated addition or subtraction.  Pascal's calculator Calculation supported  Multiplication  Division  Addition  Subtraction", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>7", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Arrange the following inventions in chronological order    I. Slide Rule  II. Pascaline  III. Analytical Engine  IV. Difference Engine", "images": [], "options": {"A": "I, II, IV and III", "B": "I, IV, III and II", "C": "III, IV, II and I", "D": "I, II, III and IV"}, "answer": "A", "explanation": "Components and uses of early computing devices are:  Abacus,  Slide Rule, Napier's bone, Pascal's calculator, Leibnitz multiplier, Jacquad loom, Charles Babbage's Analytical Engine, Difference Engine, Hollerith Census machine, Burrough's Machine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>8", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Handwritten letters, typeset documents or printout characters can be read into the computer by", "images": [], "options": {"A": "Barcode Reader", "B": "Magnetic Ink Character Recognition", "C": "Optical Character Recognition", "D": "Optical mark Reader"}, "answer": "C", "explanation": "Optical Character Recognition or optical character reader is the electronic or mechanical conversion of images of typed, handwritten or printed text into machine-encoded text, whether from a scanned document, a photo of a document, a scene-photo or from subtitle text superimposed on an image.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>9", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Which of the following logic operation would select a record when at least one condition is satisfied?", "images": [], "options": {"A": "AND", "B": "NOR", "C": "NOT", "D": "OR"}, "answer": "D", "explanation": "In logic operations, the OR operation returns true if at least one of the conditions is true. Here is a brief explanation of the other options for clarity:    AND: This operation returns true only if all the conditions are true.  NOR: This is the negation of the OR operation. It returns true only if all conditions are false.  NOT: This operation negates the condition, returning true if the condition is false and vice versa. It operates on a single condition rather than combining multiple conditions.  Therefore, the correct answer is OR.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2020>10", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "In Figure 1, the value of Z when X = 1 and Y = 0 is", "images": ["Computer Studies/imgs/2020/2020computerssceq10.png"], "options": {"A": "0", "B": "1", "C": "10", "D": "11"}, "answer": "B", "explanation": "In Figure 1, we examine the output value of Z when the inputs are X = 1 and Y = 0.    Starting with these inputs:    X = 1  Y = 0  We calculate the product of X and Y:    XY = 1⋅0 = 0    Since this is a NAND gate, we take the NOT of the result:    NAND output = NOT(0) = 1    Therefore, when X = 1 and Y = 0, the value of Z is 1.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>11", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A data bus that is capable of transferring 8 bytes of data at once can be rated as", "images": [], "options": {"A": "a 16-bit data bus", "B": "a 32-bit data bus", "C": "a 64-bit data bus", "D": "ab 8-bit data bus"}, "answer": "C", "explanation": "A byte is eight bits, a word is 2 bytes(16 bits), a doubleword is 4 bytes(32 bits), and a quadword is 8 bytes(64 bits).", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>12", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following memory types are nonvolatile?    I.   PROM  II.  SRAM  III. EEPROM  IV. DRAM", "images": [], "options": {"A": "I and III only", "B": "I and IV only", "C": "II and III only", "D": "III and IV only"}, "answer": "A", "explanation": "Non voliatile memory are type of computer memory that can retrive stored information even after having been power cycled. Examples of non-volitaile memory include flash memory, read-only memory(ROM),EPROM,EEPROM, PROM etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>13", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A company known as CIBITO has the following memory modules in four of its computers as shown in Table 1.                                                                                 Table 1  Memory ModuleMemory TypeNumber of PinsPSIMM30QSIMM72RSO DIMM72SDIMM168    Which memory module will be appropriate for graphic design?", "images": [], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "D", "explanation": "For graphic design, a computer needs a high-performance memory module. Among the given options, DIMM (Dual In-line Memory Module) with 168 pins (option S) is the most appropriate. DIMM is a type of memory module that contains circuitry to provide data to the computer. The number of pins in a DIMM can vary, but the higher the number, the more data the module can handle at once, making it faster and more efficient for tasks like graphic design.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2020>14", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "One attribute of the Read Only Memory is that it", "images": [], "options": {"A": "can be modified", "B": "is volatile", "C": "stores the BIOS", "D": "stores the POST"}, "answer": "C", "explanation": "The characteristics of read only memory are:  - non-volatile, that is it remains there even withour electrical power  - it can store data for a long period of time  - data can be retrived which is good for security purpose  - stores the basic input/output system", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>15", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The operation of a computer and peripherals attached to it is controlled by", "images": [], "options": {"A": "application software", "B": "hardware", "C": "liveware", "D": "system software"}, "answer": "D", "explanation": "The operation of a computer and peripherals attached to it is controlled by the system software. System software is a type of computer program that is designed to run a computer's hardware and application programs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>16", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Antivirus software is an example of", "images": [], "options": {"A": "application software", "B": "operating software", "C": "system software", "D": "utility software"}, "answer": "D", "explanation": "utility software is software designed to help to analyze, configure, optimize or maintain a computer. Examples of utility programs are antiviirus software, backup software, Editor and disk tools.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>17", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following devices will not require the use of system software to operate?", "images": [], "options": {"A": "Analogue camera", "B": "MICR", "C": "Mobile phones", "D": "OCR"}, "answer": "A", "explanation": "Devices like desktops and laptops, enterprise-class server computers, optical character recognition mobile phone requires system software to operate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>18", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Which of the following application packages is most suitable for database management?", "images": [], "options": {"A": "Photoshop", "B": "MS Publisher", "C": "Macromedia Flash", "D": "Fox Pro"}, "answer": "D", "explanation": "Fox pro is a text-based procedurally oriented programming language and database management system(DBMS), and it is also an object-oriented programming language, orginally published by fox software and later by microsoft, for Ms-dos, windows, Macintosh and Unix.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>19", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Files that contain machine language instructions are called", "images": [], "options": {"A": "interpreter files", "B": "executable files", "C": "batch files", "D": "source files"}, "answer": "B", "explanation": "Executable files contain machine language instructions that can be directly executed by the computer's CPU. Interpreter files are used to interpret high-level language into machine language, batch files are used to automate tasks in DOS, Windows, and Unix, and source files contain the source code of a program.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>20", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The following are types of errors in programming except", "images": [], "options": {"A": "grammar error", "B": "syntax error", "C": "logic error", "D": "arithmetic error"}, "answer": "A", "explanation": "Types of errors in programming are: syntax errors, logic errors, compilation errors, runtime errors, arithmetic errors, resource errors, interface errors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>21", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The stages of software development do not include", "images": [], "options": {"A": "analysis", "B": "conversion", "C": "design", "D": "maintenance"}, "answer": "B", "explanation": "The stages of software development include requirements gathering, analysis, design, coding, testing, and maintenance. Conversion is not a stage in software development. It is a process that involves changing one form of data to another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>22", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Express  P( 1 + R/100)N  as a BASIC programming notation.", "images": [], "options": {"A": "P  x (1 + R + 100) N", "B": "P * (1 + R/100)^N", "C": "P x (1 + R &#247;  100) ^ N", "D": "P  * (1 + R &#247;  100) * N"}, "answer": "B", "explanation": "The BASIC programming notation for the expression P( 1 + R/100)N is P * (1 + R/100)N. This is because in BASIC programming, the multiplication operator is represented by *, division by /, and exponentiation by ^.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2020>23", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "An algorithm can be described as", "images": [], "options": {"A": "the ouput of the instruction to computer", "B": "the required data to be processed", "C": "problem definition", "D": "a sequence of instruction for solving a problem"}, "answer": "D", "explanation": "An algorithm is a set of instructions designed to perform a specific task. In computer programming, algorithms are often created as functions.These serve functions serve as small programs that can be referenced by a larger program.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>24", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The major difference between low level programming language and high level programming language is that", "images": [], "options": {"A": "low level languages need an interpreter while high level languages need a compiler", "B": "high level languages will not need a translator but low level languages do", "C": "low level languages need a assembler while high level languages need an interpreter", "D": "low level languages do not need translators while high level languages do"}, "answer": "C", "explanation": "Low-level languages are closer to the hardware level and are typically written in a manner that reflects the computer architecture. They require a assembler to translate the low-level code to machine code that the computer can understand. High-level languages, on the other hand, are closer to human language and are easier to write and understand. They require an interpreter to translate the high-level code to machine code.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>25", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "What will the following BASIC statement produce?     *PRINT  \"Afrikom Computer School\"", "images": [], "options": {"A": "A blank on-screen message", "B": "An error indicating on the screen", "C": "Afrikom Computer School dispalyed on the screen", "D": "Afrikom Computer School printed on paper"}, "answer": "C", "explanation": "The BASIC statement 'PRINT \"Afrikom Computer School\"' will output the text 'Afrikom Computer School' to the screen. The PRINT command in BASIC is used to output or display text or variables on the screen.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>26", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "A rectangular image consisting of black lines and white spaces representing data which can be optically read is called", "images": [], "options": {"A": "barcode", "B": "decorder", "C": "mnemonics", "D": "pseudocode"}, "answer": "A", "explanation": "Barcode is a printed series of parallel bars or lines of varying width that is used for entering data into a computer system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>27", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "The following are types of data network except", "images": [], "options": {"A": "MAC", "B": "MAN", "C": "PAN", "D": "WAN"}, "answer": "A", "explanation": "MAC stands for Media Access Control, which is a unique identifier assigned to a network interface for communications at the data link layer of a network segment. It is not a type of data network. MAN, PAN, and WAN are types of networks, standing for Metropolitan Area Network, Personal Area Network, and Wide Area Network respectively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>28", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "The minimum number of computers that can constitute a network is", "images": [], "options": {"A": "thirty", "B": "twenty", "C": "ten", "D": "two"}, "answer": "D", "explanation": "A network consists of two or more computers that are linked in order to share resources(such as printers and CDs), exchange files, or allow electronic communications.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>29", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "If a computer user wants to access the national database from a remote location, the user will require a", "images": [], "options": {"A": "modem, telephone line and decoder", "B": "teleprinter, telephone line and facsimile", "C": "communication software, telephone line and decoder", "D": "modem,  communication software and telephone line"}, "answer": "D", "explanation": "To access a national database from a remote location, a user would require a modem, communication software, and a telephone line. The modem is used to modulate and demodulate signals for transmission and reception. The communication software is used to manage the sending and receiving of data, and the telephone line is the medium over which the data is transmitted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>30", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Which type of network topology is represented in Figure 2?", "images": ["Computer Studies/imgs/2020/2020computerssceq29.png"], "options": {"A": "Hybrid topology", "B": "Mesh topology", "C": "Ring topology", "D": "Star topology"}, "answer": "D", "explanation": "In the star topology, all the computers connect with the help of a hub.This cable is called a central node, and all other nodes are connected using this central node. It is most popular on LAN network as they are inexpensive and easy to install.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>31", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "In networking, bandwidth means", "images": [], "options": {"A": "class of IP address used in the network", "B": "number of interconnected computers in the network", "C": "transmission capacity of a commuication channel", "D": "type of nodels in a communication channel"}, "answer": "C", "explanation": "Bandwidth is the maximum rate of data transfer across a given path. It is the maximum amount of data transmitted over an internet connection in  a given amount of time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>32", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "A predesigned document that already has coordinating fonts, a layout and a background is known as", "images": [], "options": {"A": "guide", "B": "model", "C": "ruler", "D": "template"}, "answer": "D", "explanation": "Template is a file that serves as a starting point for  a new document. It is also a file that is created with an overall layout to be used with one or more documents.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>33", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "The following are functions of database management system except", "images": [], "options": {"A": "backup and replication", "B": "format operation", "C": "rule enforcement", "D": "security of data"}, "answer": "B", "explanation": "The functions of database management system are:  - Data dictionary management  - Data storage management  - Data transformation and presentation  - Security Management  - Multi User Access Control  - Backup and Recovery Management  - Data integrity Management  - Database Access Lanaguage an Application programming interfaces.  - Database communication interfaces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>34", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "To make the entire slides in a presentation to have the same \"look\" in MS PowerPoint, a user should", "images": [], "options": {"A": "use the Slide layout option", "B": "use outline view", "C": "use a presentation design template", "D": "add a slide option"}, "answer": "C", "explanation": "To make the entire slides in a presentation to have the same \"look\" in MS PowerPoint, a user should use a presentation design template", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>35", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "In MS Excel, the average of 10 numbers given as B1, B2,........,B10 is", "images": [], "options": {"A": "=(B1 + B2 +.....+ B10)/10.", "B": "@SUM(B1:B10).", "C": "#SUM(B1:B10)/10.", "D": "=B1 + B2 +.....+ B10/10"}, "answer": "A", "explanation": "In MS Excel, the correct formula to calculate the average of 10 numbers given as B1, B2, ..., B10 is:    =(B1 + B2 +.....+ B10)/10.    However, this method is not the most efficient way to calculate the average. The more straightforward and commonly used formula for calculating the average in Excel is:    =AVERAGE(B1:B10)    But, given the provided options, =(B1 + B2 +.....+ B10)/10 is the correct choice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>36", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "To centre worksheet titles across a range of cells in MS Excel, the user must", "images": [], "options": {"A": "widen the rows to centre the titles across the range of cells", "B": "widen the columns to centre the titles across range of cells", "C": "select the cells containing the titles text and use the fill handle to centre te text across the range of cells", "D": "select any cell containing the tilte text and use the fill handle to centre the text across a range of cells"}, "answer": "C", "explanation": "To center worksheet titles across a range of cells in MS Excel, the user must select the cells containing the title text and use the fill handle to center the text across the range of cells.    The fill handle is a small black square that appears in the bottom right corner of a selected cell or range of cells. To use the fill handle to center the text across a range of cells, simply select the cells containing the title text and then drag the fill handle down the range of cells.    The text in the selected cells will be centered across the range of cells.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>37", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "In graphics, a subscripts text refers to a text that is positioned", "images": [], "options": {"A": "a little bit above a normal line of text", "B": "a little bit below a normal line of text", "C": "at the end of a line of text", "D": "at the front of a line of text"}, "answer": "B", "explanation": "Subcripts appears at or below the baseline i.e set slightly below the normal line of type,respectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>38", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "In database application, the field length determines the", "images": [], "options": {"A": "maximum number of characters the field can accomodate", "B": "maximum number of operations that can be performed on the field", "C": "level of security of the database", "D": "maximum number of datatype the field can contain"}, "answer": "A", "explanation": "In a database application, the field length determines the maximum number of characters that the field can accommodate. This is because the field length is a property that sets the maximum number of characters or the maximum amount of data that a particular field can hold.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>39", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Removing a program on a computer properly requires", "images": [], "options": {"A": "deleting", "B": "archiving", "C": "disabling", "D": "uninstalling"}, "answer": "D", "explanation": "In computing uninstall means to remove an application from a computer. Uninstalling removes all files that were added to the computer when the application was initially installed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>40", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A feature on the computer desktop that indicates the current active applications is called", "images": [], "options": {"A": "icon", "B": "menu bar", "C": "ribbon", "D": "task bar"}, "answer": "D", "explanation": "The taskbar is an element of an operating system located at the bottom of the screen. It allows you to locate and lunch programs through start and the start menu, or view any program that's currently open.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>41", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "In a Windows operation involving dragging and dropping an item on the desktop, the item will be", "images": [], "options": {"A": "deleted from the screen", "B": "duplicated", "C": "moved to a new location", "D": "renamed"}, "answer": "C", "explanation": "In computer graphical user interfaces, drag and drop is a pointing device gesture in which the user selects a virtual object by \"grabbing\" it and dragging it into a different location or onto another virtual object.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>42", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Digital signals can be represented by:    I.     Binary Codes  II.    0 and 1  III.   High and Low    Which of the following options is correct?", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III"}, "answer": "D", "explanation": "In most digital circuits, the signal can have two possible valid values; this is called a binary signal or logical signal. They are represented by two voltage bands: 1 is represented by having a positive voltage and 0 is represented by having no voltage or zero voltage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>43", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "A single hexadecimal digit is represented by", "images": [], "options": {"A": "one bit", "B": "two bits", "C": "four bits", "D": "eight bits"}, "answer": "C", "explanation": "Hexadecimal numerals are widely used by computer system designers and programmers because they provide a human-friendly representation of binary- coded values. Each hexadecimal digit represents four bits (binary digits), also known as nibble(or nybble), which is half a byte.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>44", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The decimal fractions 0.9375 converts to binary as", "images": [], "options": {"A": "0.0111", "B": "0.1011", "C": "0.1111", "D": "0.1001"}, "answer": "C", "explanation": "0.9375*2 = 1.875 = 1  0.875 *2 = 1.75=  1  0.75* 2 = 1.5 = 1  0.5 *2 = 1.0 = 1  From top to bottom 0.9375 = 0.1111", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>45", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The EBCDIC coding system was developed for use on", "images": [], "options": {"A": "IBM mainframe computers", "B": "HP mainframe and mini-computers", "C": "Dell mainframe computers", "D": "Apple mainframe computers"}, "answer": "A", "explanation": "Extended Binary coded Decimal interchange code is an eight-bit character encoding used mainly on IBM mainframe and IBM midrange computer operating systems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>46", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the following is not a criterion for classifying files?", "images": [], "options": {"A": "Nature of content", "B": "Organizational method", "C": "Storage medium", "D": "Types of data"}, "answer": "C", "explanation": "Three criteria used in file classification are: Nature of file content, Organizational method and type of data", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>47", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the following options best describes the arrangement of file structure?    I.  Files  II. Fields  III. Character  IV. Records", "images": [], "options": {"A": "III, II, I and IV", "B": "II, III, I and IV", "C": "III, II, IV and I", "D": "II, III, IV and I"}, "answer": "C", "explanation": "The arrangement of file structure are: Character, Fields, Records and Files.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>48", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the following statements best describes sequential file organization?", "images": [], "options": {"A": "Records are arranged in no particular order", "B": "Records are directly addressed to the key value", "C": "Records are sorted according to a key field", "D": "Records are used as index to acess the database"}, "answer": "C", "explanation": "Sequential file contains records organized by the order in which they were entered.The order of the records is fixed. Records in sequential files can be read or written only sequentially.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2020>49", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Viruses, worms and trojan horses are all", "images": [], "options": {"A": "application software", "B": "malicious software", "C": "robust software", "D": "system software"}, "answer": "B", "explanation": "Malicious software coin the word \"malware\" and the meaning remains the same. Malicious software refers to any malicious program that causes harm to a computer system or network. It attacks a computer or network in the form of viruses, worms, trojans,  spyware, adware or rootkits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2020>50", "subject": "Computer Studies", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "In order to avoid damages caused by security breaches, the user must", "images": [], "options": {"A": "configure firewall", "B": "encourage piracy", "C": "install cracked software", "D": "promote cybercrime"}, "answer": "A", "explanation": "To avoid damages caused by security breaches, a user must configure a firewall. A firewall is a network security system that monitors and controls incoming and outgoing network traffic based on predetermined security rules. It establishes a barrier between a trusted internal network and untrusted external network, such as the Internet. Therefore, the correct answer is 'configure firewall'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>1", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Quantitative data can exist in", "images": [], "options": {"A": "continuous form only", "B": "continuous and discrete forms", "C": "nominal and ordinal forms", "D": "ordinal form only"}, "answer": "B", "explanation": "Quantitative data is defined as the value of data in the form of counts or numbers where each data-set has a unique numerical value associated with it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>2", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Data created by the user is called", "images": [], "options": {"A": "primary data", "B": "qualitative data", "C": "quantitative data", "D": "secondary data"}, "answer": "A", "explanation": "Primary data is data that is collected directly from the source. It is the most original and accurate type of data.    Secondary data is data that has been collected and analyzed by someone else. It is often used to supplement primary data.    Qualitative data is data that is non-numerical and descriptive. It is often used to understand people's thoughts, feelings, and experiences.    Quantitative data is data that is numerical and can be measured. It is often used to describe and analyze trends.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>3", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The sequence of operation of a computer is", "images": [], "options": {"A": "accept data, process data and produce output", "B": "accept data, produce data and produce information", "C": "produce data, supply data and produce output", "D": "process data, produce data and display information"}, "answer": "A", "explanation": "At a fundamental level, computers operate through these four functions; Input, Output, Processing and Storage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>4", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following description is not true about data? It", "images": [], "options": {"A": "can be converted to information", "B": "is a collection of raw facts and figures", "C": "is unorganized", "D": "is used for decision making"}, "answer": "D", "explanation": "The statement 'data is used for decision making' is not true about data. Data in its raw form cannot be used for decision making. It is only after data has been processed into information that it can be used for decision making.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>5", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Which of the following statements is true about supercomputers? They", "images": [], "options": {"A": "can fit on a single small chip", "B": "are easily affordable", "C": "can process billions of operations in a second", "D": "are found across various homes and offices"}, "answer": "C", "explanation": "A supercomputer is a computer that performs at or near the currently highest operational rate for computers. Supercomputers have been used for scientific and engineering applications that must handle very large database or do a great amount of computation ( or both).", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>6", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The Slides Rule is accurate to", "images": [], "options": {"A": "1-2 decimal places", "B": "3 -4 decimal places", "C": "5-6 decimal places", "D": "6 decimal places"}, "answer": "B", "explanation": "The slide rule is a mechanical analog computer used primarily for multiplication and division, and also for functions such as exponents, roots, logarithm, and trigonometry, but typically not for addition or subtraction. In practice, you get between two to three significant figures from slide rule calculations, and these are errors compound as you use intermediate values in subsequent calculations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>7", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "What factors will motivate a field engineer into choosing a notebook computer over a desktop computer?", "images": [], "options": {"A": "Cost, convenience and battery life", "B": "Cost, size and convenience", "C": "Size, convenience and battery life", "D": "Size, cost and battery life"}, "answer": "C", "explanation": "The factors that will motivate a field engineer into choosing a notebook computer over a desktop computer are: The Size, convenience and battery life.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>8", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A collection of wires through which data are transmitted from one part of the computer to another is known as", "images": [], "options": {"A": "address", "B": "bus", "C": "driver", "D": "register"}, "answer": "B", "explanation": "In computer architecture, a bus is a communication system that transfers data between components inside a computer, or between computers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>9", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The total possible combination of the input variables for a logic gate containing three input variables is", "images": [], "options": {"A": "3", "B": "4", "C": "8", "D": "12"}, "answer": "C", "explanation": "With three total inputs, you can make 8 ie  2n where n is the number of inputs.   Therefore, 2^ (3) = 2 x 2 x 2  = 8", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>10", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "What is the the least number of 750 MB capacity CD-ROM discs needed to transfer 10 GB size file?", "images": [], "options": {"A": "75", "B": "31", "C": "14", "D": "13"}, "answer": "C", "explanation": "1000 megabytes = 1 Gigabyte   Tota megabytes = 1000 x 10  = 10000   Therefore, 750MB = 10,000/750   = 13.33", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>11", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "- The logic gate represented in the diagram is called", "images": ["Computer Studies/imgs/2021/img13.png"], "options": {"A": "AND gate", "B": "NAND gate", "C": "NOR gate", "D": "OR gate"}, "answer": "B", "explanation": "a NAND gate is a logic gate which produces an output which is false only if all its inputs are true; thus its output is complement to that of an AND gate. It is a two input digital combination logic circuit that performs the logical inverse of AND gate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>12", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Use the logic gate in the diagram to answer this question       - Which of the logic gates will give an output opposite to the input state?", "images": ["Computer Studies/imgs/2021/img14.png"], "options": {"A": "X", "B": "Y and Z", "C": "Z", "D": "X and Y"}, "answer": "A", "explanation": "The diagram X represent the NOT gate. The NOT gate is the simplest and it is also known as inverter. It accepts a single input and outputs the opposite value. If the input is 0, the output is 1 and if the input is 1, the output is 0.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>13", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Use the logic gate in the diagram to answer this question     - Which of the following statements is true about the logic gates X and Y?", "images": ["Computer Studies/imgs/2021/img14.png"], "options": {"A": "They both have multiple output variable", "B": "The output state of each depends on the inputs state", "C": "The output is true only if all inputs are true", "D": "They are both equivalent gates"}, "answer": "B", "explanation": "Computers use Logic gates to transform the 1s and 0s from input wires. A logic gate accepts inputs and then output a result on their state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>14", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "- The logic equation of the logic circuit in the above diagram is", "images": ["Computer Studies/imgs/2021/img16.png", "Computer Studies/imgs/2021/img17a.png", "Computer Studies/imgs/2021/img17b.png", "Computer Studies/imgs/2021/img17c.png", "Computer Studies/imgs/2021/img17d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "From the truth table, The Logical equation for the logic circuit is Z = A +B. C", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2021>15", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The operation of a computer and peripherals attached to it is controlled by", "images": [], "options": {"A": "application software", "B": "hardware", "C": "live ware", "D": "system software"}, "answer": "D", "explanation": "The operation of a computer and peripherals attached to it is controlled by the system software. System software is a type of computer program that is designed to run a computer's hardware and application programs. It includes the operating system and device drivers that control how the hardware interfaces with the software.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>16", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "COBOL was developed for", "images": [], "options": {"A": "business operations", "B": "game developers", "C": "mobile applications developers", "D": "search engine optimization"}, "answer": "A", "explanation": "COBOL meaning Common business oriented language , is a compiled English-like computer programming language designed for business use. It is primarily used in business, finance, and administrative system for companies and governments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>17", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The operating system performs the following operations except", "images": [], "options": {"A": "organization of data", "B": "resource allocation", "C": "creation of data", "D": "arrangement of files"}, "answer": "C", "explanation": "An operating system has three main functions:   - manage the computer's resources such as the central processing unit, memory, disk drives and printers   - establish a user interface   - execute and provide services for applications software.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>18", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The fundamental purpose of the BIOS is", "images": [], "options": {"A": "initializing and testing hardware components", "B": "testing the system performance", "C": "updating the system performance", "D": "saving the operating system's life"}, "answer": "A", "explanation": "BIOS (Basic Input / Output System), computer program that is typically stored in EPROM and used by the CPU to perform start-up procedures when the computer is turned on. Its two major procedures are determining what peripheral devices (keyboard, mouse, disk drives, printers, video cards etc) are available and loading the operating system into main memory.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>19", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "The IF.....THEN statement in BASIC is called", "images": [], "options": {"A": "an assignment statement", "B": "an object", "C": "a class", "D": "a control structure"}, "answer": "D", "explanation": "The IF....THEN.....ELSELF.....ELSE control flow statement allows identifying if a certain condition is true, and executes a block of code if it is the case.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>20", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The use of natural language and symbols to write instructions for the computer is called", "images": [], "options": {"A": "machine language programming", "B": "assembly language programming", "C": "algorithm language programming", "D": "high level language programming"}, "answer": "D", "explanation": "A high level language is a programming language such as C, FORTRAN, or Pascal that enables a programmer to write programs that are more or less independent of a particular type of computer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>21", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following stages of the SDLC is post operational stage?", "images": [], "options": {"A": "Analysis", "B": "Design", "C": "Investigation", "D": "Maintenance"}, "answer": "D", "explanation": "The objective of the Post-Implementation Phase is to maintain and enhance the system to meet the ongoing needs of the user community. The operations and maintenance phase is the last phase when end users can fine tune the system, if they wish, to boost performance, add new capabilities or meet additional user requirements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>22", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The expression 5 + 3* 4/2 - 3^2 in QBASIC evaluate to", "images": [], "options": {"A": "7", "B": "4", "C": "2", "D": "1"}, "answer": "C", "explanation": "Operator\tName\t^\tExponent\t*\tMultiplication\t/\tDivision\t+\tAddition\t-\tSubtraction & Unary Minus\t(....)\tSub expression\t    Therefore, 5 + 3* 4/2 - 32   = 5 + 3* 4/2 - 9   = 5 + 3* 2 - 9   = 5 + 6 - 9   = 11 - 9   = 2", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>23", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Use diagram below to answer question      - The basic problem with the flowchart is that it has", "images": ["Computer Studies/imgs/2021/2NBKHF.jpg"], "options": {"A": "no direction", "B": "no algorithm", "C": "END as a process", "D": "improper branch out"}, "answer": "D", "explanation": "From the diagram above, the basic problem is the improper branch out.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2021>24", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Use diagram below to answer question    - What activity is the flowchart made to represent", "images": ["Computer Studies/imgs/2021/2NBKHF.jpg"], "options": {"A": "How to pick an orange", "B": "Instruction to pick an orange", "C": "Evaluation on how to pick an orange", "D": "Number of times to pick an orange"}, "answer": "B", "explanation": "A flow chart is a type of diagram that represents a workflow or process. The flowchart shows the steps as boxes of various kinds, and their order by connecting the boxes with arrows.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2021>25", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Use diagram below to answer question    - If N in the flowchart is represented by 10, which of the following conditions is not true?", "images": ["Computer Studies/imgs/2021/2NBKHF.jpg"], "options": {"A": "If C > 10, do not pick orange", "B": "If C = 10, stop picking orange", "C": "If C", "D": "If C = 10, continue picking orange"}, "answer": "C", "explanation": "Since the N is a Rhombus, then it has one or several entrance point and exactlty two outputs. It contains a valid conditional expression. The expression could be evaluated as \"true of \"false\".", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2021>26", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "A computer system on the network that stores pages , takes requests from clients as well as send out information is called a", "images": [], "options": {"A": "client", "B": "web page", "C": "web server", "D": "website"}, "answer": "C", "explanation": "A web server is software and hardware that uses HTTP and other protocols to respond to client requests made over the World Wide Web.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>27", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "The device in Figure 5 uses a transmission method called", "images": ["Computer Studies/imgs/2021/img15.png"], "options": {"A": "broadcast", "B": "podcast", "C": "multicast", "D": "unicast"}, "answer": "A", "explanation": "Broadcasting is a method of transferring a message to all recipents simultaneously.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>28", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "In the diagram, the signal from modem X to modem Y is", "images": ["Computer Studies/imgs/2021/img2.png"], "options": {"A": "analogue", "B": "digital", "C": "imaginary", "D": "aperiodic"}, "answer": "A", "explanation": "Analogue signals are transmitted using a continuously changing quantity as a reference. An example of an analogue signal is the transmission of radio, waves, television waves or sound waves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>29", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The \"/exams\" in the web address: https://www.waec.org.ng/exams is called", "images": [], "options": {"A": "domain name", "B": "path", "C": "port", "D": "subdomain"}, "answer": "B", "explanation": "A path is a string of character used to uniquely identify a location in a directory structure. It is used to represent the directory/file relationships common in modern operating systems and are essential in the construction of uniform Resource Locators", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>30", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "Which of the following statements about URL is true? It is", "images": [], "options": {"A": "a computer software program", "B": "a type of web server", "C": "an acronym for unlimited resources for learning", "D": "the address of a document or \"page\" on the world wide web"}, "answer": "D", "explanation": "URL stands for Uniform Resource Locator. A URL is nothing more than the address of a given unique resource on the Web.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>31", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "The type of network represented in diagram is called", "images": ["Computer Studies/imgs/2021/computerobjquestion31.png"], "options": {"A": "LAN", "B": "MAN", "C": "PAN", "D": "WAN"}, "answer": "A", "explanation": "LAN means Local Area Network and is a computer that interconnects computers within a limited area such as residence, school, laboratory, university campus or office building.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>32", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "In MS Excel, the cell that contains the pointer cursor is called the", "images": [], "options": {"A": "active cell", "B": "current cell", "C": "default cell", "D": "passive cell"}, "answer": "A", "explanation": "The active cell is also referred to as a cell pointer or selected cell. An active cell refers to a cell in an Excel spreadsheet that is currenlty selected by clicking the mouse pointer or keyboard keys.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>33", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "The part of the graphic interface in Figure 8 labelled V is called", "images": ["Computer Studies/imgs/2021/img4.png"], "options": {"A": "pan", "B": "zoom in", "C": "zoom out", "D": "fit to window"}, "answer": "D", "explanation": "The part of the graphic interface in Figure 8 labelled V is called fit to window.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>34", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The diagram above, in the number 11012 is indicated in MS Word using a feature called", "images": ["Computer Studies/imgs/2021/img14.png"], "options": {"A": "superscript", "B": "subscript", "C": "root", "D": "exponentiation"}, "answer": "B", "explanation": "In computer programming, a subscript is a number representing an element in an array. For example, with example [3] or $example[3], the [3] is the subscript of the \"example\" array.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>35", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "The part of the MS Access interface labeled X,  is called", "images": ["Computer Studies/imgs/2021/img6.png"], "options": {"A": "Report view", "B": "Report wizard", "C": "Query design", "D": "Query view"}, "answer": "D", "explanation": "It shows a select query is a database object that shows information's in Datasheet view. It does not store data; it displays data that is stored in tables.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>36", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Which of the following formulas will display the current seconds past the minute of the clock in MS Excel?", "images": [], "options": {"A": "= MINUTE0", "B": "= MINUTE (N0W0)", "C": "= MINUTE (YEAR0)", "D": "= MINUTE (HOUR(N0W0))"}, "answer": "B", "explanation": "the current seconds past the minute of the clock in MS Excel is shown as = MINUTE(N0W0)", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>37", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The part of the MS Word interface labeled II  is called", "images": ["Computer Studies/imgs/2021/img5.png"], "options": {"A": "Read mode", "B": "Print Layout", "C": "Proofing error", "D": "Web layout"}, "answer": "B", "explanation": "The print view is located at the bottom-right corner of your document window. Click view tab and then click the view you want to use, such as print layout or draft view.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>38", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "What type of relationship can you deduce from the statement a department has many employees?", "images": [], "options": {"A": "One-to-one", "B": "One-to-many", "C": "Many-to-many", "D": "Many-to-one"}, "answer": "B", "explanation": "In a relational database, a one-to-many relationship exists when one row in table A may be linked with many rows in table B, but one row in table B is linked to only one row in table A.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>39", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The screen background where icons and windows are displayed in GUI is called", "images": [], "options": {"A": "explorer", "B": "desktop", "C": "opening screen", "D": "home page"}, "answer": "B", "explanation": "The desktop is the main screen area that you see after you turn on your computer and log on to Windows. The desktop is sometimes defined more broadly to include the taskbar and Windows Sidebar. The taskbar sits at the bottom of your screen. It shows you which programs are running and allows you to switch between them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>40", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The windows shortcut key for closing an active application is", "images": [], "options": {"A": "Alt +F4", "B": "Ctrl + Alt +Del", "C": "Ctrl +Esc", "D": "Ctrl + Shift +Del"}, "answer": "A", "explanation": "The shortcut key for closing an active application in Windows is 'Alt + F4'. This command sends a close message to the active window, which will usually result in the application closing. 'Ctrl + Alt + Del' is used to open the task manager, 'Ctrl + Esc' opens the start menu, and 'Ctrl + Shift + Del' opens the clear browsing data window in most browsers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>41", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Changing the default settings or appearance of the Taskbar in windows by a user is known as", "images": [], "options": {"A": "customization", "B": "designing", "C": "generalization", "D": "globalization      ."}, "answer": "A", "explanation": "Customization lets users make their own selections about what they want to see, or set preferences for how information is organized or displayed. It can enhance user experience because it allows users to control their interaction", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>42", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The part of the computer system shown is used to", "images": ["Computer Studies/imgs/2021/img1.png"], "options": {"A": "perform memory test", "B": "power on or off the computer", "C": "print a document from the computer", "D": "reset the computer to factory setting"}, "answer": "B", "explanation": "In a typical desktop computer setup, power buttons and switches appear on the front and sometimes back of the monitor and on the front and back of the case.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>43", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A single character in an EBCDIC encoding system can be represented using", "images": [], "options": {"A": "4 bits", "B": "6 bits", "C": "8 bits", "D": "16 bits"}, "answer": "C", "explanation": "Extended Binary Coded Decimal interchange Code is an eight-bit character encoding used mainly on IBM mainframe and IBM midrange computer operating systems.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>44", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Evaluate 100112 - 11112", "images": [], "options": {"A": "000102", "B": "1002", "C": "010002", "D": "100002"}, "answer": "B", "explanation": "100112 - 11112   = 001002     Alternatively:   Convert 100112 to base to   1 x 24 + 1 x21 + 1 x 20   = 16 + 2 + 1   = 1910     11112 = 1 x 23 + 1 x2 2 + 1 x 21 + 1 x 20   = 8+4+2+1   = 1510     Therefore, 19 - 15 = 4   Convert 410 to base 2    2\t4\t2\t2 R 0\t2\t1 R 0\t\t0 R 1\t           410 = 1002", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>45", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The binary number 0.1101 in decimal is", "images": [], "options": {"A": "0.8125", "B": "0.8215", "C": "0.8225", "D": "0.8512"}, "answer": "A", "explanation": "0.1101 = 1 x 2-1 + 1 x 2-2 + 1 x2 -3 + 1 x 2-4   = 1/2 + 1/4 + 0 + 1/16   = 13/16   = 0.812510", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>46", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "To prevent unforeseen data loss, a user must", "images": [], "options": {"A": "edit the data", "B": "create the data", "C": "backup the data", "D": "defragment the data"}, "answer": "C", "explanation": "Ways to prevent data loss are: Always back up your data, Diversify your backups, Encrypt sensitive data, Address data security etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2021>47", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "The file access method shown is called", "images": ["Computer Studies/imgs/2021/img3.png"], "options": {"A": "hashed access", "B": "indexed access", "C": "random access", "D": "sequential access"}, "answer": "B", "explanation": "Index sequential method is built on the top of the sequential access method. These methods construct an index for the file. The index, like an index in the back of a book, contains the pointer to the various blocks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>48", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following options is not a similarity between computer file and manual file? Both can", "images": [], "options": {"A": "be accessed", "B": "be retrieved", "C": "store multimedia", "D": "contain information"}, "answer": "C", "explanation": "Both computer files and manual files can be accessed, retrieved, and contain information. However, manual files cannot store multimedia. Multimedia files are digital or electronic files that contain audio, video, or both. They can be played, displayed, or executed on a computer or electronic device.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>49", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "A computer program that gathers information about a person or organization without their knowledge or consent is known as", "images": [], "options": {"A": "adware", "B": "time bomb", "C": "trojan horse", "D": "spyware"}, "answer": "D", "explanation": "Spyware is software with malicious behaviour that aims to gather information about a person or organization and send it to another entity in a way that harms the user.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2021>50", "subject": "Computer Studies", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "The following actions are the effects of virus infection in a system except", "images": [], "options": {"A": "deletion of files", "B": "slow operation", "C": "hard disk failure", "D": "display of unwanted message"}, "answer": "C", "explanation": "Computer viruses infect personal computers (PCs) and server. Some viruses create mere annoyance, but other can do serious damage: delete or change files, steal important information, load and run unwanted applications, send documents via electronic mail or even cripple a machines operating system", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>1", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "One-millionth of a second is also referred to as", "images": [], "options": {"A": "nanosecond", "B": "microsecond", "C": "millisecond", "D": "picosecond"}, "answer": "B", "explanation": "One-millionth of a second is referred to as a microsecond. The prefix 'micro' in the metric system denotes a factor of one millionth (10^-6). Therefore, a microsecond is one millionth of a second.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>2", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Examples of quantitative data type are", "images": [], "options": {"A": "continuous and discrete", "B": "local and foreign", "C": "nominal and ordinal", "D": "primary and secondary"}, "answer": "A", "explanation": "Quantitative data is numerical data that can be measured or counted. It is divided into two types: continuous and discrete. Continuous data can take any value within a range, while discrete data can only take certain values.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>3", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "One difference between data and information is that", "images": [], "options": {"A": "data is meaningful while information is not meaningful", "B": "data are raw facts and figures while information is computed data", "C": "information is independent of data while data is dependent on information", "D": "information is the raw material while data is the end product of information"}, "answer": "B", "explanation": "Data are raw facts and figures, while information is processed data. Data becomes information when it is processed and put into context, providing it with meaning and relevance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>4", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "The following options are examples of information except", "images": [], "options": {"A": "area of a circle", "B": "circumference of a circle", "C": "perimeter of a rectangle", "D": "plain shape of a rectangle"}, "answer": "D", "explanation": "Information is data that is processed to be useful; it provides answers to 'who', 'what', 'where', and 'how' questions. In this context, 'plain shape of a rectangle' is not an example of information because it does not provide any specific or processed data. The other options provide specific measurements, which can be considered as information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>5", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Modern computers compared to earlier computers are", "images": [], "options": {"A": "less reliable", "B": "faster and larger", "C": "larger and stronger", "D": "faster and smaller"}, "answer": "D", "explanation": "Modern computers are faster and smaller compared to earlier computers. This is due to advancements in technology that have allowed for the miniaturization of components and increased processing power. The other options are incorrect because modern computers are not less reliable, nor are they larger and stronger.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>6", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "What type of computer would be most suitable for a student who lives in a remote village without constant electricity?", "images": [], "options": {"A": "Desktop computer", "B": "Laptop computer", "C": "Mainframe computer", "D": "Mini computer"}, "answer": "B", "explanation": "A laptop is most suitable for a student in a remote village, can easily be carried around and has enough power backup.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>7", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "EDSAC was produced using a concept known as", "images": [], "options": {"A": "Circuit switching", "B": "Packet routing", "C": "Packet switching", "D": "Stored program"}, "answer": "D", "explanation": "EDSAC, the Electronic Storage Automatic Calculator (EDSAC) was based on John Von Neumann's stored program concept.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>8", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The process of running more than one program concurrently is known as", "images": [], "options": {"A": "multithreading", "B": "multitasking", "C": "multiprogramming", "D": "multipurpose"}, "answer": "B", "explanation": "Multitasking allows users to run multiple programs at the same time, even if the computer only has one CPU. This is done by switching between the programs very quickly, so that it appears to the user that all of the programs are running at the same time.    Multitasking is a common feature of modern operating systems. It allows users to be more productive by allowing them to run multiple programs at the same time.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2022>9", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "How many binary digits are contained in 10 MB of a memory stick?", "images": [], "options": {"A": "10 x 1024", "B": "10 x 1024 x 8", "C": "10 x 1024 x x1024", "D": "10 x 1024 x 1024 x8"}, "answer": "D", "explanation": "1 byte = 8 bits, 1 KB = 1024 bytes, 1 MB = 1024 KB. Therefore, 10 MB = 10 x 1024 x 1024 x 8 bits. So, the correct answer is '10 x 1024 x 1024 x 8'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>10", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A student would require the following devices to fill an online application form except", "images": [], "options": {"A": "keyboard", "B": "mouse", "C": "printer", "D": "webcam"}, "answer": "C", "explanation": "A printer is not needed to fill an online application form, since you may not necessarily need to print, the form is submitted online.  You need mouse and keyboard to input your data and webcam to take passport photograph.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>11", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The logic gate in Figure 1 is called", "images": ["Computer Studies/imgs/2022/compstudiesq11.jpg"], "options": {"A": "AND gate", "B": "NAND gate", "C": "NOR gate", "D": "OR gate"}, "answer": "A", "explanation": "The logic gate is an AND gate, it takes two or more inputs and returns true if they are all true.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>12", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The logic equation for the logic gate in Figure 1  is", "images": ["Computer Studies/imgs/2022/compstudiesq11.jpg"], "options": {"A": "Z = A + B", "B": "Z = A.B", "C": "Z =bar( A + B)", "D": "Z = bar(A.B)"}, "answer": "B", "explanation": "Z = A.B, AND is denoted by dot or product of the input", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2022>13", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The part balled x in Figure 2 is called", "images": ["Computer Studies/imgs/2022/7MN32K.png"], "options": {"A": "auxiliary memory", "B": "output unit", "C": "secondary memory", "D": "storage unit"}, "answer": "B", "explanation": "The part labeled as x in Figure 2 is commonly referred to as the output unit in computer systems. The output unit is a fundamental component responsible for presenting the results of processed data to the user or to other systems. It plays a crucial role in the overall functioning of a computer, as it translates the internal operations and calculations into a format that can be easily understood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>14", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The logic equation for the logic circuit in Figure 3  is", "images": ["Computer Studies/imgs/2022/compstudiesq14.jpg"], "options": {"A": "Z = bar(A + B) + C", "B": "Z = bar(A.B) + C", "C": "Z = A + B + C", "D": "Z = A.B.bar(C)"}, "answer": "B", "explanation": "Z = bar(A.B.bar(C))  from boolean theorem  if P = bar(X.Y)  P = bar(X) + bar(Y)  Z = bar(A.B) + C", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2022>15", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The program that is loaded into a special area on a microprocessor or ROM on a one-time basis and becomes part of the hardware is called", "images": [], "options": {"A": "firmware", "B": "liveware", "C": "software", "D": "utility"}, "answer": "A", "explanation": "Firmware is a computer program that is embedded in a hardware device and is an essential part of the hardware.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>16", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES~~TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM~~TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The following programs are general purpose application software except", "images": [], "options": {"A": "CorelDraw", "B": "Payroll system", "C": "MS Access", "D": "MS Word"}, "answer": "B", "explanation": "Payroll system is not a general purpose application software, it provides only one feature for the user.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>17", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "One similarity between bespoke software and application packages is that they are", "images": [], "options": {"A": "both available off the shelf", "B": "highly standardized", "C": "both written by computer users", "D": "meant to be used by computer end-users"}, "answer": "D", "explanation": "Bespoke software and application packages are both meant to be used by computer end-users. Bespoke software is custom software tailored to the specific needs of an organization or user, while application packages are pre-written applications available for general use. Both are designed to be used by end-users to perform specific tasks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>18", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "One function of operating system is", "images": [], "options": {"A": "power supply allocation", "B": "file corruption and deletion", "C": "hardware upgrade", "D": "resource allocation"}, "answer": "D", "explanation": "Operating system has other functions like memory management,processor management,file management, security, coordination between other software and users. etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>19", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The process of testing the logic of algorithm to ensure they give correct result is known as", "images": [], "options": {"A": "debugging", "B": "desk checking", "C": "flowcharting", "D": "pseudo-coding"}, "answer": "B", "explanation": "A desk check is an informal non-computerized or manual process for verifying the programming and logic of an algorithm before the program is launched.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>20", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The following instructions are guidelines for drawing flowcharts  except that", "images": [], "options": {"A": "flowcharts must have logical start and finish", "B": "it should follow a direction of left to right or top to bottom", "C": "it should follow a direction of right to left or bottom to top", "D": "it should be clear, neat and easy to follow"}, "answer": "C", "explanation": "Flowcharts are graphical representations of a process. They are typically drawn from left to right or top to bottom to represent the flow of control. The option 'it should follow a direction of right to left or bottom to top' is incorrect because it contradicts the standard direction of flow in a flowchart.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>21", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING", "question": "Key skills of a system analyst include the following except", "images": [], "options": {"A": "ability to troubleshoot", "B": "interest in learning new skills", "C": "motivational skills", "D": "proficiency in programming languages"}, "answer": "C", "explanation": "A system analyst does not need a motivational skills", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>22", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The result of the expression 2*6 + 2/4*2*4^2 is", "images": [], "options": {"A": "21", "B": "27", "C": "28", "D": "29"}, "answer": "C", "explanation": "2×6 + 2/4×2×42 = 28    Therefore, the result of the expression is 28", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>23", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Use the QBASIC program below to answer the following question      10 REM Program to calculate of numbers    20 CLS    30 IMPUT A\t    40 IMPUTE B    50 LET PRODUCT = A * B     60 PRINT PRODUCT    70 END    The numbers 10, 20, 30, 40, 50, 60 and 70 as stated in the program indicate", "images": [], "options": {"A": "bullet numbering", "B": "codes", "C": "labels", "D": "line numbers"}, "answer": "D", "explanation": "In QBASIC, the numbers 10, 20, 30, 40, 50, 60, and 70 are line numbers. They are used to organize the code and control the flow of the program. Each line number is followed by a QBASIC statement or command. The program executes these commands in the order of their line numbers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>24", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The QBASIC statement LET X = Y - 3 means", "images": [], "options": {"A": "the variables X and Y both receive the value 3", "B": "the variable X receives the value 3", "C": "the variable X receives the value of Y less 3", "D": "an error message has occurred due to type mismatch"}, "answer": "C", "explanation": "In QBASIC, the statement 'LET X = Y - 3' means that the variable X is assigned the value of Y minus 3. The 'LET' keyword is used to assign a value to a variable. In this case, the value of Y is reduced by 3 and the result is stored in the variable X.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>25", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The part labelled Y  in the compiler interface in Figure 4  represents", "images": ["Computer Studies/imgs/2022/4BR284.png"], "options": {"A": "intermediate code", "B": "binary code", "C": "object code", "D": "pseudo code"}, "answer": "B", "explanation": "Compilers translate source codes to machine codes which are binary codes", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>26", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The virtual communication platform where many people keep in contact with family and friends is known as", "images": [], "options": {"A": "Microsoft Visio", "B": "social engineering", "C": "cyberspace", "D": "virtual reality"}, "answer": "C", "explanation": "Cyberspace is a concept describing a widespread interconnected digital technology", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>27", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The protocol used for email transmission is known as", "images": [], "options": {"A": "HTTPS", "B": "DHCP", "C": "IP", "D": "SMTP"}, "answer": "D", "explanation": "SMTP. The Simple Mail Transfer Protocol (SMTP) is used for sending and receiving e-mail between e-mail clients and servers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>28", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The signals from computer A to modem X in Figure 5 are", "images": ["Computer Studies/imgs/2022/compstudiesq28.jpg"], "options": {"A": "analogue", "B": "digital", "C": "electrons", "D": "protons"}, "answer": "B", "explanation": "A digital signal is a signal that represents data using a sequence of discrete values, such as 0s and 1s. Digital signals are used in computers, digital phones, and other technological devices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>29", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "What type of network is represented in Figure 6?", "images": ["Computer Studies/imgs/2022/BTEPN4.png"], "options": {"A": "Local Area Network", "B": "Metropolitan Area Network", "C": "Personal Area Network", "D": "Wide Area Network"}, "answer": "D", "explanation": "A wide area network (WAN) is a large computer network that connects groups of computers over large distances. WANs are often used by large businesses to connect their office networks; each office typically has its own local area network, or LAN, and these LANs connect via a WAN.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>30", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "In the URL https://www.waec.org.ng, the domain name is", "images": [], "options": {"A": "waec.org.ng.", "B": "https://www.", "C": "//www.waec.", "D": ".org.ng."}, "answer": "A", "explanation": "A domain name (or just 'domain') is the name of a website. It's what comes after \"@\" in an email address, or after \"www.\" in a web address.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>31", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The type of transmission in the part labelled Q in Figure 7 is called", "images": ["Computer Studies/imgs/2022/compstudiesq30.jpg"], "options": {"A": "broadcast", "B": "full duplex", "C": "half duplex", "D": "simplex"}, "answer": "B", "explanation": "In full-duplex mode, both stations can transmit and receive simultaneously.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>32", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "The maximum length of a text field in MS Access is", "images": [], "options": {"A": "75", "B": "120", "C": "255", "D": "265"}, "answer": "C", "explanation": "The maximum length of a text field in MS Access is 255 characters.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>33", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "The number of entries in Figure below is", "images": ["Computer Studies/imgs/2022/compstudiesq33.jpg"], "options": {"A": "3", "B": "4", "C": "5", "D": "12"}, "answer": "B", "explanation": "The number of entries in Figure above is four (4).", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>34", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The shortcut key for the Open dialog box in MS word is", "images": [], "options": {"A": "Alt + F12", "B": "Ctrl + F12", "C": "F12", "D": "Shift + F12"}, "answer": "B", "explanation": "The shortcut key for the Open dialog box in MS Word is Ctrl + F12. This command opens the Open dialog box where you can select a file to open.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>35", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "The part of the CorelDraw window labelled II in Figure 9  is called", "images": ["Computer Studies/imgs/2022/compstudiesq34.jpg"], "options": {"A": "Pan", "B": "Zoom In", "C": "Zoom Out", "D": "Zoom to fit"}, "answer": "A", "explanation": "pan tools let you move the page around in the drawing window to view previously hidden areas.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>36", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Which of the following operations will not  run a slide show in MS PowerPoint?", "images": [], "options": {"A": "Pressing F5", "B": "Pressing Shift + F5", "C": "Choosing the slide show tab", "D": "Clicking the slide show on the taskbar"}, "answer": "D", "explanation": "Clicking the slide show on the taskbar will not run a slide show in MS PowerPoint. The taskbar is a component of an operating system's graphical user interface which serves as the housing for tasks and notifications related to open programs. Pressing F5, Pressing Shift + F5, and Choosing the slide show tab are all correct ways to start a slide show in PowerPoint.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>37", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "What will be the result of writing the formula =Year(now()) + 3 in a worksheet of a spreadsheet, if the current calendar date is  14 August, 1960?", "images": [], "options": {"A": "17 August, 1960 03.00", "B": "14 August, 1963", "C": "11 August, 1963", "D": "1963"}, "answer": "D", "explanation": "The formula =Year(now()) + 3 in a worksheet of a spreadsheet will return the current year plus 3. If the current calendar date is 14 August, 1960, the formula will return 1963. The Year function returns the year of a date as a four digit number, the Now function returns the current date and time, and the '+' operator adds 3 to the year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>38", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "If A is in cell A1 and B is cell B1 of a worksheet in a spreadsheet application, write a formula  tocalculateX=A2+B1/2100", "images": [], "options": {"A": "((A1^2) + (B11/2))/100", "B": "((A1^2 + (B11/2))/100", "C": "((A1^2 + (B11/2)/100", "D": "((A1^2 + (B1^1/2)))/100"}, "answer": "A", "explanation": "The formula is given below:    ((A1^2) + (B11/2))/100", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2022>39", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The pictorial representation of an object or application in the computer is called", "images": [], "options": {"A": "diagram", "B": "graphic", "C": "icon", "D": "image"}, "answer": "C", "explanation": "An icon is an image on the computer screen that represents an application, a capability, or some other concept or specific entity with meaning for the user.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>40", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Deleted items in the computer are temporarily stored in the", "images": [], "options": {"A": "memory unit", "B": "processor", "C": "recycle bin", "D": "task manager"}, "answer": "C", "explanation": "When you delete items on a computer, they are not immediately removed from the system. Instead, they are moved to a special folder called the Recycle Bin. This allows you to recover files if you accidentally delete them. The items remain in the Recycle Bin until you manually empty it, or until the system automatically does so to free up disk space.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>41", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The keyboard key combination ALT + F4 in Microsoft Windows will", "images": [], "options": {"A": "close active programmes", "B": "open a file", "C": "restart the computer", "D": "save all active files"}, "answer": "A", "explanation": "The keyboard key combination ALT + F4 in Microsoft Windows is used to close the active program. This is a shortcut command that is commonly used in Windows operating systems to quickly close an application or window.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>42", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Select two stages of booting from the following list:  I.\tPower on Self Test;  II.\tLoading of Operating System;  III.\tLoading of e-mails;  IV.\tStart in safe mode.", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and IV only", "D": "III and IV only"}, "answer": "A", "explanation": "Stages of booting  The Startup. It is the first step that involves switching the power ON. ...  BIOS: Power On Self Test. It is an initial test performed by the BIOS. ...  Loading of OS.  System Configuration.  Loading System Utilities.  User Authentication", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>43", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "In number system, base 16 is called", "images": [], "options": {"A": "hexadecimal", "B": "decimal", "C": "duodecimal", "D": "octal"}, "answer": "A", "explanation": "In number systems, base 16 is called hexadecimal. The hexadecimal system is a base 16 number system that uses sixteen distinct symbols, typically the symbols 0–9 to represent values zero to nine, and A, B, C, D, E, F (or alternatively a–f) to represent values ten to fifteen.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2022>44", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Add 12716 to 50A16", "images": [], "options": {"A": "62916", "B": "63016", "C": "63116", "D": "63216"}, "answer": "C", "explanation": "1 2 75 0 A6 3 1    A = 10, 10+7 = 17  17 -16 = 1, write 1 and add 16/16 = 1 to 2 which is = 3 and 5+1 = 6", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2022>45", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The octal fraction 0.65 converts to binary as", "images": [], "options": {"A": "0.110011", "B": "0.110101", "C": "101101", "D": "101110"}, "answer": "B", "explanation": "convert 0.658 to decimal  6 × 8-1 + 5 × 8-2 = 6 × 1/8 + 5 × 1/64  5364  5364tobinary  5364=0.828125  0.828125 × 2 = 1.65625 10.65625 × 2 = 1.3125 10.3125 × 2 = 0.625 00.625 × 2 = 1.25 10.25 × 2 = 0.50 00.50 × 2 = 1 1  0.110101  Note: when converting fraction to binary, you write from top to bottom.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2022>46", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Sequential files are", "images": [], "options": {"A": "sorted using index", "B": "sorted in a particular order", "C": "stored as they come", "D": "stored in any storage media"}, "answer": "B", "explanation": "Sequential files contain records that are sorted and stored in an ascending or descending order on a particular key field.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>47", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "The file access method illustrated in Figure 10 is called", "images": ["Computer Studies/imgs/2022/compstudiesq46.jpg"], "options": {"A": "hashed access", "B": "indexed access", "C": "random access", "D": "sequential access"}, "answer": "C", "explanation": "A random access data file enables you to read or write information anywhere in the file.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>48", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Serial files are", "images": [], "options": {"A": "sorted using a key", "B": "sorted in a particular order", "C": "stored as they come", "D": "stored in any storage media"}, "answer": "C", "explanation": "Serial files are stored as they come. This means that they are stored in the order they are received, without any sorting or reordering. This is different from sequential files, which are sorted in a particular order.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>49", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Duplicating copyrighted electronic or digital content without the author's approval is considered", "images": [], "options": {"A": "felonious", "B": "ethical", "C": "treasonable", "D": "unethical"}, "answer": "D", "explanation": "Duplicating copyrighted electronic or digital content without the author's approval is considered unethical.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2022>50", "subject": "Computer Studies", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Ethical practice requires a computer user to", "images": [], "options": {"A": "shutdown properly after using the computer", "B": "hack into other people's computer", "C": "intrude into people's privacy", "D": "copy software without the license"}, "answer": "A", "explanation": "The Ten Commandments of computer ethics as defined by the Computer Ethics  Institute.  1) Thou shalt not use a computer to harm other people:  2) Thou shalt not interfere with other people's computer work:  3) Thou shalt not snoop around in other people's files:  4) Thou shalt not use a computer to steal:  5) Thou shalt not use a computer to bear false witness:  6) Thou shalt not use or copy software for which you have not paid:  7) Thou shalt not use other people's computer resources without authorization:  8) Thou shalt not appropriate other people's intellectual output:  9) Thou shalt think about the social consequences of the program you write:  10) Thou shalt use a computer in ways that show consideration and respect:", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>1", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following data is alpha-numeric?", "images": [], "options": {"A": "568", "B": "SS3", "C": "10.00", "D": "Twenty-five"}, "answer": "B", "explanation": "The alpha-numeric data is a combination of alphabetic and numeric characters. Let's check each option:    568 - This is numeric data because it contains only numbers.    SS3 - This is alpha-numeric data because it contains both alphabetic characters (\"SS\") and a numeric character (\"3\").    10.00 - This is numeric data because it contains numbers and a decimal point, which is still considered numeric.    Twenty-five - This is alphabetic data because it contains only letters and represents a textual representation of the number 25.    So, the alpha-numeric data among the options is \"SS3\".", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>2", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The process of converting data into information is known as data", "images": [], "options": {"A": "analysis", "B": "collection", "C": "processing", "D": "collation"}, "answer": "C", "explanation": "The process of converting data into information is known as data processing. Data processing involves collecting, manipulating, and storing data to produce information that is meaningful. Data analysis is a part of data processing where data is inspected, cleaned, and modeled to discover useful information. Data collection is the process of gathering and measuring data, information or any variables of interest in a standardized and established manner that enables the collector to answer or test hypothesis and evaluate outcomes of the particular collection. Collation is the assembly of written information into a standard order. None of these options fully encapsulate the process of converting data into information like data processing does.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>3", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The  BCD  equivalent of 135 is", "images": [], "options": {"A": "111101", "B": "001011101", "C": "100110101", "D": "000100110101"}, "answer": "D", "explanation": "The BCD equivalent of 135 is 0001 0011 0101.    BCD stands for Binary-Coded Decimal. It is a way of representing decimal numbers in binary form. In BCD, each decimal digit is represented by a 4-bit binary number. The BCD equivalent of 135 is 0001 0011 0101, which is the binary representation of the decimal digits 1, 3, and 5.    1 = 0001  3 = 0011  5 = 0101  ∴ 135 = 000100110101", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>4", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following is an example of information?", "images": [], "options": {"A": "Student&#8217;s score in a test", "B": "Recorded observation", "C": "List of items", "D": "Average score of students in a test"}, "answer": "D", "explanation": "Average score of students in a test is an example of information    Information is data that has been processed and organized so that it has meaning. It can be used to make decisions, solve problems, or understand the world around us.    The other options are not examples of information. Student's score in a test is data, recorded observation is data, and list of items is data. They do not have meaning until they are processed and organized.    For example, the student's score in a test is just a number. It does not have meaning until it is compared to the scores of other students. The average score of students in a test is information because it has meaning. It tells us how well the students did on the test.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>5", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The technology used for first generation computers was", "images": [], "options": {"A": "vacuum tubes.", "B": "integrated circuit.", "C": "transistors.", "D": "microprocessors."}, "answer": "A", "explanation": "The technology used for first-generation computers was vacuum tubes.    First-generation computers were developed during the late 1940s and 1950s. These computers used vacuum tubes as their primary electronic component for processing and memory. Vacuum tubes were large, fragile, and consumed a lot of power, which made early computers bulky, unreliable, and generated significant amounts of heat. As technology progressed, vacuum tubes were eventually replaced by transistors in the second-generation computers, which were smaller, more reliable, and consumed less power. Integrated circuits and microprocessors came into existence in subsequent generations, leading to more compact and powerful computers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>6", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The main distinguishing feature of fifth generation computers is", "images": [], "options": {"A": "liberal use of microprocessors.", "B": "artificial intelligence.", "C": "extremely low cost.", "D": "versatility."}, "answer": "B", "explanation": "The main distinguishing feature of fifth generation computers is artificial intelligence.    Fifth generation computers are still in the development stage, but they are expected to be able to understand and respond to human language, learn from experience, and reason like humans. They are also expected to be able to work in parallel, which will make them much faster than previous generations of computers.    The other options are not as distinguishing features of fifth generation computers. Liberal use of microprocessors is a feature of fourth generation computers, extremely low cost is not a feature of any generation of computers, and versatility is a feature of all generations of computers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>7", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The first attempt at using the  punch card principle  to do mathematical calculations led to the invention of", "images": [], "options": {"A": "Napier&#8217;s bone", "B": "Abacus", "C": "Charles Babbage Difference Engine", "D": "Charles Babbage Analytical Engine"}, "answer": "C", "explanation": "The Difference Engine was designed by Charles Babbage in the 19th century. It was a mechanical calculator intended to compute polynomial functions by the method of finite differences. Babbage's design included the use of punch cards as a means of input, similar to the concept later employed in early computers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>8", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "An opening on the motherboard of a system unit where expansion cards can be inserted is known as", "images": [], "options": {"A": "extension board.", "B": "extension box.", "C": "expansion port.", "D": "expansion slot."}, "answer": "D", "explanation": "An opening on the motherboard of a system unit where expansion cards can be inserted is known as an expansion slot.    Expansion slots are used to add additional functionality to a computer, such as a graphics card, sound card, or network card. They are also used to add more memory to a computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>9", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "One kilobyte is equivalent to", "images": [], "options": {"A": "1024 bits.", "B": "1024 bytes.", "C": "230 bits.", "D": "230 bytes."}, "answer": "B", "explanation": "One kilobyte is equivalent to 1024 bytes. This is because the binary system, which computers use, operates in powers of 2. Therefore, 1 kilobyte (KB) is 2^10 bytes, which equals 1024 bytes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>10", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "An input device that converts an image into a text is known as", "images": [], "options": {"A": "optical character reader.", "B": "scanner.", "C": "optical mark reader.", "D": "barcode reader."}, "answer": "A", "explanation": "An input device that converts an image into text is known as an \"optical character reader\" (OCR).    OCR technology is used to recognize printed or handwritten characters in an image and convert them into editable and searchable text. It is commonly used to digitize printed documents, such as books, articles, invoices, and receipts, making it easier to store, search, and process the text electronically. OCR technology is widely used in various applications, including document scanning, data entry, text recognition, and document management systems.    Scanners and barcode readers are also input devices, but they do not convert images into text. Scanners convert images into digital images, while barcode readers convert barcodes into numbers. Optical mark readers (OMRs) are used to read marks made on a document, such as those made by a pencil or pen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>11", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The unit of the computer system that directs and supervises other units is called the", "images": [], "options": {"A": "accumulator.", "B": "arithmetic logic unit.", "C": "control unit.", "D": "memory unit."}, "answer": "C", "explanation": "The unit of the computer system that directs and supervises other units is called the \"control unit.\"    The control unit is a critical component of a computer's central processing unit (CPU). It is responsible for fetching program instructions from memory, interpreting them, and coordinating the execution of these instructions by sending control signals to other units within the CPU and other parts of the computer system. The control unit ensures that data is processed in the correct sequence and that the various components of the CPU work together harmoniously to carry out the instructions of a program. It is like the \"brain\" of the CPU, managing the flow of data and instructions and ensuring that the computer performs its tasks correctly and efficiently.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>12", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Input devices are computer devices that can", "images": [], "options": {"A": "be used to get data from the computer.", "B": "send data and instructions into the computer memory.", "C": "receive data and instructions from the computer memory.", "D": "send results to the memory of the computer."}, "answer": "B", "explanation": "Input devices are computer devices that can:    send data and instructions into the computer memory.    Input devices are used to provide data and instructions to the computer. They allow users to interact with the computer by inputting various types of data, such as text, numbers, images, and commands. Examples of input devices include keyboards, mice, touchscreens, scanners, microphones, and digital cameras. These devices enable users to send data and commands to the computer's memory, where the data is processed and stored for further use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>13", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The central processing unit consists of", "images": [], "options": {"A": "input, output and processing.", "B": "control unit, primary storage and secondary storage.", "C": "control unit, arithmetic logic unit and primary storage.", "D": "control unit, processing and primary storage."}, "answer": "C", "explanation": "The central processing unit (CPU) consists of:    control unit, arithmetic logic unit, and primary storage.    Control Unit: The control unit is responsible for managing the execution of instructions and coordinating the activities of the other components in the CPU. It fetches instructions from memory, decodes them, and directs the flow of data and control signals to ensure that instructions are executed in the correct sequence.    Arithmetic Logic Unit (ALU): The ALU performs arithmetic operations (addition, subtraction, multiplication, division) and logical operations (AND, OR, NOT) on data. It carries out the actual computation and manipulations of data as directed by the instructions.    Primary Storage: Primary storage refers to the main memory of the computer, typically made up of random-access memory (RAM). It is used to temporarily store data and instructions that the CPU is currently working on. Data and instructions are fetched from secondary storage (like hard drives or solid-state drives) into primary storage before being processed by the CPU.    The CPU is often considered the \"brain\" of the computer, as it performs the actual processing of data and instructions, making decisions, and controlling the overall operation of the computer system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>14", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A  wait state of zero  in hardware means the", "images": [], "options": {"A": "processor speed is higher than that of the memory.", "B": "processor speed is lower than that of the memory.", "C": "memory is faster than the processor in terms of speed.", "D": "processor and the memory are equally matched in speed."}, "answer": "D", "explanation": "A wait state of zero in hardware means that the processor and the memory are equally matched in speed. In computing, a wait state refers to the delay experienced by a computer processor when accessing memory. A wait state of zero means that there is no delay, implying that the processor and memory are operating at the same speed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>15", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The set of instructions used to solve specific user tasks is called", "images": [], "options": {"A": "application software.", "B": "editor.", "C": "system software", "D": "utility software."}, "answer": "A", "explanation": "The set of instructions used to solve specific user tasks is called \"application software.\"    Application software, also known as applications or apps, is a type of computer software designed to perform specific tasks or applications for end-users. These programs are created to address the needs and requirements of users, allowing them to accomplish various tasks such as word processing, spreadsheet calculations, graphic design, video editing, web browsing, and more. Application software is distinct from system software and utility software, as it is developed to serve the users directly and provide functionality tailored to specific tasks and activities. Examples of application software include Microsoft Word, Adobe Photoshop, Google Chrome, and video games.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>16", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following commands can be used to switch between open window?", "images": [], "options": {"A": "Alt + F4", "B": "Alt + Tab", "C": "Ctrl + D", "D": "Ctrl + F"}, "answer": "B", "explanation": "The command that can be used to switch between open windows is \"Alt + Tab.\"    When you press the \"Alt + Tab\" keys simultaneously, it will bring up a visual display showing thumbnail previews of all open windows on your computer. While holding the \"Alt\" key, you can continue pressing the \"Tab\" key to cycle through the open windows. Releasing the \"Alt\" key will switch to the selected window.    This feature is commonly used in operating systems like Windows to quickly switch between different applications or open windows without using the mouse. It allows users to efficiently manage and navigate among multiple open applications or tasks on their computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>17", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The command used to seek for assistance in Microsoft disk operating system is", "images": [], "options": {"A": "Helper.", "B": "/?", "C": "Attrib.", "D": "/S."}, "answer": "B", "explanation": "The command used to seek for assistance in Microsoft Disk Operating System (DOS) is \"/?\".    The /? switch is a universal switch that can be used with most MS-DOS commands to get help about the command. To use the /? switch, simply type the command followed by the /? switch and press Enter. For example, to get help about the attrib command, you would type:    attrib /?  This will display a help screen that describes the attrib command and its options.    The other options are incorrect. Helper is not a valid MS-DOS command. Attrib is a command that is used to change the attributes of files. /S is a switch that is used to specify that the command should be applied to all files in a directory and its subdirectories.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>18", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The software responsible for allocating and managing system resources is called", "images": [], "options": {"A": "driver.", "B": "operating system.", "C": "translator.", "D": "utility software."}, "answer": "B", "explanation": "The software responsible for allocating and managing system resources is called the \"operating system (OS)\".    The OS is a software program that controls the computer's hardware and software resources. It is responsible for tasks such as:    Managing memory: The OS allocates memory to different programs and processes, and it ensures that no program uses more memory than it needs.  Managing processing power: The OS schedules the execution of programs and processes, and it ensures that no program hogs the CPU.  Managing input and output: The OS controls the flow of data between the computer and its peripherals, such as the keyboard, mouse, and printer.  Managing files and directories: The OS creates and manages files and directories on the computer's hard drive.  Providing a user interface: The OS provides a user interface that allows users to interact with the computer.  The OS is a complex piece of software that is essential for the smooth operation of a computer. It is responsible for managing all of the computer's resources, and it provides a platform for running application software.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>19", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The  LET  statement in  QBASIC", "images": [], "options": {"A": "allows users to assign a value to a variable.", "B": "checks the errors within the code.", "C": "allows the users to enter data into the computer from \"outside\" the program.", "D": "allows the users to enter data into the computer during program execution."}, "answer": "A", "explanation": "The LET statement in QBASIC allows users to assign a value to a variable.    In QBASIC and other programming languages, the LET statement is used to assign a value to a variable. It is an optional keyword, and in most cases, you can simply use the variable name followed by the assignment operator (=) and the value you want to assign to the variable. For example:    LET x = 10    This statement assigns the value 10 to the variable x.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>20", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Datatypes in QBASIC programming language include the following except", "images": [], "options": {"A": "double.", "B": "float.", "C": "long.", "D": "short."}, "answer": "D", "explanation": "Datatypes in QBASIC programming language include the following except \"short.\"    In QBASIC, the datatypes that are commonly used include \"double,\" \"float,\" and \"long.\" However, \"short\" is not a standard datatype in QBASIC.    Here's a brief explanation of the other datatypes:    INTEGER: A 16-bit signed integer variable.  LONG:\t A 32-bit signed integer variable.  SINGLE: A single-precision 32-bit floating-point variable.  DOUBLE: A double-precision 64-bit floating-point variable.  STRING * n%:  A fixed-length string variable n% bytes long.  STRING: A variable-length string variable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>21", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "A good algorithm must be", "images": [], "options": {"A": "concise and finite.", "B": "consistent and continuous.", "C": "detailed and verbose.", "D": "sequential and lengthy."}, "answer": "A", "explanation": "A good algorithm must be \"concise and finite.\"    Here's the breakdown of each term:    Concise: An algorithm should be clear and easy to understand without unnecessary complexity. A concise algorithm focuses on the essential steps needed to achieve the desired outcome.    Finite: An algorithm must have a well-defined endpoint. It should eventually stop executing and provide a result after a finite number of steps. This is important to ensure that the algorithm doesn't run indefinitely, which could lead to inefficiency or errors.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>22", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The commands used for adding comments in  QBASIC  programming is", "images": [], "options": {"A": "CLS.", "B": "INPUT.", "C": "REM.", "D": "PRINT."}, "answer": "C", "explanation": "The command used for adding comments in QBASIC programming is \"REM.\"    In QBASIC, the \"REM\" statement is used to insert comments within your code. Comments are lines of text that are ignored by the computer when the program is executed. They are used to provide explanations, notes, or documentation about the code for the programmer's or reader's understanding. Any text following the \"REM\" keyword on the same line is treated as a comment and is not executed by the program. For example:    REM This is a comment explaining the purpose of the following code.  PRINT \"Hello, World!\"    In the example above, the text following \"REM\" is ignored by the program, and only the \"PRINT\" statement is executed.    The other options are incorrect. CLS is a statement that clears the screen. INPUT is a statement that gets input from the user. PRINT is a statement that prints text to the screen.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>23", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of the following  QBASIC  arithmetic operations is the last in order of precedence?", "images": [], "options": {"A": "Addition", "B": "Division", "C": "Exponentiation", "D": "Subtraction"}, "answer": "D", "explanation": "In QBASIC arithmetic operations, the order of precedence determines the sequence in which operations are performed. The operation with the highest precedence is performed first, followed by those with lower precedence. Among the options provided, the arithmetic operation that is last in order of precedence is \"Subtraction.\"    The order of precedence, from highest to lowest, typically follows this sequence:    Exponentiation (^)  Multiplication (*), Division (/), and Integer Division ()  Addition (+), Subtraction (-)    For example, the expression 2 * 3 - 4 is evaluated as follows:    The multiplication is performed first, so 2 * 3 = 6.  The subtraction is performed next, so 6 - 4 = 2.  The final value of the expression is 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>24", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The part labelled Y in the compiler interface in Figure 1 indicates", "images": ["Computer Studies/imgs/2023/2023_comp_two_four.png"], "options": {"A": "intermediate code.", "B": "input code.", "C": "object code.", "D": "stored code."}, "answer": "C", "explanation": "The result of passing the source code of an high level language through a compiler is an object code.    A compiler is a program that converts source code written in a high-level language into machine code, which can be executed by the computer's CPU. The first step in the compilation process is to parse the source code, which means breaking it down into its component parts and identifying the syntax errors. Once the source code has been parsed, the compiler will generate the object code, which is a file that contains the machine instructions that will be executed by the CPU.    The object code is not yet ready to be executed by the CPU. It needs to be linked with other object codes, such as libraries, before it can be run. The linker is a program that combines multiple object codes into a single executable file. The executable file is the final product of the compilation process, and it can be executed by the CPU.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>25", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A program that converts source code instructions in high-level programming language to object codes line by line is known as", "images": [], "options": {"A": "assembler.", "B": "compiler.", "C": "interpreter.", "D": "editor."}, "answer": "C", "explanation": "A program that converts source code instructions in high-level programming language to object codes line by line is known as an interpreter.    An interpreter is a program that executes source code line by line. It does not convert the source code into machine code first. This makes interpreters slower than compilers, but it also makes them more flexible. Interpreters can be used to execute programs that are written in languages that are not supported by compilers.    Compilers, on the other hand, convert source code into machine code before executing it. This makes compilers faster than interpreters, but it also makes them less flexible. Compilers can only be used to execute programs that are written in languages that are supported by the compiler.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>26", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The process of transferring a file from a server to a computer is called", "images": [], "options": {"A": "downloading.", "B": "uploading.", "C": "browsing.", "D": "pinging."}, "answer": "A", "explanation": "The process of transferring a file from a server to a computer is called \"downloading.\"    Downloading involves retrieving data from a remote server and saving it to your local computer or device. It's a common action when you want to obtain files, documents, software, media, or other content from the internet. This content is copied from the server's storage to your computer's storage, enabling you to access and use it locally.    The opposite of downloading is uploading. When you upload a file, you are sending a file from your computer to a server. The server stores the file on its hard drive until it is needed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>27", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The  https  in the web address, https://waec.org.ng, is called a", "images": [], "options": {"A": "file path.", "B": "hostname.", "C": "protocol.", "D": "web page."}, "answer": "C", "explanation": "The \"https\" in the web address \"https://waec.org.ng\" is called a \"protocol.\"    In web addresses (URLs), \"https\" stands for \"Hypertext Transfer Protocol Secure.\" It's a communication protocol used to transmit data securely over the internet. When you access a website with an \"https\" URL, the data exchanged between your browser and the web server is encrypted to ensure privacy and security. This is especially important for transmitting sensitive information like login credentials, payment details, and personal data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>28", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "The transmission method that allows data transmission to multiple computers on a network without addressing all the computers is called", "images": [], "options": {"A": "broadcast.", "B": "multicast.", "C": "switch.", "D": "unicast."}, "answer": "A", "explanation": "The transmission method that allows data transmission to multiple computers on a network without addressing all the computers is called \"broadcast.\"    In a broadcast transmission, data is sent from one source to all devices within the network, and the devices that are not intended to receive the data will still process it. This approach can be efficient for sending the same data to multiple recipients simultaneously but may lead to unnecessary network traffic and can impact network performance.    On the other hand:    \"Multicast\" involves sending data to a specific group of devices that have joined a multicast group. It's more efficient than broadcast because it targets only the interested devices.  \"Switch\" is a network device that forwards data to specific devices based on their MAC addresses, which is more efficient than using broadcast transmissions.  \"Unicast\" refers to the transmission of data from one sender to one receiver, specifically addressing the intended recipient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>29", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "Which of the following  IP  addresses can be used to access a locally running website on a user's computer?", "images": [], "options": {"A": "172.0.0.0", "B": "127.0.0.1", "C": "1.172.0.0", "D": "127.1.0.1"}, "answer": "B", "explanation": "The IP address that can be used to access a locally running website on a user's computer is \"127.0.0.1.\"    The IP address \"127.0.0.1\" is known as the loopback address or localhost. It is used to refer to the user's own computer. When you enter \"127.0.0.1\" in a web browser's address bar, it directs the browser to connect to the local machine itself. This is commonly used for testing and development purposes when you want to access a website or application running on your own computer without going through the internet.    The other IP addresses provided (\"172.0.0.0,\" \"1.172.0.0,\" and \"127.1.0.1\") are not typically used for this purpose and do not have the same loopback behavior as \"127.0.0.1.\"    172.0.0.0 is a private IP address range that is used for local networks.  1.172.0.0 is not a valid IP address.  127.1.0.1 is a loopback address, but it is not the loopback address for the local computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>30", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "An advantage of  bus topology  over  star topology  is that", "images": [], "options": {"A": "it is stronger than star topology.", "B": "it is more expensive than star topology.", "C": "it requires less cable length than star topology.", "D": "its component are easily removed compared to star topology."}, "answer": "C", "explanation": "An advantage of bus topology over star topology is that \"it requires less cable length than star topology.\"    In a bus topology, all devices are connected to a single central cable (the bus), which means that less cabling is required compared to a star topology where each device has its own cable running to a central hub or switch. This can result in cost savings in terms of both cable material and installation.    It's important to note that while bus topology has its advantages, it also has drawbacks, such as potential issues with signal degradation and difficulty in identifying and isolating faults. Each topology has its own set of strengths and weaknesses, and the choice between them depends on factors like the network's size, layout, and specific requirements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>31", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The technology used in the connection in Figure 2 is called", "images": ["Computer Studies/imgs/2023/2023_comp_three_one.png"], "options": {"A": "Bluetooth.", "B": "Infrared.", "C": "Radar.", "D": "Radio wave."}, "answer": "A", "explanation": "The technology used in the connection in Figure 2 is called \"Bluetooth\"    Bluetooth technology is a wireless communication protocol that allows devices to exchange data over short distances. It operates on the 2.4 GHz frequency band and is commonly used for connecting devices like smartphones, laptops, tablets, headphones, speakers, smartwatches, and more.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>32", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "The database model that uses tables with columns and rows is called", "images": [], "options": {"A": "hierarchical database.", "B": "network database.", "C": "relational database.", "D": "linear database."}, "answer": "C", "explanation": "The database model that uses tables with columns and rows is called a \"relational database.\"    In a relational database, data is organized into tables, where each table represents a specific entity or concept. The columns of the table represent attributes or properties of the entity, and each row contains a set of values corresponding to those attributes. The relationships between tables are established through keys, primarily primary keys and foreign keys.    For example, a table that stores customer data might have columns for customer name, address, phone number, and email address. Each row in the table would represent a single customer.    Relational databases are widely used for managing structured data, and they provide a flexible and efficient way to store, retrieve, and manipulate data. The relational model has become one of the most dominant and popular approaches for organizing and managing data in various applications and industries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>33", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Personalized form of letters which can be sent to many people can be achieved using", "images": [], "options": {"A": "macros.", "B": "mail merge.", "C": "query.", "D": "template."}, "answer": "B", "explanation": "Personalized form of letters which can be sent to many people can be achieved using \"mail merge\".    Mail merge is a feature in word processing software that allows you to create a single document that contains personalized information for multiple recipients. For example, you can use mail merge to create a form letter that includes the recipient's name and address.    To use mail merge, you first need to create a template document that contains the static content of the letter. This might include the letterhead, the body of the letter, and the signature block. You then need to create a data source that contains the recipient information. This might be a spreadsheet or a database.    Once you have created the template document and the data source, you can use mail merge to create the personalized letters. To do this, you simply select the mail merge options in your word processing software and then follow the prompts.    Mail merge is a very efficient way to create personalized letters. It can save you a lot of time and effort, and it ensures that your letters are accurate and consistent", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>34", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "The following are functions of database management system except", "images": [], "options": {"A": "backup and replication.", "B": "format operation.", "C": "rule enforcement.", "D": "security of data."}, "answer": "B", "explanation": "The following are functions of a database management system (DBMS).    Backup and replication: A DBMS can be used to backup and replicate databases. This means that the database can be copied to a different location or to multiple locations. This is important for disaster recovery purposes.  Rule enforcement: A DBMS can be used to enforce rules on data. This means that the DBMS can be used to prevent users from entering invalid data or from making changes to data that they are not authorized to change.  Security of data: A DBMS can be used to secure data. This means that the DBMS can be used to encrypt data, to restrict access to data, and to audit access to data.    Format operation is not a function of a DBMS. A format operation is the process of converting data from one format to another. This is not something that a DBMS typically does.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>35", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Which of the following actions is not an animation in Microsoft PowerPoint?", "images": [], "options": {"A": "Dancing", "B": "Emphasis", "C": "Entrance", "D": "Motion paths"}, "answer": "A", "explanation": "The action \"Dancing\" is not an animation in Microsoft PowerPoint.    In Microsoft PowerPoint, animations are used to add movement and visual effects to slides and their content during a presentation. The other actions you mentioned, namely \"Emphasis,\" \"Entrance,\" and \"Motion paths,\" are types of animations that you can apply to elements on your slides to enhance your presentation.    \"Dancing\" is not a predefined animation effect in PowerPoint. However, you can use various animation effects like \"Emphasis,\" \"Entrance,\" and \"Motion paths\" to create dynamic and engaging presentations by making text, images, and other elements appear, move, or change in ways that capture your audience's attention.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>36", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Headers and footers are used in Microsoft Word documents to", "images": [], "options": {"A": "make large document more readable.", "B": "allow test to appear at the top of the first page.", "C": "enhance the overall appearance of the document.", "D": "allow text to appear at the top and bottom of every page."}, "answer": "D", "explanation": "Headers and footers are used in Microsoft Word documents to \"allow text to appear at the top and bottom of every page.\"    Headers are sections of the document that appear at the top of each page, and footers appear at the bottom of each page. They provide a way to include consistent information such as page numbers, document titles, author names, dates, and other important details that you want to appear on every page of the document. Headers and footers enhance the professional appearance and consistency of a document, especially for larger documents or reports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>37", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "If today's date is 02/02/2008, what will be the result of typing \"=today() - 1\" in a cell of a spreadsheet?", "images": [], "options": {"A": "02/01/2008", "B": "01/02/2009", "C": "01/02/2008", "D": "02/02/2007"}, "answer": "A", "explanation": "If today's date is 02/02/2008, the result of typing \"=today() - 1\" in a cell of a spreadsheet will be \"02/01/2008\".    The today() function in Excel returns the current date. The - 1 operator subtracts one from the result of the today() function. Therefore, the expression =today() - 1 will return the date that is one day before the current date.    In this case, the current date is 02/02/2008. Subtracting one from this date gives us 02/01/2008.    NB: By default, Excel uses the mm/dd/yyyy format for dates. This means that the month is represented by the first two digits, the day is represented by the third digit, and the year is represented by the last four digits. The date format in Excel can be customized to suit your needs.    However, you can change the date format to something else if you prefer. For example, you could change the date format to dd/mm/yyyy, which would represent the day, month, and year in that order.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>38", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The usage of the keys  CTRL + W  in Ms Word", "images": [], "options": {"A": "saves the current file.", "B": "opens the print dialogue box.", "C": "closes the current window.", "D": "updates the current web page."}, "answer": "C", "explanation": "The usage of the keys \"CTRL + W\" in Microsoft Word is to \"close the current window.\"    When you press \"CTRL + W\" in Microsoft Word, it closes the currently active document window. This action doesn't save the document if changes have been made; it simply closes the window. If there are unsaved changes, Word will prompt you to save before closing. This keyboard shortcut is used to quickly close documents and is commonly found in many applications to close active windows or tabs.    To close the current window using Ctrl + W, simply press and hold the Ctrl key and then press the W key. The current window will be closed immediately.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>39", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Stored instructions and data in digital computer consist of", "images": [], "options": {"A": "alphabets.", "B": "numerals.", "C": "characters.", "D": "bits."}, "answer": "D", "explanation": "Stored instructions and data in a digital computer consist of \"bits.\"    A bit is the smallest unit of information in a digital computer. It can be either a 0 or a 1. Bits are combined to form bytes, which are used to represent characters, numbers, and instructions.    Alphabets, numerals, and characters are all represented by bits in a digital computer. For example, the letter \"A\" can be represented by the bits 01000001, the number \"1\" can be represented by the bits 00000001, and the character \"@\" can be represented by the bits 01001000.    The instructions that a computer follows are also stored as bits. These instructions tell the computer what to do, such as add two numbers, print a message, or open a file.    Bits are the foundation of all data and instructions in a digital computer. Without bits, computers would not be able to function.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>40", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "During the booting process in Windows, the  Master Boot Record  is loaded by the", "images": [], "options": {"A": "BIOS .", "B": "GRUB .", "C": "Init.", "D": "Kernel."}, "answer": "A", "explanation": "During the booting process in Windows, the Master Boot Record (MBR) is loaded by the \"BIOS\" (Basic Input/Output System).    The MBR is a small piece of code that is stored at the beginning of a hard drive. It is responsible for loading the operating system into memory. When the computer boots up, the BIOS first checks the MBR to see if it is bootable. If it is, the BIOS will load the operating system into memory.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>41", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A  BIOS  configuration program that allows a windows user to configure attributes such as password, time and date is called", "images": [], "options": {"A": "BIOS  drivers.", "B": "Bootstrap.", "C": "CMOS  setup.", "D": "GRUB ."}, "answer": "C", "explanation": "A BIOS configuration program that allows a Windows user to configure attributes such as password, time, and date is called \"CMOS setup.\"    CMOS (Complementary Metal-Oxide-Semiconductor) setup is a utility that lets users access and modify various settings stored in the CMOS chip on the computer's motherboard. These settings include system configuration options such as the system clock, date, passwords, boot order, and hardware settings. CMOS setup provides a way to customize system settings at a low level and is typically accessed during the computer's boot process by pressing a specific key (often Del, F2, or another designated key) as indicated on the screen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>42", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "The speed of data transfer can be affected by the following factors except", "images": [], "options": {"A": "address bus width.", "B": "broadband status.", "C": "clock speed.", "D": "data bus width."}, "answer": "B", "explanation": "The speed of data transfer can be affected by the following factors except \"broadband status.\"    The factors listed in the options can indeed affect the speed of data transfer in a computer system:    Address Bus Width: The width of the address bus determines the maximum memory capacity that the system can access. It indirectly affects data transfer speed by allowing more efficient access to memory locations.    Clock Speed: The clock speed of the CPU determines how many instructions the CPU can execute per second. A higher clock speed generally leads to faster data processing.    Data Bus Width: The width of the data bus affects the amount of data that can be transferred between the CPU and memory in a single bus cycle. A wider data bus can transfer more data at once.    However, \"broadband status\" is not typically a factor that directly affects the speed of data transfer within a computer system. Broadband status is more related to network connectivity and internet speed, not internal data transfer within a computer's components.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>43", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The radix of hexadecimal number system is", "images": [], "options": {"A": "2.", "B": "8.", "C": "10.", "D": "16."}, "answer": "D", "explanation": "The radix of the hexadecimal number system is \"16.\"    In a number system, the radix (also known as the base) indicates the number of unique symbols used to represent values in that system. The hexadecimal number system uses 16 distinct symbols (0-9 and A-F) to represent values. Each digit in a hexadecimal number corresponds to a power of 16, similar to how each digit in a decimal number corresponds to a power of 10.    The hexadecimal number system is often used in computer science because it is a convenient way to represent binary numbers. A hexadecimal number can be used to represent 4 binary digits (bits) at a time. This makes it easier to read and write binary numbers.    For example, the binary number 10100001 can be represented as the hexadecimal number A1. This is because 10100001 in binary is equal to A1 in hexadecimal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2023>44", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Machine language instruction codes are expressed in", "images": [], "options": {"A": "ASCII .", "B": "binary.", "C": "EBCDIC .", "D": "hexadecimal."}, "answer": "B", "explanation": "Machine language instruction codes are expressed in \"binary.\"    Machine language is the lowest level of programming language that a computer can understand. It is a series of binary digits (bits) that tell the computer what to do. Each instruction in machine language is a sequence of 8 bits, called a byte.    The bits in a machine language instruction code represent different things. For example, some bits might represent the operation that the computer should perform, while others might represent the operands of the operation.    Binary is the only language that the computer can understand directly. Therefore, machine language instruction codes are always expressed in binary.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>45", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "In binary, the decimal number 28 is represented as", "images": [], "options": {"A": "10012", "B": "110012", "C": "110112", "D": "111002"}, "answer": "D", "explanation": "228214 rem 027 rem 023 rem 121 rem 10 rem 1  ∴ The decimal number 28 is represented as 111002", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>46", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "A file organization in which the records are stored in the order in which they occur is called", "images": [], "options": {"A": "indexed file.", "B": "random file.", "C": "serial file.", "D": "sequential file."}, "answer": "D", "explanation": "A file organization in which the records are stored in the order in which they occur is called \"sequential file\"    In a sequential file, records are stored in the order in which they occur. This means that the first record is stored at the beginning of the file, the second record is stored after the first record, and so on. To access a record in a sequential file, the computer must start at the beginning of the file and read each record until it finds the one that it is looking for.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>47", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "The following are effects of file insecurities except", "images": [], "options": {"A": "data overwriting.", "B": "data loss.", "C": "data use.", "D": "file corruption."}, "answer": "C", "explanation": "The effect of \"data use\" is not considered an effect of file insecurities.    The other options are all possible effects of file insecurities. Data overwriting can occur when a file is overwritten with new data, which can result in the loss of the original data. Data loss can occur when a file is deleted or corrupted, which can make it impossible to access the data. File corruption can occur when a file is damaged, which can make it unreadable or unusable.    However, data use is not an effect of file insecurity. Data use is simply the act of accessing and using data. It can occur even if a file is secure. For example, a user can access and use a file even if it is password protected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>48", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "The process of making copies of files which can be used to restore the original copy in the event of data loss is called file", "images": [], "options": {"A": "backup.", "B": "organization.", "C": "restoration.", "D": "retrieval."}, "answer": "A", "explanation": "The process of making copies of files which can be used to restore the original copy in the event of data loss is called \"backup.\"    File backup is the process of making copies of files which can be used to restore the original copy in the event of data loss. This is an important process for protecting your data from accidental deletion, corruption, or hardware failure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>49", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The act of translating data into a secret code is known as", "images": [], "options": {"A": "authentication.", "B": "authorization.", "C": "encryption.", "D": "piracy."}, "answer": "C", "explanation": "The act of translating data into a secret code is known as \"encryption\".    Authentication is the process of verifying the identity of a user or device. Authorization is the process of granting permissions to a user or device to access certain resources. Piracy is the unauthorized use or reproduction of copyrighted material.    Encryption is a security technique that converts data into a secret code so that it cannot be read by unauthorized users. The code is only readable by someone who has the decryption key. Encryption is used to protect data from unauthorized access, disclosure, modification, or destruction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2023>50", "subject": "Computer Studies", "year": "2023", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Viruses, worms and Trojan horses are regarded as", "images": [], "options": {"A": "application software.", "B": "malicious software.", "C": "utility software.", "D": "system software."}, "answer": "B", "explanation": "Viruses, worms, and Trojan horses are regarded as \"malicious software\" or \"malware.\"    These terms refer to different types of software that are designed to disrupt, damage, or gain unauthorized access to computer systems, networks, or data. Here's a brief explanation of each:    Viruses: Viruses are programs that attach themselves to legitimate files or software and spread when those files are executed. They can cause a range of issues, from annoying pop-ups to data corruption.    Worms: Worms are self-replicating programs that can spread over computer networks without the need for user intervention. They exploit vulnerabilities to spread and can consume network resources.    Trojan Horses (Trojans): Trojans are programs that appear harmless but have malicious intent. They often trick users into running them, leading to unauthorized access, data theft, or other harmful actions.    These forms of malware can cause significant harm to computer systems and data, which is why it's important to have effective antivirus and security measures in place to protect against them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>1", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "An automatic system is one that", "images": [], "options": {"A": "is operated using sophisticated skills", "B": "needs fuel before it can be operated by humans", "C": "performs different kinds of tasks diligently", "D": "requires little or no human intervention to work"}, "answer": "D", "explanation": "An automatic system is one that operates independently, without human intervention, once it is set in motion. It performs tasks on its own, without the need for continuous human control or input.  Automatic systems are designed to reduce human labor, increase efficiency, and improve accuracy, making them essential in various industries, such as manufacturing, transportation, and healthcare.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>2", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following features of information is not important for meaningful decision?", "images": [], "options": {"A": "Accuracy", "B": "Competitiveness", "C": "Completeness", "D": "Timeliness"}, "answer": "B", "explanation": "Competitiveness is not a feature of information itself, but rather a aspect of business or organizational strategy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>3", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The microprocessor that controls a washing machine is known as:", "images": [], "options": {"A": "bot", "B": "console", "C": "embedded computer", "D": "mainframe computer"}, "answer": "C", "explanation": "An embedded computer is a small, specialized computer system that is built into a device or system to control its functions. In the case of a washing machine, the embedded computer controls the machine's cycles, temperature, and other functions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>4", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following statements is correct about data?", "images": [], "options": {"A": "Information is a product of data while knowledge is a product of information", "B": "Data produces knowledge while knowledge produces information", "C": "Data is a product of information while knowledge is a product of data", "D": "Knowledge produces information while information produces data"}, "answer": "A", "explanation": "The correct sequence is:    Data → Information → Knowledge    Data is processed and organized to create information, which is then analyzed and applied to gain knowledge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>5", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS~~INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Instructions were written to the first generation computers in", "images": [], "options": {"A": "assemblers", "B": "low level language", "C": "machine language", "D": "mnemonics"}, "answer": "C", "explanation": "The first generation computers (1940s-1950s) were programmed using machine language, which consists of binary code (0s and 1s) that the computer's processor can execute directly. Programmers had to write instructions using machine language, which was a tedious and error-prone process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>6", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Addition and subtraction of numbers in Abacus are done using", "images": [], "options": {"A": "bars", "B": "beads", "C": "frame", "D": "string"}, "answer": "B", "explanation": "An Abacus is a traditional calculating tool used for arithmetic calculations. It consists of a frame with rows of beads on wires. The beads are used to represent numbers and perform calculations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>7", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "In the slide rule, multiplication that goes off the scale can be corrected by the following approaches except", "images": [], "options": {"A": "resetting the slide", "B": "using circular slide rule", "C": "using flat scales", "D": "using folded scales"}, "answer": "C", "explanation": "using flat scales is not a method to correct multiplication that goes off the scale on a slide rule.    Here are the methods that can be used:    Resetting the slide: If the product goes off the scale on one side, you can often reset the slide and continue the calculation on the other side.  Using a circular slide rule: Circular slide rules can handle larger numbers and calculations that might go off the scale on a flat slide rule.  Using folded scales: Some slide rules have folded scales that allow for calculations with larger numbers.  Therefore, using flat scales is not a valid approach for correcting multiplication that goes off the scale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>8", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The computer's short-term memory is the", "images": [], "options": {"A": "arithmetic logic unit", "B": "arithmetic operator", "C": "control unit", "D": "random access memory"}, "answer": "D", "explanation": "Random Access Memory (RAM) is the computer's short-term memory, where data and program instructions are stored temporarily while being processed. RAM allows the computer to access and manipulate data quickly, but its contents are lost when the computer is powered off.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>9", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "LOGIC GATES", "question": "Which of the following logic devices is considered as  equivalent gate ?", "images": [], "options": {"A": "AND", "B": "EX-NOR", "C": "EX-OR", "D": "NOR"}, "answer": "B", "explanation": "EX-NOR is considered an equivalent gate.    An equivalent gate is a logic gate that can perform the same function as another gate or combination of gates. The EX-NOR (Exclusive NOR) gate is equivalent to the AND gate followed by a NOT gate. In other words, the output of an EX-NOR gate is 1 only when both inputs are the same (either both 0 or both 1). This is the same behavior as an AND gate followed by a NOT gate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>10", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "LOGIC GATES", "question": "Use the devices in Figure 1 and Figure 2 to answer questions 10 to 13. given that the input variables X and Y have values of 0011 and 0101 respectively as shown on Table 1            Compute the value of the output Z in Figure 1 using the values of X and Y given.", "images": ["Computer Studies/imgs/2024/2JMCNC.jpg", "Computer Studies/imgs/2024/TJG2FL.jpg"], "options": {"A": "0001", "B": "0110", "C": "0111", "D": "1000"}, "answer": "C", "explanation": "The gate is OR Gate    XYZ = X + Y000011101111", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2024>11", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "LOGIC GATES", "question": "Use the devices in Figure 1 and Figure 2 to answer questions 10 to 13. given that the input variables X and Y have values of 0011 and 0101 respectively as shown on Table 1            If the input variable X in Figure 1 is passed through the device in Figure 2 before going into the logic gate in Figure 1, what will be the value of the output Z?", "images": ["Computer Studies/imgs/2024/2JMCNC.jpg", "Computer Studies/imgs/2024/TJG2FL.jpg"], "options": {"A": "0111", "B": "1011", "C": "1101", "D": "1110"}, "answer": "C", "explanation": "The gate in Figure 2 is NOT gate. When X passes through it, X becomes:   X  = 1100    XY X Z =  X  + Y0011011110001101", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2024>12", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "LOGIC GATES", "question": "Use the devices in Figure 1 and Figure 2 to answer questions 10 to 13. given that the input variables X and Y have values of 0011 and 0101 respectively as shown on Table 1            If the input variable Y in Figure 1 is passed through the device in Figure 2 before going into the logic gate in Figure 1, compute the resulting output Z?", "images": ["Computer Studies/imgs/2024/2JMCNC.jpg", "Computer Studies/imgs/2024/TJG2FL.jpg"], "options": {"A": "0111", "B": "1011", "C": "1101", "D": "1110"}, "answer": "B", "explanation": "NOT Y = 1010  X +  Y  = 0011 + 1010    XY Y Z = X +  Y 0011010010111101", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2024>13", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "LOGIC GATES", "question": "Use the devices in Figure 1 and Figure 2 to answer questions 10 to 13. given that the input variables X and Y have values of 0011 and 0101 respectively as shown on Table 1            Using the given values X and Y for the device in Figure 1, what will be the output Z if it is passed through the device in Figure 2", "images": ["Computer Studies/imgs/2024/2JMCNC.jpg", "Computer Studies/imgs/2024/TJG2FL.jpg"], "options": {"A": "0001", "B": "0110", "C": "0111", "D": "1000"}, "answer": "D", "explanation": "X + Y = Z  0011 + 0101 = 0111  If the result is passed through the NOT gate, it becomes:   Z  = 1000    XYZ = X + Y Z 0001011010101110", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2024>14", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The part labelled Q in Figure 3 is called", "images": ["Computer Studies/imgs/2024/JRLXLP.jpg"], "options": {"A": "control unit", "B": "data bus", "C": "memory unit", "D": "register"}, "answer": "D", "explanation": "A register is a small, high-speed storage unit within a computer's central processing unit (CPU) that is used to hold data temporarily during calculations or other operations. Registers are made up of a series of flip-flops, which are electronic circuits that can store a single bit of data (0 or 1).", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>15", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "MS Access is an example of", "images": [], "options": {"A": "word processing package", "B": "spreadsheet application", "C": "graphic software", "D": "database management system"}, "answer": "D", "explanation": "Microsoft Access (MS Access) is a database management system (DBMS) that allows users to create, design, and manage databases. It provides a graphical interface to create tables, forms, queries, and reports, making it a powerful tool for managing and analyzing data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>16", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Which of the following statements explains the function of device drivers? They", "images": [], "options": {"A": "convert source code to object code.", "B": "enable hardware and software control and manage the system", "C": "help to clean disk space and manage", "D": "help to improve the functionality of hardware devices"}, "answer": "D", "explanation": "Device drivers are software components that allow hardware devices to communicate with the operating system and other software applications. They act as translators between the hardware and software, enabling the hardware to function properly and providing features such as:    - Controlling hardware operations  - Managing data transfer between hardware and software  - Providing hardware-specific functionality  - Enhancing hardware performance", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>17", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "One usefulness of utility software in the computer is", "images": [], "options": {"A": "conversion of source code to object code", "B": "enhancement of communication between hardware and the computer system", "C": "removal of malware from the computer", "D": "to improve the functionality of hardware devices"}, "answer": "C", "explanation": "Utility software refers to programs that perform maintenance, optimization, and other tasks to keep a computer running smoothly. Some common examples of utility software include:    - Antivirus programs (e.g., Norton Antivirus) that remove malware and protect against future infections  - Disk cleanup tools (e.g., CCleaner) that free up space on the hard drive  - Disk formatting tools (e.g., fdisk) that prepare hard drives for use  - System monitoring tools (e.g., Task Manager) that display system performance and resource usage", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>18", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Which of the following statements about operating systems is false? It", "images": [], "options": {"A": "enhances the booting process", "B": "manages computer devices", "C": "manages storage location", "D": "protects the computer from storage"}, "answer": "D", "explanation": "Operating systems (OS) perform various functions, including:    - Managing computer devices (C)  - Managing storage locations (C)  - Enhancing the booting process (A)  - Providing security features to protect the computer from malware, unauthorized access, and other threats (but not specifically from storage)    The correct statement would be \"protects the computer from malware and unauthorized access\", but not \"from storage\".    Storage refers to the hardware components that store data, such as hard drives, solid-state drives, and flash drives. Operating systems manage storage locations, but they do not protect the computer from storage itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>19", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "Debugging in program development is the process of", "images": [], "options": {"A": "fixing errors", "B": "Introducing bugs", "C": "removing virus", "D": "writing error messages"}, "answer": "A", "explanation": "Debugging is the process of identifying, isolating, and fixing errors or bugs in a program or software. It involves:    - Finding the source of the error  - Understanding the cause of the error  - Correcting the error  - Testing the program to ensure the error is resolved    Debugging is an essential step in the program development process, ensuring that the software runs correctly, efficiently, and reliably.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>20", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "Figure 4 is a flowchart symbol. Use it to answer questions 20 and 21        Identify the flowchart symbol in Figure 4", "images": ["Computer Studies/imgs/2024/Y8G6YM.jpg"], "options": {"A": "Decision box", "B": "Manual input", "C": "Preparation", "D": "Process"}, "answer": "A", "explanation": "In flowcharts, the symbol used for a decision box is a diamond.    A diamond represents a decision point where the flow can branch based on a \"yes/no\" or \"true/false\" question.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>21", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "Figure 4 is a flowchart symbol. Use it to answer questions 20 and 21      The flowchart symbol in Figure 4 is used to", "images": ["Computer Studies/imgs/2024/Y8G6YM.jpg"], "options": {"A": "show the preparation stage", "B": "represent a decision-making point", "C": "input data manually in a flowchart", "D": "execute a process"}, "answer": "B", "explanation": "The flowchart symbol represent a decision-making point.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>22", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "Which of the following operations will be executed last in a program", "images": [], "options": {"A": "Addition", "B": "Division", "C": "Exponentiation", "D": "Subtraction"}, "answer": "D", "explanation": "In programming, the order of operations follows the standard mathematical precedence rules, often remembered by the acronym PEMDAS (Parentheses, Exponents, Multiplication and Division, Addition and Subtraction).", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>23", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "The equation x = p + q(r &#247;  s) can be expressed in QBASIC programming as", "images": [], "options": {"A": "X = P + Q * (RS)", "B": "X = P + Q * (R/S)", "C": "X = P + Q (R/S)", "D": "X = P + Q (RS)"}, "answer": "B", "explanation": "The equation x = p + q(r ÷ s) can be expressed in QBASIC programming as:    X = P + Q * (R/S)", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2024>24", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "Which of the following statements is true about the rules of flowcharting?", "images": [], "options": {"A": "All boxes of flowcharts are connected with arrows to show the logical connection between them", "B": "All flowchart process boxes are connected with on page connector to show the flow of operation", "C": "All flowcharts start with a start box and end with a decision box", "D": "The flow of control must always enter an object from bottom to top"}, "answer": "A", "explanation": "All boxes of flowcharts are connected with arrows to show the logical connection between them.    Flowcharting rules:    - Use standardized symbols (e.g., rectangles, diamonds, ovals)  - Connect symbols with arrows to show logical connections and flow  - Use one entry and one exit point (except for loops)  - Avoid crossing arrows or lines  - Keep it simple, clear, and concise", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>25", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "In computer programming, it is advised to translate source code into intermediate code to", "images": [], "options": {"A": "change the analysis portion for different compilers", "B": "ensure that full native compiler is used for every new machine that will run the program", "C": "make it easier to apply the source code modifications to improve code performance", "D": "make the synthesis part of the compiler target-machine dependent"}, "answer": "D", "explanation": "In compiler design:    Intermediate code is used to create a machine-independent layer between the source code and the final machine code.    Analysis (or the front-end) of the compiler, which includes tasks like lexical analysis, parsing, and semantic analysis, produces this intermediate code. This part is machine-independent, meaning it doesn't need to change for different target machines.    The synthesis (or the back-end) of the compiler then takes this intermediate code and translates it into machine code specific to the target machine. This part is machine-dependent.    The use of intermediate code allows the front-end of the compiler to remain consistent across different platforms, while the back-end (synthesis) is adapted to generate machine-specific code.    So, the correct answer (\"make the synthesis part of the compiler target-machine dependent\") refers to the fact that the synthesis, or the code generation phase, is tailored to the specific machine, while the analysis part remains independent of the machine.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2024>26", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "A graphic or text in a document or webpage that links to another file or object is referred to as", "images": [], "options": {"A": "a domain name", "B": "a hyperlink", "C": "a shortcut", "D": "an icon"}, "answer": "B", "explanation": "A hyperlink is a graphic or text in a document or webpage that links to another file, object, or webpage. It allows users to click on the link to access the connected resource. Hyperlinks are a fundamental feature of the internet, enabling navigation between web pages and access to related information.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>27", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Instant messages can be sent with little or no time lag using", "images": [], "options": {"A": "podcast", "B": "facsimile", "C": "email", "D": "chat room"}, "answer": "D", "explanation": "Chat rooms, also known as instant messaging (IM) or real-time messaging, allow users to send text messages in real-time, with little to no time lag. This enables instantaneous communication and conversation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>28", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Which of the following statements is true about preventing phishing", "images": [], "options": {"A": "Ensure that antivirus is updated regularly", "B": "Do not click on links in emails from untrusted sources", "C": "Do not download from untrusted sites", "D": "Use a strong password at all times"}, "answer": "B", "explanation": "Do not click on links in emails from untrusted sources.    Phishing is a type of cybercrime that involves tricking individuals into revealing sensitive information such as passwords, credit card numbers, or other personal information. To prevent phishing, it's essential to:    - Be cautious with links in emails from untrusted sources  - Verify the authenticity of emails before taking any action  - Use two-factor authentication whenever possible  - Keep software and security up to date (including antivirus)", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>29", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Which of the following statements is true about star topologies?", "images": [], "options": {"A": "Computers are connected node-to-node", "B": "Computers are connected to a central device", "C": "The connection is linear in shape", "D": "The connection is a tree-like structure"}, "answer": "B", "explanation": "Computers are connected to a central device.    In a star topology, all devices (computers, nodes, etc.) are connected to a central device, such as a hub, switch, or router. This central device acts as a connection point for all the other devices, and all data transmission goes through it.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>30", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "An internet user secures his social media account by regularly changing passwords. Which of the following passwords produces the best security?", "images": [], "options": {"A": "wasscesc2024", "B": "WASSCESC2024", "C": "2024wasscesc", "D": "WASSCESchoolCandidates@2024"}, "answer": "D", "explanation": "The correct answer is WASSCESchoolCandidates@2024.    This password is the strongest because it:    - Is long (over 12 characters)  - Contains a mix of:      - Uppercase letters (W, S, C)      - Lowercase letters (s, c, h, o, o, l)      - Numbers (2, 0, 2, 4)      - Special characters (@)  - Does not contain personal information (name, birthdate, etc.)  - Does not contain common words or phrases  - Is not a variation of a previous password", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>31", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Which of the following statements is true about intranet?", "images": [], "options": {"A": "Private network that uses internet protocol and is accessible by all visitors to an organization's website", "B": "Private network that uses internet protocol and is accessible by employees of an organization", "C": "Private network which does not use internet protocol and is accessible by employees of an organization", "D": "Public network that uses internet protocol and is accessible by all visitors to an organization's website"}, "answer": "B", "explanation": "Private network that uses Internet protocol and is accessible by employees of an organisation.    An intranet is a private network that uses Internet protocols (TCP/IP, HTTP, etc.) to share information and resources within an organization. It is accessible only to authorized employees, partners, or stakeholders, and is not publicly accessible through the Internet.    Intranets are used for various purposes, such as:    - Sharing company information and news  - Collaborating on projects and documents  - Providing access to company resources and tools  - Facilitating communication and feedback", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>32", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The art of checking for errors in a Word Document before publishing is referred to as", "images": [], "options": {"A": "editing", "B": "formatting", "C": "modifying", "D": "proof reading"}, "answer": "D", "explanation": "Proofreading is the process of carefully reviewing a document, such as a Word document, for errors in:    - Spelling  - Grammar  - Punctuation  - Syntax  - Formatting  - Consistency    before publishing or sharing it. The goal of proofreading is to ensure that the document is error-free, accurate, and polished.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>33", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Columns in MS Access are referred to as", "images": [], "options": {"A": "Fields", "B": "Files", "C": "Records", "D": "Tuples"}, "answer": "A", "explanation": "In Microsoft Access, columns in a table are referred to as Fields. Fields define the structure of a table and represent a single aspect of the data being stored, such as \"Employee ID\", \"Name\", \"Department\", etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>34", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Which of the following application packages is suitable for making budgets", "images": [], "options": {"A": "Word Processor", "B": "Spreadsheet package", "C": "Graphic package", "D": "Database Management System"}, "answer": "B", "explanation": "A spreadsheet package, such as Microsoft Excel or Google Sheets, is ideal for creating budgets because it allows you to:    - Enter and manipulate numerical data  - Perform calculations and formulas  - Create tables and charts to visualize data  - Easily update and modify data    Spreadsheet software is designed for numerical analysis and data management, making it perfect for budgeting, financial planning, and data analysis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>35", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "What happens when a user clicks on the icon in Figure 5 in the Microsoft Excel Menu Bar?", "images": ["Computer Studies/imgs/2024/298NP6.jpg"], "options": {"A": "A copy of the selection is put on the clipboard so that user can paste it somewhere else", "B": "A label that spans multiple columns is created", "C": "Content on the clipboard is added to the document", "D": "Selected range of cells is quickly converted to a table with its own style"}, "answer": "C", "explanation": "The Paste icon in Excel is a clipboard symbol, often represented by a clipboard with a sheet of paper on it. It is used to insert copied or cut data into a selected cell or range of cells.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>36", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "New Comment can be added to a cell in MS Excel using", "images": [], "options": {"A": "Edit &#8594; Comment", "B": "File &#8594; Comment", "C": "Insert &#8594; Comment", "D": "Review &#8594; Comment"}, "answer": "D", "explanation": "To add a new comment to a cell in MS Excel, you can follow these steps:    1. Select the cell where you want to add the comment.  2. Go to the Review tab in the ribbon.  3. Click on the \"New Comment\" button in the \"Comments\" group.  4. Type your comment in the text box that appears.    Alternatively, you can also right-click on the cell and select \"Insert Comment\" from the context menu.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>37", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "What is the function of the CorelDraw Toolbox object shown in Figure 6? It is used to", "images": ["Computer Studies/imgs/2024/MYF4WL.jpg"], "options": {"A": "change the magnification level in drawing window", "B": "draw lines and curves", "C": "edit the shape of objects", "D": "select and transform objects"}, "answer": "D", "explanation": "The move tool in CorelDRAW is a powerful and versatile tool that allows you to select, move, resize, rotate, and apply various transformations to objects in your design. It's a combination of several tools, making it a convenient one-stop solution for many common tasks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>38", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Which of the following statements about index is true? It is a data structure", "images": [], "options": {"A": "that reduces the speed of data retrieval operations on a database table", "B": "used to quickly locate data without searching every row in a table every time a database table is accessed", "C": "created using only two rows of a database table to uniquely identify each record", "D": "that allows relational database to split and store data in different tables while linking disparate items"}, "answer": "B", "explanation": "It is a data structure that enables quick location of data without searching every row in a table every time a database table is accessed.    This statement is true because an index in a database allows for fast lookup and retrieval of data without having to scan the entire table, making queries more efficient.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>39", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A collection of computer wires used to identify memory location in a computer is", "images": [], "options": {"A": "system bus", "B": "data bus", "C": "data cable", "D": "address bus"}, "answer": "D", "explanation": "An address bus is a collection of computer wires used to identify memory locations in a computer. It carries the addresses of memory locations that the CPU (Central Processing Unit) wants to access, allowing the computer to retrieve or store data in the corresponding memory locations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>40", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Read Only Memory (ROM) contains", "images": [], "options": {"A": "current program in operation", "B": "preset instructions for operation", "C": "user instructions", "D": "volatile programs"}, "answer": "B", "explanation": "ROM (Read-Only Memory) contains permanent, preset instructions that are programmed during the manufacturing process and cannot be changed or written by a user. These instructions are used to control the basic operation of a computer or device, such as the BIOS (Basic Input/Output System) in a computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>41", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "What happens when the Shift key is pressed down while deleting a file from the computer. The file is", "images": [], "options": {"A": "Uninstalled from the computer", "B": "permanently deleted from the computer", "C": "deleted and sent to the Recycle Bin", "D": "deleted and kept in the clipboard"}, "answer": "B", "explanation": "When you press the Shift key while deleting a file (by clicking \"Delete\" or pressing \"Delete\" on your keyboard), the file will be permanently deleted from your computer, bypassing the Recycle Bin. This means that the file will not be moved to the Recycle Bin, where it can be recovered, but will instead be immediately removed from your system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>42", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Which of the following statements about warm booting is true? The computer", "images": [], "options": {"A": "reloads the operating system while still running in the background", "B": "loads the operating system into memory from the power-on button", "C": "reloads the operating system into memory while still loading", "D": "loads the application into memory from rest state"}, "answer": "A", "explanation": "Reloads the operating system while still running in the background.    Warm booting, also known as soft booting, is the process of restarting a computer without turning off the power. This means that the computer's operating system is reloaded while the computer is still running, without going through the full shutdown and startup process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>43", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The  ASCII  character set that represents alphabetical and control characters using numeric code ranges from", "images": [], "options": {"A": "0 to 32", "B": "0 to 64", "C": "0 to 127", "D": "0 to 128"}, "answer": "C", "explanation": "ASCII (American Standard Code for Information Interchange) is a character encoding standard that represents alphabetical, numerical, and control characters using numeric codes. The ASCII character set ranges from 0 to 127, inclusive.    - 0 to 31: Control characters (e.g., tab, newline, bell)  - 32 to 126: Printable characters (letters, digits, punctuation marks, etc.)  - 127: Delete character (a special control character)", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>44", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following hard disk drive memory capacities can store the largest size of data", "images": [], "options": {"A": "2 TB", "B": "12 GB", "C": "240 MB", "D": "800 KB"}, "answer": "A", "explanation": "2TB can store the largest size of data among the given options.    Here's a breakdown of the units:    Terabyte (TB): The largest unit among the options, representing 1 trillion bytes.     Gigabyte (GB): 1 billion bytes.     Megabyte (MB): 1 million bytes.     Kilobyte (KB): 1 thousand bytes.       Therefore, 2TB is the largest storage capacity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>45", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The equivalent of the letter A in the standard ASCII is", "images": [], "options": {"A": "01000001", "B": "01000010", "C": "01100001", "D": "01100010"}, "answer": "A", "explanation": "In the standard ASCII (American Standard Code for Information Interchange) character set, the letter \"A\" is represented by the binary code 01100001.    Here's a brief explanation:    - ASCII uses 7-bit binary codes to represent characters.  - The letter \"A\" is the 65th character in the ASCII table.  - The binary representation of 65 in 7-bit form is 01100001.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>46", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "One example of a file containing reference data which is usually altered is", "images": [], "options": {"A": "brand name", "B": "payroll", "C": "price list", "D": "stock"}, "answer": "C", "explanation": "A price list is a type of reference data file that is commonly updated or altered as prices change over time. It contains a list of items or services with their corresponding prices, and is often used in business and commerce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>47", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION~~INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Figure 7 represents a procedure to", "images": ["Computer Studies/imgs/2024/HCPMGJ.jpg"], "options": {"A": "backup files on the computer", "B": "repair a corrupted file on a computer", "C": "transfer files from one device to another", "D": "update software on a device"}, "answer": "C", "explanation": "The figure represents the procedure of transfer of files through bluetooth from a PC to an Android phone and vice versa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>48", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "A user observed that a certain file in a removable storage device changed to a shortcut icon. This implies that", "images": [], "options": {"A": "the file is corrupt", "B": "the file is shared", "C": "the removable storage device is corrupt", "D": "there is a link to the file"}, "answer": "D", "explanation": "When a file icon changes to a shortcut icon, it usually indicates that there's a link (or shortcut) pointing to the original file. This link can be located on the same device or on a different device. The shortcut allows you to quickly access the original file without having to navigate to its actual location.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2024>49", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Set of characters used to authenticate a computer user is called", "images": [], "options": {"A": "encoder", "B": "binary code", "C": "password", "D": "barcode"}, "answer": "C", "explanation": "A password is a set of characters used to authenticate a computer user, providing secure access to a computer system, network, or application. Passwords are typically a combination of letters, numbers, and special characters that only the authorized user knows.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2024>50", "subject": "Computer Studies", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET~~INFORMATION TRANSMISSION : NETWORKING", "question": "Which of the following statements about firewall is correct", "images": [], "options": {"A": "A network transmission system that increases the speed of incoming and outgoing network traffic", "B": "A network security system that establishes a barrier between a trusted internal network and an untrusted external network such as the Internet", "C": "A data structure that improves the speed of data retrieval operations on a database table", "D": "A data structure created using only two rows of a database table used to uniquely identify each record"}, "answer": "B", "explanation": "A network security system that establishes a barrier between a trusted internal network and an untrusted external network, such as the Internet.    A firewall is a network security system that monitors and controls incoming and outgoing network traffic based on predetermined security rules. It acts as a barrier between a trusted internal network (such as a company's internal network) and an untrusted external network (such as the Internet). This helps to prevent unauthorized access, block malicious traffic, and protect the internal network from potential threats.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>1", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A system is described as a", "images": [], "options": {"A": "collection of static hardware components.", "B": "digital means of solving problems.", "C": "method of computerization.", "D": "set of objects connected to form a whole unit."}, "answer": "D", "explanation": "A system is generally defined as a group of interconnected or interacting elements that work together to form a unified whole. This definition applies broadly, whether in engineering, biology, computing, or other fields.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>2", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "One method of obtaining data is through", "images": [], "options": {"A": "calculation.", "B": "conversion.", "C": "observation.", "D": "transmission."}, "answer": "C", "explanation": "Observation is a fundamental method of gathering data by directly monitoring or measuring phenomena, events, or behaviors. This can be done manually (e.g., a scientist recording temperatures) or through instruments (e.g., sensors collecting environmental data).", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>3", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The number  B8F  is written in", "images": [], "options": {"A": "binary system.", "B": "decimal system.", "C": "hexadecimal system.", "D": "octal system."}, "answer": "C", "explanation": "The number B8F contains the digit 'B' (which represents the decimal value 11) and the letter 'F' (which represents 15). These alphanumeric characters (A-F) are only used in the hexadecimal (base-16) system.    Hexadecimal numbers are commonly used in computing (e.g., memory addresses, color codes).", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>4", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "One difference between a desktop computer and a laptop computer is that laptop computer", "images": [], "options": {"A": "can be connected directly to the Internet through WiFi but desktop computer can only be connected through Ethernet.", "B": "contains high capacity battery that powers it for an extensive period while desktop computer mainly uses UPS for alternative power source.", "C": "does not support the use of mouse while desktop computer supports the use of mouse.", "D": "uses only serial ports for all connections while desktop computer uses only parallel ports for all connections."}, "answer": "B", "explanation": "Laptops have built-in rechargeable batteries, allowing them to operate without being plugged in for hours.    Desktops rely on continuous mains power and usually need an Uninterruptible Power Supply (UPS) for backup during outages.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>5", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : HISTORY OF COMPUTERS", "question": "A mechanical device that allows the operation of multiplication through repeated addition is the", "images": [], "options": {"A": "Jacquard's Loom.", "B": "Pascaline.", "C": "Slide Rule.", "D": "Stepped Reckoner."}, "answer": "D", "explanation": "The Stepped Reckoner (invented by Gottfried Wilhelm Leibniz in the late 17th century) was a mechanical calculator capable of performing multiplication through repeated addition (and division via repeated subtraction). It used a stepped drum mechanism, making it one of the first machines to automate these operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>6", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : HISTORY OF COMPUTERS", "question": "Which of the following statements about the Slide Rule are true?    I. Multiplication that goes off the slide can be corrected by resetting the slide.  II. Operations of addition can be carried out by directly adding two or more numbers together on the slide.  III. Logarithm is used to transform the operations of multiplication and division to addition and substraction.", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III"}, "answer": "B", "explanation": "Statement I is true – If multiplication exceeds the scale, the slide can be reset to continue the operation.    Statement II is false – The Slide Rule does not perform direct addition or subtraction of numbers; it is primarily used for multiplication, division, roots, and logarithms.    Statement III is true – The Slide Rule uses logarithmic scales to convert multiplication and division into addition and subtraction operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>7", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The following features distinguish the supercomputer from other types of computer except", "images": [], "options": {"A": "high processing speed.", "B": "number of users connected at once.", "C": "physical size.", "D": "small memory capacity."}, "answer": "D", "explanation": "A supercomputer is characterized by its exceptionally high processing speed and large physical size. It handles massive computations and large datasets, thus requiring enormous memory capacity, not small. While capable of handling many tasks, its primary distinction isn't the number of direct human users compared to other types of computers like mainframes. Therefore, having a \"small memory capacity\" is the statement that does not distinguish a supercomputer, as it's the opposite of reality.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>8", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following statements are true about pointing devices?    I. Device has buttons used to select objects.  II. Device moves an onscreen pointer to allow user select objects.  III. Older types of the device used laser, an optical technology that tracks movements with light while newer types of the device use ball only.  IV. User slides device along a flat surface to move pointer around the screen.", "images": [], "options": {"A": "I, II and III only", "B": "I, II and IV only", "C": "I, III and IV only", "D": "I, II, III and IV"}, "answer": "B", "explanation": "True Statements:  I. \"Device has buttons used to select objects.\"    Most pointing devices (e.g., mice, trackballs) include buttons (left/right click) for selection.    II. \"Device moves an onscreen pointer to allow user to select objects.\"    The primary function of a pointing device is to control a cursor/pointer on the screen.    IV. \"User slides device along a flat surface to move pointer around the screen.\"    This describes traditional mechanical mice (ball-based) and modern optical/laser mice (though they don't require a ball).    False Statement:  III. \"Older types of the device used laser, an optical technology that tracks movements with light while newer types of the device use ball only.\"    Incorrect: Older mice used balls (mechanical), while newer ones use optical/laser sensors. The statement reverses the timeline.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>9", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "LOGIC GATES", "question": "Which of the following logic devices is a  non-equivalent  gate?", "images": [], "options": {"A": "AND gate", "B": "EX-NOR gate", "C": "EX-OR gate", "D": "NOR gate"}, "answer": "C", "explanation": "What is a Non-Equivalent Gate?  A non-equivalent gate outputs true (1) when its inputs are different and false (0) when they are the same. This matches the behavior of the EX-OR (XOR) gate.    Truth Table for EX-OR (XOR) Gate:    A\tB\tOutput0\t0\t00\t1\t11\t0\t11\t1\t0  Outputs 1 only when inputs differ (non-equivalent).", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2025>10", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "LOGIC GATES", "question": "Use the logic devices in Figures 1 and 2 to answer questions 10 to 12 given that the input variables X and Y have values of 0011 and 0101 respectively.      Compute the value of the output Z in Figure 1 using the values of X and Y given.", "images": ["Computer Studies/imgs/2025/R42ED8.jpg"], "options": {"A": "1110", "B": "1000", "C": "0001", "D": "0111"}, "answer": "C", "explanation": "Figure 1 represents an AND gate.    An AND gate's output (Z) is HIGH (1) only if both of its inputs (X and Y) are HIGH (1). Otherwise, the output is LOW (0).    Given input values:    X = 0011  Y = 0101  Let's compute Z for each corresponding bit:    X\tY\tZ = X AND Y0\t0\t00\t1\t01\t0\t01\t1\t1  So, the value of the output Z is 0001.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2025>11", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "LOGIC GATES", "question": "Use the logic devices in Figures 1 and 2 to answer questions 10 to 12 given that the input variables X and Y have values of 0011 and 0101 respectively.    If the input variable X in Figure 1 is passed through the device in Figure 2 before going into the logic gate in Figure 1, what will be the output Z?", "images": ["Computer Studies/imgs/2025/R42ED8.jpg"], "options": {"A": "1001", "B": "0100", "C": "1101", "D": "1110"}, "answer": "B", "explanation": "Figure 1 is an AND gate.  Figure 2 is a NOT gate.    The problem states that input variable X is first passed through the NOT gate (Figure 2) before going into the AND gate (Figure 1). This means the inputs to the AND gate will be the NOT of X (let's call this X') and the original Y. The output will be Z = X' AND Y.    Given input values:    X = 0011  Y = 0101    Step 1: Compute X' (NOT X)  A NOT gate inverts its input.  If X = 0011, then X' = NOT(0011) = 1100.    Step 2: Compute Z = X' AND Y  Now we perform an AND operation with X' and Y.    X' (NOT X)\tY\tZ = X' AND Y1\t0\t01\t1\t10\t0\t00\t1\t0  So, the value of the output Z is 0100.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2025>12", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "LOGIC GATES", "question": "Use the logic devices in Figures 1 and 2 to answer questions 10 to 12 given that the input variables X and Y have values of 0011 and 0101 respectively.    If the input variable Y in Figure 1 is passed through the device in Figure 2 before going into the logic gate in Figure 1, compute the output at Z.", "images": ["Computer Studies/imgs/2025/R42ED8.jpg"], "options": {"A": "1101", "B": "0100", "C": "0010", "D": "0001"}, "answer": "C", "explanation": "Figure 1 is an AND gate.  Figure 2 is a NOT gate.    This time, the input variable Y is passed through the NOT gate (Figure 2) before entering the AND gate (Figure 1). The inputs to the AND gate will be the original X and the NOT of Y (let's call this Y'). The output will be Z = X AND Y'.    Given input values:    X = 0011  Y = 0101  Step 1: Compute Y' (NOT Y)  A NOT gate inverts its input.  If Y = 0101, then Y' = NOT(0101) = 1010.    Step 2: Compute Z = X AND Y'  Now we perform an AND operation with X and Y'.    X\tY' (NOT Y)\tZ = X AND Y'0\t1\t00\t0\t01\t1\t11\t0\t0  So, the value of the output Z is 0010.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2025>13", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following memory capacities is the largest?", "images": [], "options": {"A": "1 TB", "B": "100 GB", "C": "500 MB", "D": "960 KB"}, "answer": "A", "explanation": "Here's the comparison of the options in bytes (smallest to largest):    960 KB = 960 × 1,024 = 983,040 bytes    500 MB = 500 × 1,024² = 524,288,000 bytes    100 GB = 100 × 1,024³ = 107,374,182,400 bytes    1 TB = 1 × 1,024⁴ = 1,099,511,627,776 bytes    Key Conversion:    1 TB = 1,024 GB (largest unit here).    100 GB is 10% of 1 TB, making it smaller.    500 MB and 960 KB are significantly smaller.    Therefore, 1 TB (terabyte) is the largest capacity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>14", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "LOGIC GATES", "question": "Which one of the following statements is true about logic gates?", "images": [], "options": {"A": "The output of AND gate is low if both inputs are high.", "B": "The output of AND gate is high if both or either of the inputs is low.", "C": "The output of NOT gate is high if the input is low.", "D": "The output of OR gate is low if both inputs are high."}, "answer": "C", "explanation": "A NOT gate (also called an inverter) has only one input. It inverts the input signal. If the input is LOW (0), the output is HIGH (1), and if the input is HIGH (1), the output is LOW (0).", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>15", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "A set of instructions written in the language of the computer to solve user's problem is called", "images": [], "options": {"A": "assembler.", "B": "byte.", "C": "pseudocode.", "D": "software."}, "answer": "D", "explanation": "Software: This is a general term for sets of instructions, data, or programs used to operate computers and execute specific tasks. The instructions are written in a language that the computer can understand (ultimately translated into machine code).    Let's look at the other options:    Assembler: This is a type of program that translates assembly language (a low-level programming language) into machine code. It's a tool used in the software development process, not the set of instructions itself.    Byte: This is a unit of digital information that typically consists of eight bits. It's a unit of data storage, not a set of instructions.    Pseudocode: This is an informal high-level description of the operating principle of a computer program or other algorithm. It's written in a human-readable format, often using structural conventions of a normal programming language but without strict syntax. It's a way to plan software, not the final instructions the computer executes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>16", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "In computer operation, loading and starting of application programs is carried out by", "images": [], "options": {"A": "device drivers.", "B": "embedded system.", "C": "operating system.", "D": "peripheral devices."}, "answer": "C", "explanation": "The operating system (OS) is responsible for loading and starting application programs. It manages system resources, handles memory allocation, and ensures programs run smoothly.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>17", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The operating system is responsible for", "images": [], "options": {"A": "checking the effect of virus on the computer.", "B": "creating tasks for computer programmers.", "C": "making the most efficient use of the computer hardware.", "D": "teaching new skills to computer users through videos."}, "answer": "C", "explanation": "The operating system (OS) is the core software that manages hardware resources (CPU, memory, storage, etc.) to ensure:    Efficiency: Allocates CPU time, memory, and I/O devices optimally.    Fairness: Prevents one program from monopolizing resources.    Abstraction: Simplifies hardware interaction for applications (e.g., file systems, device drivers).", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>18", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Which one of the following statements explains the function of utility software?", "images": [], "options": {"A": "Converts source code to object code", "B": "Enables hardware to communicate with the computer", "C": "Helps to clean disk space and manages installation of applications", "D": "Helps to improve the functionality of hardware devices"}, "answer": "C", "explanation": "Utility software is designed to help manage, maintain, and optimize a computer system. Common functions include:    - Disk cleanup    - File management    - Installing/uninstalling applications    - System monitoring    - Backup and recovery", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>19", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "The clear and precise step-by-step procedure of solving a particular problem is called", "images": [], "options": {"A": "algorithm.", "B": "flowchart.", "C": "interpretation.", "D": "programming."}, "answer": "A", "explanation": "An algorithm is a well-defined, step-by-step procedure for solving a problem or accomplishing a task. It provides a clear and unambiguous sequence of instructions that, when executed, will lead to the desired outcome.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>20", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "A program written in source code can be converted to object code by", "images": [], "options": {"A": "code converter.", "B": "language translator.", "C": "operating system.", "D": "utility software."}, "answer": "B", "explanation": "A language translator converts source code (human-readable code, e.g., Python, C++) into object code (machine-readable binary). There are three main types:    1. Compiler: Translates the entire source code at once (e.g., GCC for C).    2. Interpreter: Translates and executes line-by-line (e.g., Python interpreter).    3. Assembler: Converts assembly language to machine code.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>21", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "The process of searching for errors and eliminating them in a computer program is called", "images": [], "options": {"A": "compilation.", "B": "debugging.", "C": "execution.", "D": "normalization."}, "answer": "B", "explanation": "Debugging is the systematic process of:    1. Identifying errors (bugs) in a program.    2. Analyzing their causes (e.g., logic mistakes, syntax issues).    3. Fixing the errors to ensure the program runs correctly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>22", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "Use the QBASIC program below to answer question 22.  10 REM Multiplication Table Construction  20 CLS  30 FOR 1% = 1 TO 50  40 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;C = 1  50 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;FOR J% = 1 TO 50  60 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;PRINT TAB(C) J% * 1%  70 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;C = C + 3  80 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;NEXT J%  90 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;PRINT  100 NEXT 1%  110 END    The main function of the statement in line 20 in the QBASIC program above is to", "images": [], "options": {"A": "assign variable names before the execution of the current program.", "B": "create memory location for all the variables that will be declared in the current program.", "C": "erase previously printed output on the screen before the output of the current program.", "D": "indicate that the current program is command based."}, "answer": "C", "explanation": "In QBASIC, the CLS (CLear Screen) command clears the screen, erasing any previously printed output before displaying new output.    So the main function of line 20 is to:    erase previously printed output on the screen before the output of the current program.", "marks": "1", "difficulty": "3"}, {"id": "objective>Computer Studies>2025>23", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "Which one of the following statements is correct about the rules of flowcharting?", "images": [], "options": {"A": "All symbols of flowchart are connected with Terminal Box to show the logical connection between them", "B": "All flowchart process symbols are connected with On page connector to show the flow of operation", "C": "All flowcharts start with a Start Box and end with a Decision Box", "D": "The flow of Control must always enter an object from top to bottom"}, "answer": "D", "explanation": "The flow of Control must always enter an object from top to bottom. This is a convention in flowcharting that promotes clarity and readability. While flow lines can exit a symbol in different directions (e.g., from the bottom or sides for branching in decision boxes), the standard practice is to have the primary flow of control enter a process or other symbol from the top.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>24", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "The major difference between low level programming languages and high level programming languages is that", "images": [], "options": {"A": "high level languages are less memory efficient while low level languages are more memory efficient.", "B": "high level languages will not need a translator but low level languages will do.", "C": "low level languages are slower while high level languages are faster.", "D": "low level languages are interpreted while high level languages are assembled."}, "answer": "A", "explanation": "Low-level languages (like assembly language) provide direct control over hardware and memory, allowing skilled programmers to optimize memory usage. High-level languages abstract away many of these details, often leading to less memory-efficient code by default, although modern compilers do perform optimizations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>25", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "In computer programming, source codes are usually translated to intermediate codes in order to", "images": [], "options": {"A": "avoid the need for full native compiler for every new machine that will run the program.", "B": "change the analysis portion for different compilers.", "C": "prevent modification of the program source code by unauthorized persons.", "D": "prevent the synthesis part of the compiler from changing for any target machine."}, "answer": "A", "explanation": "Intermediate Code (e.g., Bytecode): By compiling the source code into an intermediate representation, you create a platform-independent code. This intermediate code can then be executed by a virtual machine (VM) or further translated into native machine code specific to each target architecture. This approach has several advantages:    - Portability: The same intermediate code can run on any machine that has a compatible VM or a relatively simple just-in-time (JIT) compiler for that intermediate code. This significantly reduces the effort required to make a program run on different operating systems and hardware.    - Faster Porting: Instead of writing a full compiler from scratch for each new platform, developers only need to create or adapt the VM or JIT compiler for the intermediate code.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>26", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "The set of rules by which communication takes place over a network is called", "images": [], "options": {"A": "connectivity.", "B": "ethics.", "C": "protocol.", "D": "topology."}, "answer": "C", "explanation": "In networking, a protocol is a set of rules and procedures that govern how data is transmitted and received over a network. These rules define the format, timing, sequencing, and error handling of data exchange between devices.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>27", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Which one of the following pairs contains types of network topology?", "images": [], "options": {"A": "Token and Mesh", "B": "Star and Token", "C": "Ring and Bus", "D": "Bus and Node"}, "answer": "C", "explanation": "Network Topology refers to the physical or logical arrangement of nodes (devices) and connections in a network. Common types of network topologies include:     - Ring Topology: Devices are connected in a closed loop or ring.  - Bus Topology: All devices are connected to a single central cable (the bus).  - Star Topology: All devices connect to a central hub or switch.  - Mesh Topology: Devices are interconnected with many redundant connections.  - Tree Topology: A combination of star and bus topologies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>28", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "An advantage of using Computer Aided Manufacturing in car manufacturing industry is that", "images": [], "options": {"A": "cost of equipment is low.", "B": "equipment does not require close supervision.", "C": "pollution is reduced.", "D": "products follow consistent standards."}, "answer": "D", "explanation": "Computer Aided Manufacturing (CAM) systems use precise computer control to direct manufacturing processes. This ensures that each component and the final product are manufactured to exact specifications, leading to higher levels of consistency and quality across the entire production line.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>29", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "The Transmission Control Protocol/Internet Protocol ( TCP/IP ) is used to", "images": [], "options": {"A": "interconnect devices on the Internet.", "B": "retrieve email from a mail server.", "C": "transfer files from a server to a client.", "D": "send email from one user to another."}, "answer": "A", "explanation": "TCP/IP (Transmission Control Protocol/Internet Protocol) is the fundamental communication protocol suite that enables devices to connect and exchange data across the Internet and other networks. Its primary functions include:    - Device Interconnection: Assigns unique IP addresses to devices (e.g., computers, servers) and routes data packets between them.    - Reliable Data Delivery:    1. TCP ensures error-checked, ordered delivery (e.g., loading a webpage).    2. IP handles addressing and routing (e.g., sending packets to the correct destination).", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>30", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "One difference between intranetworking and internetworking is that", "images": [], "options": {"A": "intranetworking is more secured compared to internetworking.", "B": "intranetworking has unlimited coverage compared to internetworking.", "C": "intranetworking is publicly owned while internetworking is privately owned.", "D": "intranetworking can be accessed by everyone while internetworking is accessible to the staff of an organization only."}, "answer": "A", "explanation": "Intranetworking refers to the communication within a single private network, such as an organization's local area network (LAN). It is generally more secure because it is restricted to authorized users within the organization.    Internetworking involves the connection of multiple networks, such as the connection of LANs via the internet. This broader connectivity exposes systems to more external threats, making it less secure than a closed intranet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>31", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Which one of the following statements is true about email client?", "images": [], "options": {"A": "It is a server which stores email messages", "B": "It is a program which enables users to send and receive email", "C": "It is a person using email services to serve the public", "D": "It is a computer which provides email services to users"}, "answer": "B", "explanation": "An email client is a software application that users install on their computers, phones, or access through a web browser. This program allows them to compose, send, receive, organize, and manage their email messages. Examples include Microsoft Outlook, Mozilla Thunderbird, Apple Mail, and web-based clients like Gmail and Yahoo Mail accessed in a browser.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>32", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A record in a database can be identified using", "images": [], "options": {"A": "a key field.", "B": "an attribute key.", "C": "an entity relationship.", "D": "an object identifier."}, "answer": "A", "explanation": "A key field is an attribute or a set of attributes within a database table that uniquely identifies each record (row) in that table. This ensures that you can distinguish and access specific pieces of information. Examples include a customer ID, a product serial number, or a combination of fields that together are unique.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>33", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Which one of the following software can be used by a company accountant to prepare staff payment?", "images": [], "options": {"A": "Microsoft Word", "B": "Microsoft Publisher", "C": "Microsoft PowerPoint", "D": "Microsoft Excel"}, "answer": "D", "explanation": "Microsoft Excel is a spreadsheet application widely used by accountants for tasks such as:    - Calculating staff salaries    - Creating payroll sheets    - Managing financial records    - Automating calculations with formulas and functions", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>34", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "In MS Access, the first object to be created which will enable user to create or use other objects is a", "images": [], "options": {"A": "Form.", "B": "Macro.", "C": "Report.", "D": "Table."}, "answer": "D", "explanation": "In Microsoft Access, a table is the foundational object where data is stored. All other objects—forms, queries, reports, and macros—are based on the data contained in tables.    You cannot create meaningful forms, reports, or macros without having at least one table with data to work on.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>35", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The Microsoft Excel menu bar icon in Figure 3 represents a command used to", "images": ["Computer Studies/imgs/2025/2HMPBA.jpg"], "options": {"A": "change the row height or column width, organize sheets, protect or hide cells.", "B": "continue a series or pattern into neighbouring cells in any direction.", "C": "remove the selection and put it on the clipboard so that user can paste it somewhere else.", "D": "wrap extra-long text into multiple lines to allow a user view all of it."}, "answer": "D", "explanation": "The Microsoft Excel menu bar icon in Figure 3 represents a command used to wrap extra-long text into multiple lines to allow a user view all of it.    The icon shows text wrapping within a cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>36", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "The CorelDraw Toolbox object in Figure 4 is used to", "images": ["Computer Studies/imgs/2025/P4346A.jpg"], "options": {"A": "select and transform objects.", "B": "edit the shape of objects.", "C": "draw lines and curves.", "D": "change the magnification level in drawing window."}, "answer": "B", "explanation": "The CorelDraw Toolbox object in Figure 4 is indeed the Shape Tool, which is used to edit the shape of objects.    The Shape Tool allows users to manipulate the nodes and control handles of vector objects to precisely alter their form.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>37", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Which one of the following statements is true about the Slide Sorter View in Microsoft PowerPoint?", "images": [], "options": {"A": "Only the texts of all slides are shown", "B": "Preview presentation takes place", "C": "Slide time appears on the screen", "D": "Thumbnail versions of all slides are arranged"}, "answer": "D", "explanation": "In Slide Sorter View in Microsoft PowerPoint, you see small thumbnail images of all the slides in the presentation arranged on one screen. This view helps you easily rearrange, add, or delete slides.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>38", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Arrange the following steps in the correct order of creating queries in Microsoft Access.  I. Choose the tables to include in the query.  II. Choose the fields to include and adjust the criteria.  III. Click the CREATE > Query Design button on the ribbon.  IV. Click the RUN button/switch to Data Sheet View.", "images": [], "options": {"A": "I, II, III, IV", "B": "I, II, IV, III", "C": "II, I, III, IV", "D": "III, I, II, IV"}, "answer": "D", "explanation": "Step-by-Step Explanation for Creating a Query in Microsoft Access:    III. Click the CREATE > Query Design button on the ribbon.    This is the first step to initiate the query design process. It opens the Query Design view.    I. Choose the tables to include in the query.    Once in the Query Design view, the \"Show Table\" dialog box appears (or you can manually add tables). You select the tables that contain the data you want to retrieve or work with in your query.    II. Choose the fields to include and adjust the criteria.    After adding the tables, you select the specific fields from those tables that you want to display in your query results. You also define any criteria (conditions) to filter the data and retrieve only the records that meet your requirements.    IV. Click the RUN button/switch to Data Sheet View.    Finally, after designing your query by selecting tables, fields, and setting criteria, you run the query to see the results in Data Sheet View. The \"RUN\" button executes the query based on your design.    Therefore, the logical sequence is to first open the query designer, then select the data sources (tables), specify what data you want (fields) and any conditions (criteria), and finally execute the query to see the output.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>39", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "A small picture or object that represents a file, program, webpage or comment in windows is called", "images": [], "options": {"A": "a taskbar.", "B": "a toolbar.", "C": "an icon.", "D": "an image."}, "answer": "C", "explanation": "An icon is a small graphical representation that symbolizes:    - Files (e.g., a PDF icon).    - Programs (e.g., Chrome's colorful ball).    - Webpages (e.g., favicons in browser tabs).    - Functions (e.g., trash bin for deletion).    Icons provide a visual way for users to quickly identify and interact with these items.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>40", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS : PROGRAMMING LANGUAGE (PL)", "question": "The two main types of user interface are", "images": [], "options": {"A": "visual user interface and command driven interface.", "B": "soft user interface and graphical user interface.", "C": "graphical user interface and visual user interface.", "D": "graphical user interface and command driven interface."}, "answer": "D", "explanation": "The two main types of user interface are graphical user interface and command driven interface.    Here's why:    - Graphical User Interface (GUI): This type of interface allows users to interact with a computer through visual elements such as icons, menus, windows, and buttons. Users typically use a mouse, trackpad, or touch screen to navigate and interact with these elements. Examples include Windows, macOS, Android, and iOS.    - Command-Driven Interface (CLI): This type of interface requires users to interact with the computer by typing specific text commands. The computer responds by displaying text output. Examples include the command prompt in Windows (cmd.exe), the terminal in macOS and Linux (bash, zsh), and older operating systems like MS-DOS.", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>41", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "To initiate the startup process, the BIOS requires", "images": [], "options": {"A": "date, hardware status and system configuration.", "B": "date, time and system configuration.", "C": "date, time, data file and hardware status.", "D": "date, time, hardware status and text file."}, "answer": "B", "explanation": "BIOS (Basic Input/Output System) is a firmware embedded on a computer's motherboard. One of its primary functions during startup (the POST - Power-On Self Test) is to initialize the system hardware and prepare it for the operating system to load. To do this effectively, the BIOS needs certain fundamental pieces of information:  - Date and Time: The system's real-time clock is checked and initialized.  - System Configuration: This includes details about the installed hardware components (CPU, memory, hard drives, etc.), their settings, and the boot order (which device to try to load the operating system from).", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>42", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "A desktop computer is switched on and the monitor displays an error message which reads: No input signal. The likely cause of this error is", "images": [], "options": {"A": "defective monitor.", "B": "disconnected VGA cable.", "C": "low memory.", "D": "power failure."}, "answer": "B", "explanation": "The error message \"No input signal\" on a monitor usually means the monitor is not receiving any video signal from the computer. The most common cause is a disconnected or loose VGA (or HDMI/DisplayPort) cable between the monitor and the computer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>43", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The parts of the EBCDIC are", "images": [], "options": {"A": "nibbles and bytes.", "B": "strings and integers.", "C": "words and numbers.", "D": "zone bits and numerical bits."}, "answer": "D", "explanation": "EBCDIC (Extended Binary Coded Decimal Interchange Code) is an 8-bit character encoding system primarily used in IBM mainframes. Its structure divides each 8-bit byte into two parts:    1. Zone Bits (First 4 bits): Define the category of the character (e.g., letters, symbols).    Example: 1100 for uppercase letters.    2. Numerical Bits (Last 4 bits): Specify the value within the category.    Example: 0001 for 'A' (1100 0001 in full EBCDIC).", "marks": "1", "difficulty": "1"}, {"id": "objective>Computer Studies>2025>44", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The binary number 100101 can be written in denary as", "images": [], "options": {"A": "25.", "B": "37.", "C": "45.", "D": "211."}, "answer": "B", "explanation": "1001012 =  (1 × 25) + (0 × 24) + (0 × 23) + (1 × 22) + (0 × 21) + (1 × 20)    = (1 × 32) + 0 + 0 + (1 × 4) + 0 + (1 × 1)    = 32 + 0 + 0 + 4 + 0 + 1    = 37", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>45", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Convert 70 from base ten to octal.", "images": [], "options": {"A": "0188", "B": "1068", "C": "6018", "D": "8108"}, "answer": "B", "explanation": "87088 rem 681 rem 00 rem 1  ∴ 7010 = 1068 (moving from bottom to top)", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>46", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Backing up of computer files is the process of", "images": [], "options": {"A": "updating files in the computer main storage area.", "B": "storing extra copy of files in the main memory of the computer.", "C": "storing extra copy of files in an external storage location.", "D": "storing extra copy of files on the computer main storage area."}, "answer": "C", "explanation": "Backing up is the process of creating a duplicate of your computer files and storing it in a separate location. This is done as a safeguard against data loss due to hardware failure, software corruption, accidental deletion, or other unforeseen events. The key is that the backup is stored outside of your computer's primary storage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>47", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "The file structure is represented systematically in ascending order as", "images": [], "options": {"A": "data → field → record → file.", "B": "record → data → file → field.", "C": "field → record → data → file.", "D": "file → record → field → data."}, "answer": "A", "explanation": "The file structure is represented systematically in ascending order of complexity and size as:    data → field → record → file.    Here's why:    - Data: The most basic unit, representing raw facts or values.  - Field: A collection of related characters (data) that represents a single attribute of an entity (e.g., a name, an age, a product code).  - Record: A collection of related fields that describe a single instance of an entity (e.g., all the information about one specific customer).  - File: A collection of related records (e.g., a file containing the records of all customers).    Therefore, the hierarchy builds from individual pieces of data up to a complete file containing multiple related entities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>48", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Which of the following statements supports the goals of data backup?  I. Need for duplication.  II. Need for future reference.  III. Protection against data loss.", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III"}, "answer": "D", "explanation": "All three statements fully support the core goals of data backup:    I. \"Need for duplication\" →    Backups create redundant copies of data to ensure availability if the original is lost/corrupted.    II. \"Need for future reference\" →    Backups preserve data for long-term access (e.g., archival records, compliance).    III. \"Protection against data loss\" →    The primary purpose of backups is to safeguard against risks like hardware failure, cyberattacks, or accidental deletion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>49", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "The unauthorized use of computer and network resources is known as", "images": [], "options": {"A": "hacking.", "B": "phishing.", "C": "piracy.", "D": "spamming."}, "answer": "A", "explanation": "Hacking refers to the unauthorized access, use, or manipulation of computer systems, networks, or data, often with malicious intent. It encompasses activities like:    - Exploiting vulnerabilities to gain access.    - Disrupting services (e.g., DDoS attacks).    - Stealing sensitive information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Computer Studies>2025>50", "subject": "Computer Studies", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Poor implementation of network or lack of ICT policies may result to", "images": [], "options": {"A": "phishing.", "B": "security breach.", "C": "spamming.", "D": "virus infection."}, "answer": "B", "explanation": "Weak network implementation (e.g., open ports, default passwords, unpatched systems) and the absence of clear ICT policies (e.g., password requirements, access controls, data handling procedures) create vulnerabilities that malicious actors can exploit to gain unauthorized access to systems and data. This is the essence of a security breach.", "marks": "1", "difficulty": "2"}];